/// Live Metal present state owned by a `Surface` (Issue 802 / Exp 15, slice 1). Holds the
/// compositor (device/queue/pipelines + the IOSurface `CALayer` attached to the app's NSView),
/// the persistent CPU-side frame renderer, the font `SharedGrid`, and the glyph atlases the
/// compositor samples. Not `Send` (it owns `Retained<MTLDevice>` + a `CALayer`) — created and
/// used only on the main thread (`Surface` is already `!Send` via its raw-pointer fields).
#[allow(dead_code)]
struct SurfaceLiveRenderer {
    device: objc2::rc::Retained<objc2::runtime::ProtocolObject<dyn objc2_metal::MTLDevice>>,
    compositor: renderer::metal::compositor::MetalFrameCompositor,
    frame_renderer: renderer::frame_renderer::FrameRenderer,
    image_state: renderer::image::ImageState<renderer::metal::texture::MetalTexture>,
    background_image: renderer::image::BackgroundImageState<renderer::metal::texture::MetalTexture>,
    link_set: renderer::link::RendererLinkSet,
    custom_shader: SurfaceCustomShaderState,
    shared_grid: font::shared_grid::SharedGrid,
}

#[allow(dead_code)]
struct SurfaceCustomShaderState {
    paths: Vec<config::ConfigFilePath>,
    pipelines: Vec<renderer::metal::pipeline::MetalPipeline>,
    uniforms: renderer::shadertoy::CustomShaderUniforms,
    first_frame: Option<std::time::Instant>,
    last_frame: Option<std::time::Instant>,
    focus_changed: bool,
}

impl SurfaceCustomShaderState {
    fn new() -> Self {
        Self {
            paths: Vec::new(),
            pipelines: Vec::new(),
            uniforms: renderer::shadertoy::CustomShaderUniforms::new(),
            first_frame: None,
            last_frame: None,
            focus_changed: true,
        }
    }

    fn sync_from_config(
        &mut self,
        device: &objc2::runtime::ProtocolObject<dyn objc2_metal::MTLDevice>,
        config: &config::Config,
    ) {
        if self.paths == config.custom_shader.list {
            return;
        }

        self.paths = config.custom_shader.list.clone();
        self.pipelines.clear();
        self.uniforms = renderer::shadertoy::CustomShaderUniforms::new();
        self.first_frame = None;
        self.last_frame = None;
        self.focus_changed = true;

        if self.paths.is_empty() {
            return;
        }

        let sources = match renderer::shadertoy::load_from_files(
            &self.paths,
            renderer::metal::CUSTOM_SHADER_TARGET,
        ) {
            Ok(sources) => sources,
            Err(error) => {
                eprintln!("[roastty] custom shader load failed: {error}");
                return;
            }
        };

        match renderer::metal::shaders::build_post_process_pipelines(
            device,
            &sources,
            renderer::metal::api::MetalPixelFormat::Bgra8Unorm,
        ) {
            Ok(pipelines) => self.pipelines = pipelines,
            Err(error) => {
                eprintln!("[roastty] custom shader pipeline build failed: {error:?}");
            }
        }
    }

    fn frame_input(
        &mut self,
        screen_size: [u32; 2],
        cell_size: [u32; 2],
        focused: bool,
    ) -> renderer::frame_rebuild::FrameCustomShaderInput {
        let now = std::time::Instant::now();
        let first = *self.first_frame.get_or_insert(now);
        let time_secs = now.duration_since(first).as_secs_f32();
        let time_delta_secs = self
            .last_frame
            .map(|last| now.duration_since(last).as_secs_f32())
            .unwrap_or(0.0);
        self.last_frame = Some(now);

        renderer::frame_rebuild::FrameCustomShaderInput {
            time_secs,
            time_delta_secs,
            screen_size,
            cell_size,
            padding: [0, 0],
            cursor: None,
            focused,
            focus_changed: self.focus_changed,
        }
    }
}

/// A `*mut Surface` that can cross into a dispatch closure (Issue 802 / Exp 19). SAFETY:
/// dereferenced ONLY on the main thread, guarded by the driver's `running` flag — the surface
/// outlives every deref because `surface_free`/`Drop` flip `running` false before the box is
/// dropped, and the main queue is serial so no tick interleaves with the free.
#[derive(Clone, Copy)]
struct SendSurfacePtr(*mut Surface);
// SAFETY: see the type doc — the pointer is only dereferenced on the main thread while `running`.
unsafe impl Send for SendSurfacePtr {}

struct PresentDriver {
    running: std::sync::Arc<std::sync::atomic::AtomicBool>,
    kind: PresentDriverKind,
}

enum PresentDriverKind {
    FallbackThread(Option<std::thread::JoinHandle<()>>),
    #[cfg(target_os = "macos")]
    DisplayLink(MacDisplayLink),
    #[cfg(test)]
    Test(TestPresentDriver),
}

#[cfg(test)]
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum PresentDriverTestMode {
    ForceFallback,
    FailDisplayLink,
    FakeDisplayLink,
}

#[cfg(test)]
#[derive(Default)]
struct PresentDriverTestState {
    mode: Option<PresentDriverTestMode>,
    updated_display_ids: Vec<u32>,
}

#[cfg(test)]
thread_local! {
    static PRESENT_DRIVER_TEST_STATE: std::cell::RefCell<PresentDriverTestState> =
        const { std::cell::RefCell::new(PresentDriverTestState {
            mode: None,
            updated_display_ids: Vec::new(),
        }) };
}

#[cfg(test)]
struct PresentDriverTestGuard {
    previous: Option<PresentDriverTestMode>,
    previous_updates: Vec<u32>,
}

#[cfg(test)]
impl Drop for PresentDriverTestGuard {
    fn drop(&mut self) {
        PRESENT_DRIVER_TEST_STATE.with(|state| {
            let mut state = state.borrow_mut();
            state.mode = self.previous;
            state.updated_display_ids = std::mem::take(&mut self.previous_updates);
        });
    }
}

#[cfg(test)]
fn with_present_driver_test_mode<T>(mode: PresentDriverTestMode, f: impl FnOnce() -> T) -> T {
    let guard = PRESENT_DRIVER_TEST_STATE.with(|state| {
        let mut state = state.borrow_mut();
        PresentDriverTestGuard {
            previous: state.mode.replace(mode),
            previous_updates: std::mem::take(&mut state.updated_display_ids),
        }
    });
    let result = f();
    drop(guard);
    result
}

#[cfg(test)]
fn present_driver_test_updates() -> Vec<u32> {
    PRESENT_DRIVER_TEST_STATE.with(|state| state.borrow().updated_display_ids.clone())
}

#[cfg(test)]
struct TestPresentDriver {
    display_link: bool,
}

impl PresentDriver {
    fn start(surface: *mut Surface, window_vsync: bool) -> Self {
        let running = std::sync::Arc::new(std::sync::atomic::AtomicBool::new(true));
        #[cfg(test)]
        {
            let mode = PRESENT_DRIVER_TEST_STATE.with(|state| state.borrow().mode);
            match mode {
                Some(PresentDriverTestMode::ForceFallback) => {
                    present_driver_log("present-driver=fallback reason=test-force-fallback");
                    return Self {
                        running,
                        kind: PresentDriverKind::Test(TestPresentDriver {
                            display_link: false,
                        }),
                    };
                }
                Some(PresentDriverTestMode::FailDisplayLink) if window_vsync => {
                    present_driver_log("present-driver=fallback reason=test-display-link-failed");
                    return Self {
                        running,
                        kind: PresentDriverKind::Test(TestPresentDriver {
                            display_link: false,
                        }),
                    };
                }
                Some(PresentDriverTestMode::FakeDisplayLink) if window_vsync => {
                    present_driver_log("present-driver=display-link reason=test-fake-display-link");
                    return Self {
                        running,
                        kind: PresentDriverKind::Test(TestPresentDriver { display_link: true }),
                    };
                }
                _ => {}
            }
        }

        #[cfg(target_os = "macos")]
        if window_vsync {
            if let Some(link) = MacDisplayLink::new(surface, running.clone()) {
                present_driver_log("present-driver=display-link reason=core-video");
                return Self {
                    running,
                    kind: PresentDriverKind::DisplayLink(link),
                };
            }
        }

        let reason = if window_vsync {
            "display-link-unavailable"
        } else {
            "window-vsync-false"
        };
        present_driver_log(&format!("present-driver=fallback reason={reason}"));
        Self {
            kind: PresentDriverKind::FallbackThread(Some(start_present_fallback_thread(
                surface,
                running.clone(),
            ))),
            running,
        }
    }

    fn stop(&mut self) {
        use std::sync::atomic::Ordering;
        self.running.store(false, Ordering::SeqCst);
        match &mut self.kind {
            PresentDriverKind::FallbackThread(handle) => {
                if let Some(handle) = handle.take() {
                    let _ = handle.join();
                }
            }
            #[cfg(target_os = "macos")]
            PresentDriverKind::DisplayLink(link) => link.stop(),
            #[cfg(test)]
            PresentDriverKind::Test(_) => {}
        }
    }

    fn set_display_id(&mut self, display_id: u32) {
        match &mut self.kind {
            PresentDriverKind::FallbackThread(_) => {}
            #[cfg(target_os = "macos")]
            PresentDriverKind::DisplayLink(link) => link.set_display_id(display_id),
            #[cfg(test)]
            PresentDriverKind::Test(test) => {
                if test.display_link {
                    present_driver_log(&format!("present-driver-display-id={display_id}"));
                    PRESENT_DRIVER_TEST_STATE.with(|state| {
                        state.borrow_mut().updated_display_ids.push(display_id);
                    });
                }
            }
        }
    }

    #[cfg(test)]
    fn is_display_link(&self) -> bool {
        match &self.kind {
            PresentDriverKind::FallbackThread(_) => false,
            #[cfg(target_os = "macos")]
            PresentDriverKind::DisplayLink(_) => true,
            PresentDriverKind::Test(test) => test.display_link,
        }
    }

    #[cfg(test)]
    fn is_running(&self) -> bool {
        self.running.load(std::sync::atomic::Ordering::SeqCst)
    }
}

fn present_driver_log(message: &str) {
    if std::env::var_os("ROASTTY_PRESENT_DRIVER_LOG").as_deref() == Some(std::ffi::OsStr::new("1"))
    {
        eprintln!("[roastty] {message}");
    }
}

impl Drop for PresentDriver {
    fn drop(&mut self) {
        self.stop();
    }
}

fn start_present_fallback_thread(
    surface: *mut Surface,
    running: std::sync::Arc<std::sync::atomic::AtomicBool>,
) -> std::thread::JoinHandle<()> {
    use std::sync::atomic::Ordering;
    let ptr = SendSurfacePtr(surface);
    std::thread::spawn(move || {
        while running.load(Ordering::SeqCst) {
            std::thread::sleep(std::time::Duration::from_millis(16));
            if !running.load(Ordering::SeqCst) {
                break;
            }
            enqueue_present_tick(ptr, running.clone());
        }
    })
}

fn enqueue_present_tick(
    ptr: SendSurfacePtr,
    running: std::sync::Arc<std::sync::atomic::AtomicBool>,
) {
    dispatch2::DispatchQueue::main().exec_async(move || {
        // Re-bind the whole `SendSurfacePtr` (Rust 2021 disjoint capture would otherwise grab
        // the `!Send` `*mut Surface` field directly, bypassing the Send wrapper).
        let ptr = ptr;
        use std::sync::atomic::Ordering;
        if !running.load(Ordering::SeqCst) {
            return;
        }
        // SAFETY: main thread + running == true → the surface is alive (free flips running false
        // before dropping the box, serialized on this same queue).
        let surface = unsafe { &mut *ptr.0 };
        let now = std::time::Instant::now();
        surface.tick_termio();
        // Issue 802 / Exp 28: drive drag-selection autoscroll while a drag is held past the edge
        // (no-op otherwise); before the dirty check so the scrolled row presents now.
        surface.selection_autoscroll_tick();
        surface.advance_cursor_blink(now);
        if surface.dirty && surface.should_present_live() {
            surface.present_live();
            surface.dirty = false;
        }
    });
}

#[cfg(target_os = "macos")]
struct MacDisplayLink {
    link: core_video_display_link::CVDisplayLinkRef,
    context: *mut DisplayLinkContext,
}

#[cfg(target_os = "macos")]
impl MacDisplayLink {
    fn new(
        surface: *mut Surface,
        running: std::sync::Arc<std::sync::atomic::AtomicBool>,
    ) -> Option<Self> {
        let context = Box::new(DisplayLinkContext {
            running,
            ptr: SendSurfacePtr(surface),
        });
        let context = Box::into_raw(context);
        let mut link = std::ptr::null_mut();
        let create =
            unsafe { core_video_display_link::CVDisplayLinkCreateWithActiveCGDisplays(&mut link) };
        if create != 0 || link.is_null() {
            unsafe { drop(Box::from_raw(context)) };
            return None;
        }
        let callback = unsafe {
            core_video_display_link::CVDisplayLinkSetOutputCallback(
                link,
                display_link_callback,
                context.cast(),
            )
        };
        if callback != 0 {
            unsafe {
                core_video_display_link::CVDisplayLinkRelease(link);
                drop(Box::from_raw(context));
            }
            return None;
        }
        let start = unsafe { core_video_display_link::CVDisplayLinkStart(link) };
        if start != 0 {
            unsafe {
                core_video_display_link::CVDisplayLinkRelease(link);
                drop(Box::from_raw(context));
            }
            return None;
        }
        Some(Self { link, context })
    }

    fn stop(&mut self) {
        if self.link.is_null() {
            return;
        }
        unsafe {
            let _ = core_video_display_link::CVDisplayLinkStop(self.link);
            core_video_display_link::CVDisplayLinkRelease(self.link);
            self.link = std::ptr::null_mut();
            if !self.context.is_null() {
                drop(Box::from_raw(self.context));
                self.context = std::ptr::null_mut();
            }
        }
    }

    fn set_display_id(&mut self, display_id: u32) {
        if self.link.is_null() || display_id == 0 {
            return;
        }
        present_driver_log(&format!("present-driver-display-id={display_id}"));
        unsafe {
            let _ =
                core_video_display_link::CVDisplayLinkSetCurrentCGDisplay(self.link, display_id);
        }
    }
}

#[cfg(target_os = "macos")]
impl Drop for MacDisplayLink {
    fn drop(&mut self) {
        self.stop();
    }
}

#[cfg(target_os = "macos")]
struct DisplayLinkContext {
    running: std::sync::Arc<std::sync::atomic::AtomicBool>,
    ptr: SendSurfacePtr,
}

#[cfg(target_os = "macos")]
extern "C" fn display_link_callback(
    _display_link: core_video_display_link::CVDisplayLinkRef,
    _in_now: *const std::ffi::c_void,
    _in_output_time: *const std::ffi::c_void,
    _flags_in: core_video_display_link::CVOptionFlags,
    _flags_out: *mut core_video_display_link::CVOptionFlags,
    context: *mut std::ffi::c_void,
) -> core_video_display_link::CVReturn {
    use std::sync::atomic::Ordering;
    if context.is_null() {
        return 0;
    }
    let context = unsafe { &*(context.cast::<DisplayLinkContext>()) };
    if context.running.load(Ordering::SeqCst) {
        enqueue_present_tick(context.ptr, context.running.clone());
    }
    0
}

#[cfg(target_os = "macos")]
mod core_video_display_link {
    use std::ffi::c_void;

    pub(crate) type CVReturn = i32;
    pub(crate) type CVOptionFlags = u64;
    pub(crate) type CGDirectDisplayID = u32;
    pub(crate) type CVDisplayLinkRef = *mut c_void;

    pub(crate) type CVDisplayLinkOutputCallback = extern "C" fn(
        CVDisplayLinkRef,
        *const c_void,
        *const c_void,
        CVOptionFlags,
        *mut CVOptionFlags,
        *mut c_void,
    ) -> CVReturn;

    #[link(name = "CoreVideo", kind = "framework")]
    extern "C" {
        pub(crate) fn CVDisplayLinkCreateWithActiveCGDisplays(
            display_link_out: *mut CVDisplayLinkRef,
        ) -> CVReturn;
        pub(crate) fn CVDisplayLinkSetOutputCallback(
            display_link: CVDisplayLinkRef,
            callback: CVDisplayLinkOutputCallback,
            user_info: *mut c_void,
        ) -> CVReturn;
        pub(crate) fn CVDisplayLinkStart(display_link: CVDisplayLinkRef) -> CVReturn;
        pub(crate) fn CVDisplayLinkStop(display_link: CVDisplayLinkRef) -> CVReturn;
        pub(crate) fn CVDisplayLinkSetCurrentCGDisplay(
            display_link: CVDisplayLinkRef,
            display_id: CGDirectDisplayID,
        ) -> CVReturn;
        pub(crate) fn CVDisplayLinkRelease(display_link: CVDisplayLinkRef);
    }
}

/// Build the live Metal present state for a surface on the main thread (Issue 802 / Exp 15,
/// slice 1): a default-monospace `SharedGrid` at the surface font size, glyph atlases, the Metal
/// device + compositor, and the IOSurface layer attached to the app's NSView. `None` if the
/// Metal device or config-derived font grid can't be created.
fn build_live_renderer(
    nsview: *mut c_void,
    config: &config::Config,
    font_size: f32,
    width_px: u32,
    height_px: u32,
    scale: f64,
) -> Option<SurfaceLiveRenderer> {
    use objc2_metal::MTLCreateSystemDefaultDevice;
    let device = MTLCreateSystemDefaultDevice()?;
    let width = width_px.max(1) as usize;
    let height = height_px.max(1) as usize;
    let scale = scale.max(1.0);
    // Rasterize at font_size * scale so the cell metrics are PHYSICAL pixels matching
    // the px-space compositor target/projection (Issue 802 / Exp 18 — Retina), using
    // the config-derived SharedGrid path (Issue 802 / Exp 55).
    let shared_grid =
        font::shared_grid_set::build_grid_from_config(config, (font_size * scale as f32).max(1.0))
            .ok()?;
    let compositor = renderer::metal::compositor::MetalFrameCompositor::new(
        renderer::metal::compositor::MetalFrameCompositorOptions {
            device: device.clone(),
            width,
            height,
            pixel_format: renderer::metal::api::MetalPixelFormat::Bgra8Unorm,
            storage_mode: renderer::metal::api::MetalStorageMode::Shared,
            resource_options: renderer::metal::api::MetalResourceOptions::image(
                renderer::metal::api::MetalStorageMode::Shared,
            ),
            // Seed the compositor from the grid's own atlases (Issue 802 / Exp 17) — the
            // same atlases the rebuild rasterizes glyphs into + the present samples.
            grayscale_atlas: &shared_grid.atlas_grayscale,
            color_atlas: &shared_grid.atlas_color,
        },
    )
    .ok()?;
    compositor
        .layer()
        .set_bounds_pixels(width as f64 / scale, height as f64 / scale, scale);
    compositor.layer().attach_to_nsview(nsview, scale);
    let frame_renderer = renderer::frame_renderer::FrameRenderer::new(
        renderer::metal::shaders::MetalUniforms::from_config(config),
    );
    Some(SurfaceLiveRenderer {
        device,
        compositor,
        frame_renderer,
        image_state: renderer::image::ImageState::default(),
        background_image: renderer::image::BackgroundImageState::default(),
        link_set: renderer::link::RendererLinkSet::default(),
        custom_shader: SurfaceCustomShaderState::new(),
        shared_grid,
    })
}

#[derive(Clone, Copy)]
struct MouseViewportGeometry {
    screen_width: u32,
    screen_height: u32,
    fallback_cols: u16,
    fallback_rows: u16,
    cell_width: u32,
    cell_height: u32,
}

fn mouse_viewport_from_geometry(
    terminal: &InnerTerminal,
    geometry: MouseViewportGeometry,
    position: Option<(f64, f64)>,
) -> Option<point::Coordinate> {
    let (x, y) = position?;
    if !x.is_finite() || !y.is_finite() || x > f64::from(f32::MAX) || y > f64::from(f32::MAX) {
        return None;
    }
    if geometry.screen_width == 0 || geometry.screen_height == 0 {
        return None;
    }

    let terminal_cols = u32::from(terminal.columns());
    let terminal_rows = terminal.rows();
    let cols = if terminal_cols == 0 {
        u32::from(geometry.fallback_cols).max(1)
    } else {
        terminal_cols
    };
    let rows = if terminal_rows == 0 {
        geometry.fallback_rows.max(1)
    } else {
        terminal_rows
    };
    let cell_width = if geometry.cell_width == 0 {
        geometry.screen_width / cols.max(1)
    } else {
        geometry.cell_width
    }
    .max(1);
    let cell_height = if geometry.cell_height == 0 {
        geometry.screen_height / u32::from(rows.max(1))
    } else {
        geometry.cell_height
    }
    .max(1);

    let geometry = mouse_encode::Geometry {
        screen: mouse_encode::PixelSize {
            width: geometry.screen_width,
            height: geometry.screen_height,
        },
        cell: mouse_encode::PixelSize {
            width: cell_width,
            height: cell_height,
        },
        padding: mouse_encode::Padding::default(),
    };
    let pos = mouse_encode::Position {
        x: x as f32,
        y: y as f32,
    };
    (!geometry.pos_out_of_viewport(pos)).then(|| geometry.pos_to_cell(pos))
}

fn osc8_hover_link_ranges(
    terminal: &InnerTerminal,
    map: &terminal::string_map::ViewportStringMap,
    rows: usize,
    mouse_viewport: Option<point::Coordinate>,
    mouse_mods: key_mods::Mods,
) -> Vec<Vec<[u16; 2]>> {
    let Some(mouse) = mouse_viewport else {
        return vec![Vec::new(); rows];
    };
    if mouse_mods != key_mods::ctrl_or_super(key_mods::Mods::new()) {
        return vec![Vec::new(); rows];
    }
    let Some(hover_ref) = terminal.grid_ref(TerminalPointTag::Viewport, mouse) else {
        return vec![Vec::new(); rows];
    };
    let Ok(hover_uri) = hover_ref.hyperlink_uri() else {
        return vec![Vec::new(); rows];
    };
    if hover_uri.is_empty() {
        return vec![Vec::new(); rows];
    }

    let mut seen = HashSet::new();
    let mut cells = Vec::new();
    for &cell in &map.map {
        if !seen.insert(cell) {
            continue;
        }
        let Some(ref_) = terminal.grid_ref(TerminalPointTag::Viewport, cell) else {
            continue;
        };
        if ref_.hyperlink_uri().is_ok_and(|uri| uri == hover_uri) {
            cells.push(cell);
        }
    }

    renderer::link::ranges_from_cells(rows, cells)
}

impl Drop for Surface {
    fn drop(&mut self) {
        // Stop the present driver (Exp 19/175) so no tick dereferences this surface after it drops.
        if let Some(driver) = &mut self.present_driver {
            driver.stop();
        }
        self.clear_clipboard_requests();
    }
}

