#[cfg(test)]
thread_local! {
    static DEFAULT_SHELL_DESKTOP_OVERRIDE: Cell<Option<bool>> = const { Cell::new(None) };
}

fn default_shell_program() -> OsString {
    default_shell_program_from(
        std::env::var_os("SHELL"),
        os::passwd::get().shell,
        launched_from_desktop_for_default_shell(),
    )
}

fn default_shell_program_from(
    env_shell: Option<OsString>,
    passwd_shell: Option<OsString>,
    launched_from_desktop: bool,
) -> OsString {
    if !launched_from_desktop {
        if let Some(shell) = env_shell.filter(|shell| !shell.is_empty()) {
            return shell;
        }
    }
    if let Some(shell) = passwd_shell.filter(|shell| !shell.is_empty()) {
        return shell;
    }
    OsString::from("/bin/sh")
}

fn launched_from_desktop_for_default_shell() -> bool {
    #[cfg(test)]
    if let Some(value) = DEFAULT_SHELL_DESKTOP_OVERRIDE.with(Cell::get) {
        return value;
    }

    os::desktop::launched_from_desktop()
}

fn clipboard_codepoint_map_entries(
    map: &config::RepeatableClipboardCodepointMap,
) -> Vec<CodepointMapEntry> {
    map.map
        .iter()
        .map(|entry| {
            let replacement = match &entry.replacement {
                config::ClipboardReplacement::Codepoint(cp) => CodepointReplacement::Codepoint(
                    char::from_u32(*cp)
                        .expect("clipboard codepoint map parser validates scalar replacements"),
                ),
                config::ClipboardReplacement::String(value) => {
                    CodepointReplacement::String(value.clone())
                }
            };
            CodepointMapEntry::new(entry.range[0], entry.range[1], replacement)
                .expect("clipboard codepoint map parser validates scalar ranges")
        })
        .collect()
}

fn finalized_parsed_config(config: &config::Config) -> config::Config {
    let mut config = config.clone();
    config.finalize();
    config
}

fn finalized_parsed_config_with_conditional_state(
    config: &config::Config,
    conditional_state: config::conditional::State,
) -> config::Config {
    let finalized = finalized_parsed_config(config);
    match finalized.change_conditional_state(conditional_state) {
        Ok(Some(config)) => config,
        Ok(None) | Err(_) => finalized,
    }
}

fn default_finalized_config() -> config::Config {
    let mut config = config::Config::default();
    config.finalize();
    config
}

fn color_scheme_conditional_theme(color_scheme: c_int) -> Option<config::conditional::Theme> {
    match color_scheme {
        ROASTTY_COLOR_SCHEME_LIGHT => Some(config::conditional::Theme::Light),
        ROASTTY_COLOR_SCHEME_DARK => Some(config::conditional::Theme::Dark),
        _ => None,
    }
}

fn soft_reload_config_storage() -> [usize; 8] {
    let mut storage = [0usize; 8];
    storage[0] = 1;
    storage
}

fn derived_config_palette(config: &config::Config) -> color::Palette {
    if config.palette_generate && !config.palette.mask.is_empty() {
        return color::generate_256_color(
            config.palette.value,
            config.palette.mask,
            config.background.to_terminal_rgb(),
            config.foreground.to_terminal_rgb(),
            config.palette_harmonious,
        );
    }

    config.palette.value
}

fn palette_color_tuples(palette: color::Palette) -> [(u8, u8, u8); 256] {
    let mut result = [(0, 0, 0); 256];
    for (index, rgb) in palette.into_iter().enumerate() {
        result[index] = (rgb.r, rgb.g, rgb.b);
    }
    result
}

fn click_repeat_interval_ns(config: &config::Config) -> u64 {
    u64::from(config.click_repeat_interval) * 1_000_000
}

fn scroll_cursor_key_sequence(y_steps: i64, cursor_keys: bool) -> &'static [u8] {
    match (y_steps > 0, cursor_keys) {
        (true, true) => b"\x1bOA",
        (true, false) => b"\x1b[A",
        (false, true) => b"\x1bOB",
        (false, false) => b"\x1b[B",
    }
}

impl Surface {
    fn apply_config(&mut self, config: &Config) {
        let parsed = finalized_parsed_config_with_conditional_state(
            &config.parsed,
            self.config_conditional_state,
        );
        self.confirm_close_surface = config.confirm_close_surface;
        self.clipboard_paste_protection = parsed.clipboard_paste_protection;
        self.clipboard_paste_bracketed_safe = parsed.clipboard_paste_bracketed_safe;
        self.copy_on_select = parsed.copy_on_select;
        self.selection_clear_on_typing = parsed.selection_clear_on_typing;
        self.selection_word_chars = parsed.selection_word_chars.codepoints.clone();
        self.vt_kam_allowed = parsed.vt_kam_allowed;
        self.key_remaps = parsed.key_remap.clone();
        self.macos_option_as_alt = parsed.macos_option_as_alt;
        self.cursor_click_to_move = parsed.cursor_click_to_move;
        self.right_click_action = parsed.right_click_action;
        self.middle_click_action = parsed.middle_click_action;
        self.mouse_reporting = parsed.mouse_reporting;
        self.mouse_scroll_multiplier = parsed.mouse_scroll_multiplier;
        self.click_repeat_interval_ns = click_repeat_interval_ns(&parsed);
        let _ = self.deactivate_all_key_tables();
        let configured_font_size = parsed.font_size.clamp(1.0, 255.0);
        self.original_font_size_points = configured_font_size;
        if !self.font_size_adjusted {
            self.set_font_size_points(configured_font_size);
        }
        let palette = derived_config_palette(&parsed);
        if let Some(worker) = &self.termio_worker {
            worker.with_termio_mut(|termio| {
                termio
                    .terminal_mut()
                    .set_palette_default(Some(palette_color_tuples(palette)));
            });
            self.dirty = true;
        }
        if self.has_live_view() {
            self.renderer = None;
            self.dirty = true;
            self.wakeup_app();
        }
    }

    fn selection_word_boundaries(&self) -> &[u32] {
        &self.selection_word_chars
    }

    fn sanitized_scale(value: f64) -> f64 {
        if value.is_finite() && value > 0.0 {
            value
        } else {
            1.0
        }
    }

    fn cursor_position(&self) -> (u16, u16) {
        if self.app.is_null() {
            return (0, 0);
        }
        self.termio_worker
            .as_ref()
            .map(|worker| worker.with_termio(|termio| termio.terminal().cursor_position()))
            .unwrap_or((0, 0))
    }

    fn preedit_width(&self) -> u32 {
        self.preedit
            .as_deref()
            .map(|preedit| {
                preedit.chars().fold(0u32, |width, ch| {
                    width.saturating_add(
                        ch.width()
                            .and_then(|width| u32::try_from(width).ok())
                            .unwrap_or(0),
                    )
                })
            })
            .unwrap_or(0)
    }

    fn ime_point(&self) -> ImePoint {
        if self.size.cell_width_px == 0 || self.size.cell_height_px == 0 {
            return ImePoint::default();
        }

        let (cursor_x, cursor_y) = self.cursor_position();
        let cursor_x = u32::from(cursor_x);
        let cursor_y = u32::from(cursor_y);
        let cell_width = self.size.cell_width_px;
        let cell_height = self.size.cell_height_px;
        let scale_x = Self::sanitized_scale(self.scale_factor_x);
        let scale_y = Self::sanitized_scale(self.scale_factor_y);
        let remaining_width = self
            .size
            .width_px
            .saturating_sub(cursor_x.saturating_add(1).saturating_mul(cell_width));
        let preedit_width = self
            .preedit_width()
            .saturating_mul(cell_width)
            .min(remaining_width);

        ImePoint {
            x: (f64::from(cursor_x.saturating_mul(cell_width)) + f64::from(cell_width) / 2.0)
                / scale_x,
            y: f64::from(
                cursor_y
                    .saturating_mul(cell_height)
                    .saturating_add(cell_height),
            ) / scale_y,
            width: f64::from(preedit_width),
            height: f64::from(cell_height) / scale_y,
        }
    }

    fn selection_text_metadata(
        &self,
        terminal: &InnerTerminal,
        selection: TerminalSelection,
    ) -> RoasttyText {
        if self.size.cell_width_px == 0 || self.size.cell_height_px == 0 {
            return empty_text();
        }

        let Ok(Some(selection)) =
            terminal.selection_ordered(selection, TerminalSelectionOrder::Forward)
        else {
            return empty_text();
        };
        let Some((viewport_top_left, viewport_bottom_right)) = terminal.viewport_bounds() else {
            return empty_text();
        };
        let Ok(selection_before_viewport) =
            terminal.grid_ref_before(selection.end, viewport_top_left)
        else {
            return empty_text();
        };
        if selection_before_viewport {
            return empty_text();
        }
        let Ok(viewport_before_selection) =
            terminal.grid_ref_before(viewport_bottom_right, selection.start)
        else {
            return empty_text();
        };
        if viewport_before_selection {
            return empty_text();
        }

        let top_left =
            match terminal.point_from_grid_ref(selection.start, TerminalPointTag::Viewport) {
                Ok(coord) => coord,
                Err(_) => match terminal.grid_ref_before(selection.start, viewport_top_left) {
                    Ok(true) => point::Coordinate::new(0, 0),
                    _ => return empty_text(),
                },
            };
        let bottom_right =
            match terminal.point_from_grid_ref(selection.end, TerminalPointTag::Viewport) {
                Ok(coord) => coord,
                Err(_) => match terminal.grid_ref_before(viewport_bottom_right, selection.end) {
                    Ok(true) => match terminal
                        .point_from_grid_ref(viewport_bottom_right, TerminalPointTag::Viewport)
                    {
                        Ok(coord) => coord,
                        Err(_) => return empty_text(),
                    },
                    _ => return empty_text(),
                },
            };
        let columns = terminal.columns();
        if columns == 0 {
            return empty_text();
        }

        let offset_start = viewport_text_offset(top_left, columns);
        let offset_end = viewport_text_offset(bottom_right, columns);
        let scale_x = Self::sanitized_scale(self.scale_factor_x);
        let scale_y = Self::sanitized_scale(self.scale_factor_y);

        RoasttyText {
            tl_px_x: f64::from(u32::from(top_left.x).saturating_mul(self.size.cell_width_px))
                / scale_x,
            tl_px_y: f64::from(u32::from(top_left.y).saturating_mul(self.size.cell_height_px))
                / scale_y,
            offset_start,
            offset_len: offset_end.saturating_sub(offset_start),
            text: ptr::null(),
            text_len: 0,
        }
    }

    fn pty_size(&self) -> os::pty::PtySize {
        os::pty::PtySize {
            rows: if self.size.rows == 0 {
                24
            } else {
                self.size.rows
            },
            cols: if self.size.columns == 0 {
                80
            } else {
                self.size.columns
            },
            width_px: u16::try_from(self.size.width_px).unwrap_or(u16::MAX),
            height_px: u16::try_from(self.size.height_px).unwrap_or(u16::MAX),
        }
    }

    fn start_termio(&mut self) -> c_int {
        append_ui_key_trace(format!(
            "rust surface_start_termio begin app_null={} has_worker={} initial_surface={} process_exited={} size={}x{} rows={} cols={}",
            self.app.is_null(),
            self.termio_worker.is_some(),
            self.initial_surface,
            self.process_exited,
            self.size.width_px,
            self.size.height_px,
            self.size.rows,
            self.size.columns
        ));
        if self.app.is_null() {
            append_ui_key_trace("rust surface_start_termio result=invalid reason=app-null");
            return ROASTTY_INVALID_VALUE;
        }
        if self.termio_worker.is_some() {
            append_ui_key_trace(
                "rust surface_start_termio result=success reason=already-has-worker",
            );
            return ROASTTY_SUCCESS;
        }

        let cwd = self.working_directory.as_ref().map(PathBuf::from);
        let size = self.pty_size();
        let config = app_from_handle(self.app)
            .map(|app| app.parsed_config.clone())
            .unwrap_or_default();
        let resource_dir = os::resources_dir::resources_dir()
            .ok()
            .and_then(|resources| resources.host().map(PathBuf::from));
        let command = self
            .command
            .as_deref()
            .filter(|command| !command.is_empty());
        let initial_command = if command.is_none() && self.initial_surface {
            config.initial_command.as_ref()
        } else {
            None
        };
        append_ui_key_trace(format!(
            "rust surface_start_termio command={} initial_command={} cwd={} env_count={} term={}",
            command.unwrap_or("<default-shell>"),
            initial_command
                .map(|command| match command {
                    config::Command::Shell(_) => "shell",
                    config::Command::Direct(_) => "direct",
                })
                .unwrap_or("none"),
            cwd.as_ref()
                .map(|path| path.display().to_string())
                .unwrap_or_else(|| "<none>".to_string()),
            self.env_vars.len(),
            config.term
        ));

        let options = termio::TermioSpawnOptions {
            cwd,
            env: self.env_vars.clone(),
            cursor_visual_style: config.cursor_style.to_terminal(),
            cursor_blink: config.cursor_style_blink,
            shell_integration: config.shell_integration,
            shell_integration_features: config.shell_integration_features,
            resource_dir: resource_dir.clone(),
            term: config.term.clone(),
            palette: derived_config_palette(&config),
        };

        let termio = match (command, initial_command) {
            (Some(command), _) => {
                termio::Termio::spawn_with_options("/bin/sh", ["-lc", command], options, size)
            }
            (None, Some(config::Command::Shell(command))) => termio::Termio::spawn_with_options(
                "/bin/sh",
                ["-lc", command.as_str()],
                options,
                size,
            ),
            (None, Some(config::Command::Direct(args))) => match args.split_first() {
                Some((program, args)) => termio::Termio::spawn_with_options(
                    program,
                    args.iter().map(String::as_str),
                    options,
                    size,
                ),
                None => termio::Termio::spawn_with_options(
                    default_shell_program(),
                    std::iter::empty::<&str>(),
                    options,
                    size,
                ),
            },
            (None, None) => termio::Termio::spawn_with_options(
                default_shell_program(),
                std::iter::empty::<&str>(),
                options,
                size,
            ),
        };
        let Ok(termio) = termio else {
            append_ui_key_trace(
                "rust surface_start_termio result=invalid reason=termio-spawn-failed",
            );
            return ROASTTY_INVALID_VALUE;
        };

        let worker = termio::TermioWorker::spawn(termio, 10, 4096);
        let Ok(worker) = worker else {
            append_ui_key_trace(
                "rust surface_start_termio result=invalid reason=worker-spawn-failed",
            );
            return ROASTTY_INVALID_VALUE;
        };
        if let Some(initial_input) = &self.initial_input {
            append_ui_key_trace(format!(
                "rust surface_start_termio initial_input_len={}",
                initial_input.len()
            ));
            if worker.queue_write(initial_input).is_err() {
                append_ui_key_trace(
                    "rust surface_start_termio result=invalid reason=initial-input-disconnected",
                );
                return ROASTTY_INVALID_VALUE;
            }
        }

        self.termio_worker = Some(worker);
        self.process_exited = false;
        self.dirty = false;
        // Present an initial frame now that the terminal worker is running (Issue 802 / Exp 15,
        // slice 1) — `set_size` fires before the worker exists, so this is the first present
        // with a live terminal. (Continuous live updates need the slice-2 CVDisplayLink driver.)
        self.present_live();
        self.last_termio_error = None;
        append_ui_key_trace("rust surface_start_termio result=success reason=worker-assigned");
        ROASTTY_SUCCESS
    }

    fn set_size(&mut self, width: u32, height: u32) {
        // Compute the pixel-size change BEFORE the store (Issue 802 / Exp 37) — gates the in-band
        // size report below. `resize_pty` stays unconditional.
        let changed = self.size.width_px != width || self.size.height_px != height;
        self.size.width_px = width;
        self.size.height_px = height;

        let size = self.pty_size();
        let mut resize_err = None;
        if let Some(worker) = &self.termio_worker {
            if let Err(err) = worker.resize_pty(size) {
                resize_err = Some(format!("{err:?}"));
            } else if changed {
                // On an actual resize, emit the in-band size report if mode 2048 is enabled (Exp 37).
                worker.with_termio_mut(|termio| termio.terminal_mut().report_in_band_size());
            }
        }
        if let Some(err) = resize_err {
            self.apply_termio_event(termio::TermioWorkerEvent::Error(err));
        }
    }

    fn request_render(&mut self) {
        self.dirty = true;
        self.wakeup_app();
    }

    fn has_live_view(&self) -> bool {
        !self.nsview.is_null()
    }

    fn should_present_live(&self) -> bool {
        self.has_live_view() && self.visible
    }

    fn reset_cursor_blink(&mut self, now: std::time::Instant) {
        self.cursor_blink_visible = true;
        self.cursor_blink_next = now + CURSOR_BLINK_INTERVAL;
        self.dirty = true;
    }

    fn reset_cursor_blink_for_output(&mut self, now: std::time::Instant) {
        if self
            .last_cursor_reset
            .is_some_and(|last| now.duration_since(last) <= CURSOR_BLINK_RESET_THROTTLE)
        {
            return;
        }

        self.last_cursor_reset = Some(now);
        self.reset_cursor_blink(now);
    }

    fn advance_cursor_blink(&mut self, now: std::time::Instant) -> bool {
        if !self.focused || now < self.cursor_blink_next {
            return false;
        }

        self.cursor_blink_visible = !self.cursor_blink_visible;
        self.cursor_blink_next = now + CURSOR_BLINK_INTERVAL;
        self.dirty = true;
        true
    }

    fn focus_changed_for_cursor_blink(&mut self, focused: bool, now: std::time::Instant) {
        if focused {
            self.cursor_blink_visible = true;
            self.cursor_blink_next = now + CURSOR_BLINK_INTERVAL;
        }
        self.request_live_render();
    }

    fn apply_focus_options(&mut self, focused: bool, now: std::time::Instant) {
        let changed = self.focused != focused;
        self.focused = focused;
        if changed {
            if let Some(renderer) = self.renderer.as_mut() {
                renderer.custom_shader.focus_changed = true;
            }
            self.focus_changed_for_cursor_blink(focused, now);
        }
    }

    fn apply_visibility_options(&mut self, visible: bool) {
        if self.visible == visible {
            return;
        }
        self.visible = visible;
        if visible {
            self.request_live_render();
        }
    }

    fn request_live_render(&mut self) {
        if self.has_live_view() {
            self.dirty = true;
            self.wakeup_app();
        }
    }

    fn refresh(&mut self) {
        self.request_render();
    }

    fn draw(&mut self) {
        self.request_render();
        self.present_live();
    }

    /// Render the live terminal and present it into the app's NSView layer (Issue 802 / Exp 15,
    /// slice 1). Lazily builds the Metal renderer on first call (main thread; driven from
    /// `set_size`/`set_content_scale`/`draw`). No-op without an nsview or a running terminal.
    fn present_live(&mut self) {
        if !self.should_present_live() {
            return;
        }
        if self.renderer.is_none() {
            let config = app_from_handle(self.app)
                .map(|app| app.parsed_config.clone())
                .unwrap_or_default();
            self.renderer = build_live_renderer(
                self.nsview,
                &config,
                self.font_size_points,
                self.size.width_px,
                self.size.height_px,
                self.scale_factor_x,
            );
        }
        if let Some(cell) = self
            .renderer
            .as_ref()
            .map(|live| live.shared_grid.cell_size())
        {
            if cell.width > 0 && cell.height > 0 {
                self.size.cell_width_px = cell.width;
                self.size.cell_height_px = cell.height;
                self.size.columns =
                    (self.size.width_px / cell.width).min(u32::from(u16::MAX)) as u16;
                self.size.rows =
                    (self.size.height_px / cell.height).min(u32::from(u16::MAX)) as u16;
            }
        }
        let width = self.size.width_px.max(1) as usize;
        let height = self.size.height_px.max(1) as usize;
        let scale = self.scale_factor_x.max(1.0);
        let columns = self.size.columns;
        let rows = self.size.rows;
        let focused = self.focused;
        let cursor_options = renderer::frame_renderer::FrameCursorOptions {
            focused,
            blink_visible: self.cursor_blink_visible,
        };
        let mouse_position = self.mouse.position;
        let mouse_mods = self.mouse.mods;
        let mouse_geometry = MouseViewportGeometry {
            screen_width: self.size.width_px,
            screen_height: self.size.height_px,
            fallback_cols: self.pty_size().cols,
            fallback_rows: self.pty_size().rows,
            cell_width: self.size.cell_width_px,
            cell_height: self.size.cell_height_px,
        };
        let Some(live) = self.renderer.as_mut() else {
            return;
        };
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        let SurfaceLiveRenderer {
            device,
            compositor,
            frame_renderer,
            image_state,
            background_image,
            link_set,
            custom_shader,
            shared_grid,
        } = live;
        // Drive the projection/screen-size + font-grid uniforms from the surface (Exp 18) — the
        // rebuild updates grid_size but not the projection, so without this glyphs render
        // off-screen. Physical-pixel space throughout (clamped width/height, scaled cell).
        frame_renderer.update_screen(
            renderer::size::Size {
                screen: renderer::size::ScreenSize {
                    width: width as u32,
                    height: height as u32,
                },
                cell: shared_grid.cell_size(),
                padding: renderer::size::Padding::default(),
            },
            renderer::size::GridSize { columns, rows },
            &shared_grid.metrics,
        );
        let config = app_from_handle(self.app)
            .map(|app| app.parsed_config.clone())
            .unwrap_or_default();
        link_set.sync_from_config(&config.link);
        custom_shader.sync_from_config(device, &config);
        worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let viewport_map = terminal.viewport_string_map();
            let mouse_viewport =
                mouse_viewport_from_geometry(terminal, mouse_geometry, mouse_position);
            let rows = usize::from(terminal.rows());
            let regex_ranges =
                link_set.render_ranges(&viewport_map, rows, mouse_viewport, mouse_mods);
            let osc8_ranges =
                osc8_hover_link_ranges(terminal, &viewport_map, rows, mouse_viewport, mouse_mods);
            let link_ranges = renderer::link::merge_ranges(regex_ranges, &osc8_ranges);
            let kitty_placements = kitty_render_placement_snapshots(terminal);
            image_state.update_kitty_from_render_placements(&kitty_placements);
            let present_result = if custom_shader.pipelines.is_empty() {
                frame_renderer.render_and_present_frame_with_images_and_link_ranges_and_cursor_options(
                    terminal,
                    shared_grid,
                    image_state,
                    background_image,
                    link_ranges,
                    renderer::frame_rebuild::RenderDirty::Full,
                    None,
                    &config,
                    renderer::frame_rebuild::FramePreparedPresentationInput {
                        compositor,
                        width,
                        height,
                        contents_scale: scale,
                    },
                    cursor_options,
                )
            } else {
                let cell = shared_grid.cell_size();
                let custom_input = custom_shader.frame_input(
                    [width as u32, height as u32],
                    [cell.width, cell.height],
                    focused,
                );
                let pipeline_refs: Vec<_> = custom_shader.pipelines.iter().collect();
                let result = frame_renderer
                    .render_and_present_frame_with_images_and_custom_shaders_and_link_ranges_and_cursor_options(
                        terminal,
                        shared_grid,
                        image_state,
                        background_image,
                        &mut custom_shader.uniforms,
                        custom_input,
                        &pipeline_refs,
                        link_ranges,
                        renderer::frame_rebuild::RenderDirty::Full,
                        None,
                        &config,
                        renderer::frame_rebuild::FramePreparedPresentationInput {
                            compositor,
                            width,
                            height,
                            contents_scale: scale,
                        },
                        cursor_options,
                    );
                custom_shader.focus_changed = match &result {
                    Ok(app) => app
                        .custom_shader
                        .map(|custom| custom.next_focus_changed)
                        .unwrap_or(custom_input.focus_changed),
                    Err(_) => custom_input.focus_changed,
                };
                result
            };
            if let Err(e) = present_result {
                eprintln!("[roastty] live present error: {e:?}");
            }
        });
    }

    fn wakeup_app(&self) {
        let Some(app) = app_from_handle(self.app) else {
            return;
        };
        if let Some(wakeup) = app.runtime.wakeup_cb {
            unsafe {
                wakeup(app.runtime.userdata);
            }
        }
    }

    fn needs_confirm_quit(&self) -> bool {
        if self.app.is_null() || self.process_exited {
            return false;
        }

        match self.confirm_close_surface {
            config::ConfirmCloseSurface::Always => true,
            config::ConfirmCloseSurface::False => false,
            config::ConfirmCloseSurface::True => {
                let Some(worker) = self.termio_worker.as_ref() else {
                    return false;
                };
                let at_prompt =
                    worker.with_termio(|termio| termio.terminal().cursor_is_at_prompt());
                self.confirm_close_surface.needs_confirm(at_prompt)
            }
        }
    }

    fn request_close(&self) {
        let Some(app) = app_from_handle(self.app) else {
            return;
        };
        if let Some(close_surface) = app.runtime.close_surface_cb {
            unsafe {
                close_surface(self.userdata, self.needs_confirm_quit());
            }
        }
    }

    fn inspector_handle(&mut self) -> RoasttyInspector {
        if self.app.is_null() {
            return ptr::null_mut();
        }
        if let Some(inspector) = self.inspector {
            return inspector.as_ptr().cast();
        }

        let inspector = Box::new(Inspector {
            width: 0,
            height: 0,
            scale_x: 1.0,
            scale_y: 1.0,
            focused: false,
            mouse_position: None,
            mouse_button: None,
            mouse_scroll: None,
            key: None,
            text: None,
        });
        let inspector = unsafe { NonNull::new_unchecked(Box::into_raw(inspector)) };
        self.inspector = Some(inspector);
        inspector.as_ptr().cast()
    }

    fn free_inspector(&mut self) {
        if let Some(inspector) = self.inspector.take() {
            unsafe {
                drop(Box::from_raw(inspector.as_ptr()));
            }
        }
    }

    fn perform_action(&self, tag: c_int, storage: [usize; 8]) {
        let _ = self.perform_action_result(tag, storage);
    }

    fn perform_action_result(&self, tag: c_int, storage: [usize; 8]) -> bool {
        self.perform_targeted_action_result(
            ROASTTY_TARGET_SURFACE,
            (self as *const Surface).cast_mut().cast(),
            tag,
            storage,
        )
    }

    fn perform_app_action_result(&self, tag: c_int, storage: [usize; 8]) -> bool {
        self.perform_targeted_action_result(ROASTTY_TARGET_APP, ptr::null_mut(), tag, storage)
    }

    fn perform_start_search_result(&self, needle: &CStr) -> bool {
        let mut storage = [0usize; 8];
        storage[0] = needle.as_ptr() as usize;
        self.perform_action_result(ROASTTY_ACTION_START_SEARCH, storage)
    }

    #[allow(dead_code)]
    fn perform_open_url_result(&self, kind: c_int, url: &[u8]) -> bool {
        let mut storage = [0usize; 8];
        storage[0] = kind as usize;
        storage[1] = url.as_ptr() as usize;
        storage[2] = url.len();
        self.perform_action_result(ROASTTY_ACTION_OPEN_URL, storage)
    }

    fn perform_targeted_action_result(
        &self,
        target_tag: c_int,
        target_surface: RoasttySurface,
        tag: c_int,
        storage: [usize; 8],
    ) -> bool {
        let Some(app) = app_from_handle(self.app) else {
            return false;
        };
        if let Some(action) = app.runtime.action_cb {
            let target = RoasttyTarget {
                tag: target_tag,
                target: RoasttyTargetU {
                    surface: target_surface,
                },
            };
            let action_value = RoasttyAction {
                tag,
                action: action_u_from_storage(tag, storage),
            };
            return unsafe { action(self.app, target, action_value) };
        }
        false
    }

    fn prompt_title(&self, prompt: c_int) -> bool {
        let mut storage = [0usize; 8];
        storage[0] = prompt as usize;
        self.perform_action_result(ROASTTY_ACTION_PROMPT_TITLE, storage)
    }

    fn set_title(&self, tag: c_int, title: &[u8]) -> bool {
        let Ok(title) = CString::new(title) else {
            return false;
        };
        let mut storage = [0usize; 8];
        storage[0] = title.as_ptr() as usize;
        self.perform_action_result(tag, storage)
    }

    fn inherited_config(&mut self, context: c_int) -> RoasttySurfaceConfig {
        let mut config = roastty_surface_config_new();
        config.context = valid_surface_context(context).unwrap_or(self.context);
        if self.app.is_null() {
            self.inherited_working_directory = None;
            return config;
        }
        self.inherited_working_directory = self
            .termio_worker
            .as_ref()
            .and_then(|worker| {
                worker.with_termio(|termio| termio.terminal().pwd().map(str::to_owned))
            })
            .and_then(|pwd| CString::new(pwd).ok());
        if let Some(pwd) = self.inherited_working_directory.as_ref() {
            config.working_directory = pwd.as_ptr();
        }
        config
    }

    fn text(&mut self, text: &[u8]) {
        if text.is_empty() || self.app.is_null() {
            return;
        }

        let error = {
            if self.readonly {
                return;
            }
            let Some(worker) = self.termio_worker.as_ref() else {
                return;
            };
            let bracketed =
                worker.with_termio(|termio| termio.terminal().bracketed_paste_enabled());
            let mut data = text.to_vec();
            let segments = paste::encode(&mut data, paste::PasteOptions { bracketed });
            let mut error = None;
            for segment in segments {
                if segment.is_empty() {
                    continue;
                }
                if let Err(err) = worker.queue_write(segment) {
                    error = Some(format!("{err:?}"));
                    break;
                }
            }
            error
        };

        if let Some(error) = error {
            self.apply_termio_event(termio::TermioWorkerEvent::Error(error));
        } else if self.selection_clear_on_typing {
            self.selection_clear_and_reset();
        }
    }

    fn raw_text(&mut self, text: &[u8]) {
        if text.is_empty() || self.app.is_null() {
            return;
        }
        if self.readonly {
            return;
        }

        let error = {
            let Some(worker) = self.termio_worker.as_ref() else {
                return;
            };
            worker.queue_write(text).err().map(|err| format!("{err:?}"))
        };

        if let Some(error) = error {
            self.apply_termio_event(termio::TermioWorkerEvent::Error(error));
        } else if self.selection_clear_on_typing {
            self.selection_clear_and_reset();
        }
    }

    fn reset_terminal(&mut self) {
        if self.app.is_null() {
            return;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        worker.with_termio_mut(|termio| termio.terminal_mut().reset());
        self.request_render();
    }

    fn clear_screen(&mut self) -> bool {
        if self.app.is_null() {
            return false;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        let result = worker.with_termio_mut(|termio| termio.terminal_mut().clear_screen(true));
        let result = match result {
            Ok(result) => result,
            Err(err) => {
                self.apply_termio_event(termio::TermioWorkerEvent::Error(format!("{err:?}")));
                return false;
            }
        };
        let write_error = if result == ClearScreenResult::SendFormFeed && !self.readonly {
            worker
                .queue_write(b"\x0c")
                .err()
                .map(|err| format!("{err:?}"))
        } else {
            None
        };
        match result {
            ClearScreenResult::NotPerformed => false,
            ClearScreenResult::Performed | ClearScreenResult::SendFormFeed => {
                self.request_render();
                if let Some(error) = write_error {
                    self.apply_termio_event(termio::TermioWorkerEvent::Error(error));
                }
                true
            }
        }
    }

    fn select_all(&mut self) -> bool {
        if self.app.is_null() {
            return false;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        let selected = match worker.with_termio_mut(|termio| {
            let Some(selection) = termio.terminal().select_all() else {
                return Ok::<bool, TerminalGridRefPointError>(false);
            };
            termio.terminal_mut().set_selection(Some(selection))?;
            Ok(true)
        }) {
            Ok(selected) => selected,
            Err(err) => {
                self.apply_termio_event(termio::TermioWorkerEvent::Error(format!("{err:?}")));
                return false;
            }
        };
        if selected {
            self.request_render();
        }
        true
    }

    fn adjust_selection(&mut self, adjustment: TerminalSelectionAdjustment) -> bool {
        if self.app.is_null() {
            return false;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        let adjusted = match worker
            .with_termio_mut(|termio| termio.terminal_mut().adjust_active_selection(adjustment))
        {
            Ok(adjusted) => adjusted,
            Err(err) => {
                self.apply_termio_event(termio::TermioWorkerEvent::Error(format!("{err:?}")));
                return false;
            }
        };
        if adjusted {
            self.request_render();
        }
        adjusted
    }

    fn copy_to_clipboard(&mut self, format: CopyToClipboardFormat) -> bool {
        if self.app.is_null() {
            return false;
        }
        let Some(app) = app_from_handle(self.app) else {
            return false;
        };
        let Some(write_clipboard) = app.runtime.write_clipboard_cb else {
            return false;
        };
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        let codepoint_map =
            clipboard_codepoint_map_entries(&app.parsed_config.clipboard_codepoint_map);
        let codepoint_map = (!codepoint_map.is_empty()).then_some(codepoint_map);
        let codepoint_map = codepoint_map.as_deref();
        let trim_trailing_spaces = app.parsed_config.clipboard_trim_trailing_spaces;
        let Some(formatted) = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let selection = terminal.active_selection()?;
            match format {
                CopyToClipboardFormat::Plain => terminal
                    .selection_format_with_codepoint_map(
                        TerminalSelectionFormat::Plain,
                        true,
                        trim_trailing_spaces,
                        Some(selection),
                        codepoint_map,
                    )
                    .ok()
                    .map(|text| vec![("text/plain", text)]),
                CopyToClipboardFormat::Vt => terminal
                    .selection_format_with_codepoint_map(
                        TerminalSelectionFormat::Vt,
                        true,
                        trim_trailing_spaces,
                        Some(selection),
                        codepoint_map,
                    )
                    .ok()
                    .map(|text| vec![("text/plain", text)]),
                CopyToClipboardFormat::Html => terminal
                    .selection_format_with_codepoint_map(
                        TerminalSelectionFormat::Html,
                        true,
                        trim_trailing_spaces,
                        Some(selection),
                        codepoint_map,
                    )
                    .ok()
                    .map(|text| vec![("text/html", text)]),
                CopyToClipboardFormat::Mixed => {
                    let plain = terminal
                        .selection_format_with_codepoint_map(
                            TerminalSelectionFormat::Plain,
                            true,
                            trim_trailing_spaces,
                            Some(selection),
                            codepoint_map,
                        )
                        .ok()?;
                    let html = terminal
                        .selection_format_with_codepoint_map(
                            TerminalSelectionFormat::Html,
                            true,
                            trim_trailing_spaces,
                            Some(selection),
                            codepoint_map,
                        )
                        .ok()?;
                    Some(vec![("text/plain", plain), ("text/html", html)])
                }
            }
        }) else {
            return false;
        };

        let mut mime_strings = Vec::with_capacity(formatted.len());
        let mut data_strings = Vec::with_capacity(formatted.len());
        for (mime, data) in formatted {
            let Ok(mime) = CString::new(mime) else {
                return false;
            };
            let Ok(data) = CString::new(data) else {
                return false;
            };
            mime_strings.push(mime);
            data_strings.push(data);
        }
        let contents: Vec<RoasttyClipboardContent> = mime_strings
            .iter()
            .zip(data_strings.iter())
            .map(|(mime, data)| RoasttyClipboardContent {
                mime: mime.as_ptr(),
                data: data.as_ptr(),
            })
            .collect();
        unsafe {
            write_clipboard(
                app.runtime.userdata,
                ROASTTY_CLIPBOARD_STANDARD,
                contents.as_ptr(),
                contents.len(),
                false,
            );
        }
        if app.parsed_config.selection_clear_on_copy {
            self.selection_clear_and_reset();
        }
        true
    }

    fn clipboard_paste_is_unsafe(&self, bytes: &[u8], confirmed: bool) -> bool {
        if !self.clipboard_paste_protection || confirmed {
            return false;
        }
        let bracketed = self
            .termio_worker
            .as_ref()
            .map(|worker| worker.with_termio(|termio| termio.terminal().bracketed_paste_enabled()))
            .unwrap_or(false);
        if bracketed {
            if bytes
                .windows(b"\x1b[201~".len())
                .any(|window| window == b"\x1b[201~")
            {
                return true;
            }
            if self.clipboard_paste_bracketed_safe {
                return false;
            }
        }
        !paste::is_safe(bytes)
    }

    fn copy_url_to_clipboard(&mut self) -> bool {
        if self.app.is_null() {
            return false;
        }
        let Some(app) = app_from_handle(self.app) else {
            return false;
        };
        let Some(write_clipboard) = app.runtime.write_clipboard_cb else {
            return false;
        };
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        let Some((x, y)) = self.mouse.position else {
            return false;
        };
        if !x.is_finite() || !y.is_finite() || x > f64::from(f32::MAX) || y > f64::from(f32::MAX) {
            return false;
        }

        let uri = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let geometry = self.mouse_report_geometry(terminal)?;
            let pos = mouse_encode::Position {
                x: x as f32,
                y: y as f32,
            };
            if geometry.pos_out_of_viewport(pos) {
                return None;
            }
            let cell = geometry.pos_to_cell(pos);
            let ref_ = terminal.grid_ref(TerminalPointTag::Viewport, cell)?;
            match ref_.hyperlink_uri() {
                Ok(uri) if !uri.is_empty() => Some(uri),
                _ => None,
            }
        });
        let Some(uri) = uri else {
            return false;
        };

        let Ok(mime) = CString::new("text/plain") else {
            return false;
        };
        let Ok(data) = CString::new(uri) else {
            return false;
        };
        let content = RoasttyClipboardContent {
            mime: mime.as_ptr(),
            data: data.as_ptr(),
        };
        unsafe {
            write_clipboard(
                app.runtime.userdata,
                ROASTTY_CLIPBOARD_STANDARD,
                ptr::addr_of!(content),
                1,
                false,
            );
        }
        true
    }

    fn create_write_file(
        &self,
        target: WriteFileTarget,
        format: WriteFileFormat,
    ) -> Option<(os::temp_dir::TempDir, String)> {
        let worker = self.termio_worker.as_ref()?;
        let text = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            match target {
                WriteFileTarget::Selection => {
                    let selection = terminal.active_selection()?;
                    terminal
                        .selection_format(format.selection_format(), true, false, Some(selection))
                        .ok()
                }
                WriteFileTarget::Screen => terminal
                    .formatter_format(
                        format.selection_format(),
                        true,
                        false,
                        TerminalFormatterExtra::none(),
                        None,
                    )
                    .ok(),
                WriteFileTarget::Scrollback => terminal.scrollback_format(
                    format.selection_format(),
                    true,
                    false,
                    TerminalFormatterExtra::none(),
                ),
            }
        })?;

        let temp_dir = os::temp_dir::TempDir::new().ok()?;
        let filename = match (target, format) {
            (WriteFileTarget::Selection, WriteFileFormat::Plain | WriteFileFormat::Vt) => {
                "selection.txt"
            }
            (WriteFileTarget::Selection, WriteFileFormat::Html) => "selection.html",
            (WriteFileTarget::Screen, WriteFileFormat::Plain | WriteFileFormat::Vt) => "screen.txt",
            (WriteFileTarget::Screen, WriteFileFormat::Html) => "screen.html",
            (WriteFileTarget::Scrollback, WriteFileFormat::Plain | WriteFileFormat::Vt) => {
                "scrollback.txt"
            }
            (WriteFileTarget::Scrollback, WriteFileFormat::Html) => "scrollback.html",
        };
        let path = temp_dir.path().join(filename);
        let written = std::fs::File::create(&path)
            .and_then(|mut file| file.write_all(text.as_bytes()).and_then(|()| file.flush()));
        if written.is_err() {
            return None;
        }
        let path = std::fs::canonicalize(&path).ok()?;
        let path = path.to_str()?.to_owned();
        Some((temp_dir, path))
    }

    fn write_file(
        &mut self,
        target: WriteFileTarget,
        action: WriteFileAction,
        format: WriteFileFormat,
    ) -> bool {
        if self.app.is_null() {
            return false;
        }

        match action {
            WriteFileAction::Copy => {
                let Some(app) = app_from_handle(self.app) else {
                    return false;
                };
                let Some(write_clipboard) = app.runtime.write_clipboard_cb else {
                    return false;
                };
                let Some((temp_dir, path)) = self.create_write_file(target, format) else {
                    return false;
                };
                let Ok(mime) = CString::new("text/plain") else {
                    return false;
                };
                let Ok(data) = CString::new(path) else {
                    return false;
                };
                let content = RoasttyClipboardContent {
                    mime: mime.as_ptr(),
                    data: data.as_ptr(),
                };
                unsafe {
                    write_clipboard(
                        app.runtime.userdata,
                        ROASTTY_CLIPBOARD_STANDARD,
                        ptr::addr_of!(content),
                        1,
                        false,
                    );
                }
                self.retained_write_file_dirs.push(temp_dir);
                true
            }
            WriteFileAction::Paste => {
                if self.readonly {
                    return false;
                }
                let Some((temp_dir, path)) = self.create_write_file(target, format) else {
                    return false;
                };
                let Some(worker) = self.termio_worker.as_ref() else {
                    return false;
                };
                if let Err(err) = worker.queue_write(path.as_bytes()) {
                    self.apply_termio_event(termio::TermioWorkerEvent::Error(format!("{err:?}")));
                    return false;
                }
                self.retained_write_file_dirs.push(temp_dir);
                true
            }
            WriteFileAction::Open => {
                let Some((temp_dir, path)) = self.create_write_file(target, format) else {
                    return false;
                };
                let kind = match format {
                    WriteFileFormat::Plain | WriteFileFormat::Vt => {
                        ROASTTY_ACTION_OPEN_URL_KIND_TEXT
                    }
                    WriteFileFormat::Html => ROASTTY_ACTION_OPEN_URL_KIND_HTML,
                };
                if !self.perform_open_url_result(kind, path.as_bytes()) {
                    return false;
                }
                self.retained_write_file_dirs.push(temp_dir);
                true
            }
        }
    }

    fn search_selection(&mut self) -> bool {
        if self.app.is_null() {
            return false;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        let Some(text) = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let selection = terminal.active_selection()?;
            terminal
                .selection_format(TerminalSelectionFormat::Plain, true, true, Some(selection))
                .ok()
        }) else {
            return false;
        };
        let Ok(needle) = CString::new(text) else {
            return false;
        };
        self.perform_start_search_result(&needle)
    }

    fn paste_from_clipboard(&mut self, clipboard: c_int) -> bool {
        if self.app.is_null() {
            return false;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        let Some(app) = app_from_handle(self.app) else {
            return false;
        };
        if clipboard == ROASTTY_CLIPBOARD_SELECTION && !app.runtime.supports_selection_clipboard {
            return false;
        }
        let Some(read_clipboard) = app.runtime.read_clipboard_cb else {
            return false;
        };
        let _ = worker;
        let state = self.push_clipboard_request(ROASTTY_CLIPBOARD_REQUEST_PASTE, clipboard, b'c');
        let started = unsafe { read_clipboard(app.runtime.userdata, clipboard, state) };
        if !started {
            self.take_clipboard_request(state);
        }
        started
    }

    fn handle_terminal_clipboard_event(&mut self, event: TerminalClipboardEvent) {
        match event {
            TerminalClipboardEvent::Osc52 { kind, data } => {
                if data == b"?" {
                    self.osc52_clipboard_read(kind, &data);
                } else {
                    self.osc52_clipboard_write(kind, &data);
                }
            }
            TerminalClipboardEvent::Kitty {
                metadata,
                payload,
                terminator,
            } => {
                let event = KittyClipboard {
                    metadata: &metadata,
                    payload: payload.as_deref(),
                    terminator,
                };
                self.kitty_clipboard_event(event);
            }
        }
    }

    fn kitty_clipboard_event(&mut self, event: KittyClipboard<'_>) -> bool {
        let id = event.sanitized_id().unwrap_or_default();
        match event.operation() {
            Some(KittyClipboardOperation::Read) => self.kitty_clipboard_read(event, id),
            Some(KittyClipboardOperation::Write) => self.kitty_clipboard_write_start(event, id),
            Some(KittyClipboardOperation::WriteData) => self.kitty_clipboard_write_data(event, id),
            Some(KittyClipboardOperation::WriteAlias) => self.kitty_clipboard_write_alias(event),
            None => self.kitty_clipboard_error(
                KittyClipboardOperation::Read,
                KittyClipboardStatus::NotImplemented,
                &id,
                event.terminator,
            ),
        }
    }

    fn kitty_clipboard_write_start(&mut self, event: KittyClipboard<'_>, id: Vec<u8>) -> bool {
        if self.app.is_null() || self.termio_worker.is_none() {
            self.kitty_clipboard_write = None;
            return false;
        }
        if self.clipboard_write.denied() {
            return self.kitty_clipboard_write_start_error(
                id,
                event.terminator,
                KittyClipboardStatus::Permission,
            );
        }
        let Some(app) = app_from_handle(self.app) else {
            self.kitty_clipboard_write = None;
            return false;
        };
        let clipboard = if event.loc() == Some(KittyClipboardLocation::Primary) {
            if !app.runtime.supports_selection_clipboard {
                return self.kitty_clipboard_write_start_error(
                    id,
                    event.terminator,
                    KittyClipboardStatus::NotImplemented,
                );
            }
            ROASTTY_CLIPBOARD_SELECTION
        } else {
            ROASTTY_CLIPBOARD_STANDARD
        };

        self.kitty_clipboard_write = Some(KittyClipboardWriteTransaction {
            clipboard,
            id,
            terminator: event.terminator,
            text: Vec::new(),
            failed: false,
        });
        true
    }

    fn kitty_clipboard_write_start_error(
        &mut self,
        id: Vec<u8>,
        terminator: osc::Terminator,
        status: KittyClipboardStatus,
    ) -> bool {
        self.kitty_clipboard_write = Some(KittyClipboardWriteTransaction {
            clipboard: ROASTTY_CLIPBOARD_STANDARD,
            id,
            terminator,
            text: Vec::new(),
            failed: true,
        });
        self.kitty_clipboard_write_error_active(status)
    }

    fn kitty_clipboard_write_data(&mut self, event: KittyClipboard<'_>, id: Vec<u8>) -> bool {
        let Some(transaction) = self.kitty_clipboard_write.as_ref() else {
            self.kitty_clipboard_write = Some(KittyClipboardWriteTransaction {
                clipboard: ROASTTY_CLIPBOARD_STANDARD,
                id,
                terminator: event.terminator,
                text: Vec::new(),
                failed: true,
            });
            return self.kitty_clipboard_write_error_active(KittyClipboardStatus::Invalid);
        };
        if transaction.failed {
            return false;
        }

        match (event.mime(), event.payload) {
            (None, None) => self.kitty_clipboard_write_complete(),
            (Some(mime), Some(payload)) => {
                let Some(decoded_mime) = decode_clipboard_base64(mime) else {
                    return self.kitty_clipboard_write_error_active(KittyClipboardStatus::Invalid);
                };
                if decoded_mime != b"text/plain" {
                    return self
                        .kitty_clipboard_write_error_active(KittyClipboardStatus::NotImplemented);
                }
                let Some(decoded) = decode_clipboard_base64(payload) else {
                    return self.kitty_clipboard_write_error_active(KittyClipboardStatus::Invalid);
                };
                if decoded.contains(&0) {
                    return self.kitty_clipboard_write_error_active(KittyClipboardStatus::Invalid);
                }
                let Some(transaction) = self.kitty_clipboard_write.as_mut() else {
                    return false;
                };
                if transaction.failed {
                    return false;
                }
                transaction.text.extend_from_slice(&decoded);
                true
            }
            _ => self.kitty_clipboard_write_error_active(KittyClipboardStatus::Invalid),
        }
    }

    fn kitty_clipboard_write_alias(&mut self, event: KittyClipboard<'_>) -> bool {
        let Some(transaction) = self.kitty_clipboard_write.as_ref() else {
            let id = event.sanitized_id().unwrap_or_default();
            self.kitty_clipboard_write = Some(KittyClipboardWriteTransaction {
                clipboard: ROASTTY_CLIPBOARD_STANDARD,
                id,
                terminator: event.terminator,
                text: Vec::new(),
                failed: true,
            });
            return self.kitty_clipboard_write_error_active(KittyClipboardStatus::NotImplemented);
        };
        if transaction.failed {
            return false;
        }
        self.kitty_clipboard_write_error_active(KittyClipboardStatus::NotImplemented)
    }

    fn kitty_clipboard_write_complete(&mut self) -> bool {
        let Some(transaction) = self.kitty_clipboard_write.take() else {
            return false;
        };
        if transaction.failed {
            return false;
        }
        if self.termio_worker.is_none() {
            return false;
        }
        if self.app.is_null() {
            return self.kitty_clipboard_write_status(
                &transaction.id,
                transaction.terminator,
                KittyClipboardStatus::Io,
            );
        }
        if self.clipboard_write.denied() {
            return self.kitty_clipboard_write_status(
                &transaction.id,
                transaction.terminator,
                KittyClipboardStatus::Permission,
            );
        }
        let Some(app) = app_from_handle(self.app) else {
            return self.kitty_clipboard_write_status(
                &transaction.id,
                transaction.terminator,
                KittyClipboardStatus::Io,
            );
        };
        let Some(write_clipboard) = app.runtime.write_clipboard_cb else {
            return self.kitty_clipboard_write_status(
                &transaction.id,
                transaction.terminator,
                KittyClipboardStatus::Io,
            );
        };
        let Ok(mime) = CString::new("text/plain") else {
            return self.kitty_clipboard_write_status(
                &transaction.id,
                transaction.terminator,
                KittyClipboardStatus::Io,
            );
        };
        let Ok(text) = CString::new(transaction.text) else {
            return self.kitty_clipboard_write_status(
                &transaction.id,
                transaction.terminator,
                KittyClipboardStatus::Invalid,
            );
        };
        let content = RoasttyClipboardContent {
            mime: mime.as_ptr(),
            data: text.as_ptr(),
        };
        unsafe {
            write_clipboard(
                app.runtime.userdata,
                transaction.clipboard,
                ptr::addr_of!(content),
                1,
                self.clipboard_write.needs_confirm(),
            );
        }
        self.kitty_clipboard_write_status(
            &transaction.id,
            transaction.terminator,
            KittyClipboardStatus::Done,
        )
    }

    fn kitty_clipboard_write_error_active(&mut self, status: KittyClipboardStatus) -> bool {
        let Some(transaction) = self.kitty_clipboard_write.as_mut() else {
            return false;
        };
        transaction.failed = true;
        let id = transaction.id.clone();
        let terminator = transaction.terminator;
        self.kitty_clipboard_write_status(&id, terminator, status)
    }

    fn kitty_clipboard_write_status(
        &mut self,
        id: &[u8],
        terminator: osc::Terminator,
        status: KittyClipboardStatus,
    ) -> bool {
        self.kitty_clipboard_error(KittyClipboardOperation::Write, status, id, terminator)
    }

    fn kitty_clipboard_read(&mut self, event: KittyClipboard<'_>, id: Vec<u8>) -> bool {
        if event.loc() == Some(KittyClipboardLocation::Primary) {
            let Some(app) = app_from_handle(self.app) else {
                return false;
            };
            if !app.runtime.supports_selection_clipboard {
                return self.kitty_clipboard_error(
                    KittyClipboardOperation::Read,
                    KittyClipboardStatus::NotImplemented,
                    &id,
                    event.terminator,
                );
            }
        }

        match kitty_clipboard_read_payload(event.payload) {
            Some(KittyReadPayload::TextPlain) => {
                let clipboard = if event.loc() == Some(KittyClipboardLocation::Primary) {
                    ROASTTY_CLIPBOARD_SELECTION
                } else {
                    ROASTTY_CLIPBOARD_STANDARD
                };
                self.kitty_clipboard_start_read(clipboard, id, event.terminator)
            }
            Some(KittyReadPayload::AvailableTypes) => {
                let reply = kitty_clipboard_read_reply(&id, event.terminator, b"text/plain");
                self.queue_clipboard_reply(&reply)
            }
            None => self.kitty_clipboard_error(
                KittyClipboardOperation::Read,
                KittyClipboardStatus::NotImplemented,
                &id,
                event.terminator,
            ),
        }
    }

    fn kitty_clipboard_start_read(
        &mut self,
        clipboard: c_int,
        id: Vec<u8>,
        terminator: osc::Terminator,
    ) -> bool {
        if self.app.is_null() || self.termio_worker.is_none() {
            return false;
        }
        if self.clipboard_read.denied() {
            return self.kitty_clipboard_error(
                KittyClipboardOperation::Read,
                KittyClipboardStatus::Permission,
                &id,
                terminator,
            );
        }
        let Some(app) = app_from_handle(self.app) else {
            return false;
        };
        let Some(read_clipboard) = app.runtime.read_clipboard_cb else {
            return false;
        };

        let state = self.push_clipboard_request_with_kitty_metadata(
            ROASTTY_CLIPBOARD_REQUEST_KITTY_READ,
            clipboard,
            b'c',
            id,
            terminator,
        );
        let started = unsafe { read_clipboard(app.runtime.userdata, clipboard, state) };
        if !started {
            self.take_clipboard_request(state);
        }
        started
    }

    fn kitty_clipboard_error(
        &mut self,
        operation: KittyClipboardOperation,
        status: KittyClipboardStatus,
        id: &[u8],
        terminator: osc::Terminator,
    ) -> bool {
        let reply = kitty_clipboard_status_reply(operation, status, id, terminator);
        self.queue_clipboard_reply(&reply)
    }

    fn queue_clipboard_reply(&mut self, reply: &[u8]) -> bool {
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        if let Err(err) = worker.queue_write(reply) {
            self.apply_termio_event(termio::TermioWorkerEvent::Error(format!("{err:?}")));
            return false;
        }
        true
    }

    fn osc52_clipboard_read(&mut self, kind: u8, data: &[u8]) -> bool {
        if data != b"?" || self.app.is_null() || self.clipboard_read.denied() {
            return false;
        }
        let Some(app) = app_from_handle(self.app) else {
            return false;
        };
        let Some(read_clipboard) = app.runtime.read_clipboard_cb else {
            return false;
        };

        let reply_kind = osc52_reply_kind(kind);
        let state = self.push_clipboard_request(
            ROASTTY_CLIPBOARD_REQUEST_OSC_52_READ,
            ROASTTY_CLIPBOARD_STANDARD,
            reply_kind,
        );
        let started =
            unsafe { read_clipboard(app.runtime.userdata, ROASTTY_CLIPBOARD_STANDARD, state) };
        if !started {
            self.take_clipboard_request(state);
        }
        started
    }

    fn osc52_clipboard_write(&mut self, kind: u8, data: &[u8]) -> bool {
        if self.app.is_null() || self.clipboard_write.denied() {
            return false;
        }
        let Some(app) = app_from_handle(self.app) else {
            return false;
        };
        let Some(write_clipboard) = app.runtime.write_clipboard_cb else {
            return false;
        };
        let Some(clipboard) = osc52_write_clipboard(kind, app.runtime.supports_selection_clipboard)
        else {
            return false;
        };
        let Some(decoded) = osc52_decode_clipboard_write(data) else {
            return false;
        };
        let Ok(mime) = CString::new("text/plain") else {
            return false;
        };
        let Ok(text) = CString::new(decoded) else {
            return false;
        };
        let content = RoasttyClipboardContent {
            mime: mime.as_ptr(),
            data: text.as_ptr(),
        };
        unsafe {
            write_clipboard(
                app.runtime.userdata,
                clipboard,
                ptr::addr_of!(content),
                1,
                self.clipboard_write.needs_confirm(),
            );
        }
        true
    }

    fn push_clipboard_request(
        &mut self,
        request: c_int,
        clipboard: c_int,
        osc52_kind: u8,
    ) -> *mut c_void {
        self.push_clipboard_request_with_kitty_metadata(
            request,
            clipboard,
            osc52_kind,
            Vec::new(),
            osc::Terminator::St,
        )
    }

    fn push_clipboard_request_with_kitty_metadata(
        &mut self,
        request: c_int,
        clipboard: c_int,
        osc52_kind: u8,
        kitty_id: Vec<u8>,
        kitty_terminator: osc::Terminator,
    ) -> *mut c_void {
        let state = Box::new(ClipboardRequestState {
            request,
            clipboard,
            osc52_kind,
            kitty_id,
            kitty_terminator,
        });
        let state = NonNull::from(Box::leak(state));
        self.active_clipboard_requests.push(state);
        state.as_ptr().cast()
    }

    fn clipboard_request_index(&self, state: *mut c_void) -> Option<usize> {
        if state.is_null() {
            return None;
        }
        self.active_clipboard_requests
            .iter()
            .position(|request| request.as_ptr().cast::<c_void>() == state)
    }

    fn take_clipboard_request(&mut self, state: *mut c_void) -> Option<Box<ClipboardRequestState>> {
        let index = self.clipboard_request_index(state)?;
        let state = self.active_clipboard_requests.swap_remove(index);
        Some(unsafe { Box::from_raw(state.as_ptr()) })
    }

    fn clear_clipboard_requests(&mut self) {
        for state in self.active_clipboard_requests.drain(..) {
            drop(unsafe { Box::from_raw(state.as_ptr()) });
        }
    }

    fn increase_font_size(&mut self, delta: f32) -> bool {
        self.set_font_size_points((self.font_size_points + delta.clamp(0.0, 255.0)).min(255.0));
        self.font_size_adjusted = true;
        true
    }

    fn decrease_font_size(&mut self, delta: f32) -> bool {
        self.set_font_size_points((self.font_size_points - delta.clamp(0.0, 255.0)).max(1.0));
        self.font_size_adjusted = true;
        true
    }

    fn reset_font_size(&mut self) -> bool {
        self.set_font_size_points(self.original_font_size_points);
        self.font_size_adjusted = false;
        true
    }

    fn set_font_size(&mut self, points: f32) -> bool {
        self.set_font_size_points(points.clamp(1.0, 255.0));
        self.font_size_adjusted = true;
        true
    }

    fn set_font_size_points(&mut self, points: f32) {
        self.font_size_points = points;
        self.request_render();
    }

    fn scroll_viewport_to_top(&mut self) {
        if self.app.is_null() {
            return;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        worker.with_termio_mut(|termio| termio.terminal_mut().scroll_viewport_to_top());
        self.request_render();
    }

    fn scroll_viewport_to_bottom(&mut self) {
        if self.app.is_null() {
            return;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        worker.with_termio_mut(|termio| termio.terminal_mut().scroll_viewport_to_bottom());
        self.request_render();
    }

    fn scroll_viewport_to_row(&mut self, row: usize) {
        if self.app.is_null() {
            return;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        worker.with_termio_mut(|termio| termio.terminal_mut().scroll_viewport_to_row(row));
        self.request_render();
    }

    fn scroll_viewport_to_selection(&mut self) -> bool {
        if self.app.is_null() {
            return false;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        let scrolled =
            worker.with_termio_mut(|termio| termio.terminal_mut().scroll_viewport_to_selection());
        if scrolled {
            self.request_render();
        }
        scrolled
    }

    fn scroll_viewport_to_prompt(&mut self, delta: i16) -> bool {
        if self.app.is_null() {
            return false;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        worker.with_termio_mut(|termio| {
            termio
                .terminal_mut()
                .scroll_viewport_to_prompt(isize::from(delta))
        });
        self.request_render();
        true
    }

    fn scroll_viewport_page(&mut self, up: bool) {
        if self.app.is_null() {
            return;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        let rows = self.size.rows;
        if rows == 0 {
            return;
        }
        let delta = rows as isize;
        let delta = if up { -delta } else { delta };
        worker.with_termio_mut(|termio| {
            termio
                .terminal_mut()
                .scroll_selection_gesture_viewport(delta)
        });
        self.request_render();
    }

    fn scroll_viewport_lines(&mut self, lines: i16) {
        if self.app.is_null() {
            return;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        if lines == 0 {
            return;
        }
        worker.with_termio_mut(|termio| {
            termio
                .terminal_mut()
                .scroll_selection_gesture_viewport(isize::from(lines))
        });
        self.request_render();
    }

    fn scroll_viewport_fractional(&mut self, fraction: f32) {
        if self.app.is_null() {
            return;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        let rows = self.size.rows;
        if rows == 0 {
            return;
        }
        let delta = (f64::from(rows) * f64::from(fraction)).trunc();
        if delta == 0.0 {
            return;
        }
        if delta < isize::MIN as f64 || delta > isize::MAX as f64 {
            return;
        }
        worker.with_termio_mut(|termio| {
            termio
                .terminal_mut()
                .scroll_selection_gesture_viewport(delta as isize)
        });
        self.request_render();
    }

    fn set_preedit(&mut self, preedit: Option<&str>) {
        if self.selection_clear_on_typing && (self.preedit.is_some() || preedit.is_some()) {
            self.selection_clear_and_reset();
        }
        self.preedit = preedit.map(str::to_owned);
        self.request_render();
    }

    fn mouse_pos(&mut self, x: f64, y: f64, mods: c_int) {
        if self.app.is_null() {
            return;
        }
        self.mouse.mods = key_mods_from_raw(mods);
        self.mouse.position = if x.is_finite() && y.is_finite() {
            Some((x, y))
        } else {
            None
        };
        if self.mouse.position.is_some() {
            let reporting = self.mouse_report_context().is_some();
            let shift_override = reporting && self.mouse.mods.shift && !self.mouse_shift_capture();
            // Drag-extend selection (Issue 802 / Exp 25/28) when the left button is held + not
            // reporting, OR shift overrides reporting (Exp 33).
            if self.left_button_pressed() && (!reporting || shift_override) {
                self.selection_drag();
            }
            // Suppress the motion report only while a button is held under a shift override (Exp 33,
            // upstream `Surface.zig:4586-4607`) — bare shift-motion (mode 1003) must still report.
            let suppress = shift_override && self.any_mouse_button_pressed();
            if !suppress {
                self.dispatch_mouse_report(mouse::MouseAction::Motion, self.pressed_mouse_button());
            }
        }
    }

    fn mouse_button(&mut self, state: c_int, button: c_int, mods: c_int) -> bool {
        if self.app.is_null() {
            return false;
        }
        let Some(state) = mouse_button_state_from_int(state) else {
            return false;
        };
        let Some(button) = mouse_button_from_int(button) else {
            return false;
        };

        self.mouse.mods = key_mods_from_raw(mods);
        self.mouse.buttons[mouse_button_index(button)] = Some(state);
        let action = match state {
            SurfaceMouseButtonState::Release => mouse::MouseAction::Release,
            SurfaceMouseButtonState::Press => mouse::MouseAction::Press,
        };
        // Mouse-drag selection (Issue 802 / Exp 25): the core drives the gesture when not actually
        // mouse-reporting (faithful to upstream). Shift-while-reporting override is deferred.
        let reporting = self.mouse_report_context().is_some();
        // Shift overrides mouse-reporting for selection (Issue 802 / Exp 33, upstream
        // `Surface.zig:3882`): when reporting + shift + the terminal isn't shift-capturing, run the
        // selection (and suppress the report) instead of clearing.
        let shift_override = reporting && self.mouse.mods.shift && !self.mouse_shift_capture();
        if matches!(
            (button, state),
            (mouse::MouseButton::Left, SurfaceMouseButtonState::Release)
        ) && self.maybe_prompt_click()
        {
            return true;
        }
        if reporting && !shift_override {
            // Reporting (no override): clear+reset on ANY button + press/release (Exp 32).
            self.selection_clear_and_reset();
            return self.dispatch_mouse_report(action, Some(button));
        } else if matches!(button, mouse::MouseButton::Left) {
            // Not reporting, OR shift overrides reporting: run the selection.
            match state {
                SurfaceMouseButtonState::Press => {
                    if self.should_shift_extend() {
                        self.selection_drag(); // shift-click extends from the anchor
                    } else {
                        self.selection_press();
                    }
                }
                SurfaceMouseButtonState::Release => self.selection_release(),
            }
        }
        // On a shift override, suppress the report and report not-consumed (upstream returns false).
        if shift_override {
            false
        } else if matches!(
            (button, state),
            (mouse::MouseButton::Right, SurfaceMouseButtonState::Press)
        ) {
            self.right_click_action()
        } else if matches!(
            (button, state),
            (mouse::MouseButton::Middle, SurfaceMouseButtonState::Press)
        ) {
            self.middle_click_action()
        } else {
            self.dispatch_mouse_report(action, Some(button))
        }
    }

    fn right_click_action(&mut self) -> bool {
        match self.right_click_action {
            config::RightClickAction::Ignore => true,
            config::RightClickAction::Paste => {
                self.selection_clear_and_reset();
                let _ = self.paste_from_clipboard(ROASTTY_CLIPBOARD_STANDARD);
                true
            }
            config::RightClickAction::Copy => {
                let _ = self.copy_to_clipboard(CopyToClipboardFormat::Mixed);
                self.selection_clear_and_reset();
                true
            }
            config::RightClickAction::CopyOrPaste => {
                if self.has_active_selection() {
                    let _ = self.copy_to_clipboard(CopyToClipboardFormat::Mixed);
                    self.selection_clear_and_reset();
                } else {
                    let _ = self.paste_from_clipboard(ROASTTY_CLIPBOARD_STANDARD);
                }
                true
            }
            config::RightClickAction::ContextMenu => self.context_menu_action(),
        }
    }

    fn context_menu_action(&mut self) -> bool {
        let Some((x, y)) = self.mouse.position else {
            return false;
        };
        if !x.is_finite() || !y.is_finite() || x > f64::from(f32::MAX) || y > f64::from(f32::MAX) {
            return false;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        let boundary_codepoints = self.selection_word_boundaries().to_vec();
        let selected = worker.with_termio_mut(|termio| {
            let terminal = termio.terminal();
            let geometry = self.mouse_report_geometry(terminal)?;
            let pos = mouse_encode::Position {
                x: x as f32,
                y: y as f32,
            };
            if geometry.pos_out_of_viewport(pos) {
                return None;
            }
            let cell = geometry.pos_to_cell(pos);
            let selection = terminal.active_selection();
            if let Some(selection) = selection {
                if terminal
                    .selection_contains(selection, TerminalPointTag::Viewport, cell)
                    .ok()
                    .flatten()
                    .unwrap_or(false)
                {
                    return Some(false);
                }
            }
            let ref_ = terminal.grid_ref(TerminalPointTag::Viewport, cell)?;
            let selection = terminal
                .select_word(ref_, Some(&boundary_codepoints))
                .ok()??;
            termio.terminal_mut().set_selection(Some(selection)).ok()?;
            Some(true)
        });
        if selected == Some(true) {
            self.request_render();
        }
        false
    }

    fn has_active_selection(&self) -> bool {
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        worker.with_termio(|termio| termio.terminal().active_selection().is_some())
    }

    fn middle_click_action(&mut self) -> bool {
        match self.middle_click_action {
            config::MiddleClickAction::Ignore => false,
            config::MiddleClickAction::PrimaryPaste => {
                self.paste_from_clipboard(self.middle_click_clipboard())
            }
        }
    }

    fn middle_click_clipboard(&self) -> c_int {
        if self.copy_on_select == config::CopyOnSelect::Clipboard {
            return ROASTTY_CLIPBOARD_STANDARD;
        }
        let supports_selection = app_from_handle(self.app)
            .map(|app| app.runtime.supports_selection_clipboard)
            .unwrap_or(false);
        if supports_selection {
            ROASTTY_CLIPBOARD_SELECTION
        } else {
            ROASTTY_CLIPBOARD_STANDARD
        }
    }

    fn mouse_scroll(&mut self, x: f64, y: f64, scroll_mods: c_int) {
        if self.app.is_null() || !x.is_finite() || !y.is_finite() {
            return;
        }
        self.mouse.scroll = Some((x, y, scroll_mods as u8));
        let precision = scroll_mods as u8 & 1 != 0;
        let (cell_width, cell_height) = self.mouse_scroll_cell_size();
        let (x_steps, y_steps) = self.mouse_scroll_steps(x, y, precision, cell_width, cell_height);
        if x_steps == 0 && y_steps == 0 {
            return;
        }
        // Branch (2): the terminal is ACTUALLY mouse-reporting (a coarse `self.mouse_reporting`
        // flag is not enough — it defaults true; `mouse_report_context` also checks the terminal's
        // mouse-event mode) → button-4/5/6/7 reports.
        if self.mouse_report_context().is_some() {
            self.dispatch_scroll_reports(x_steps, y_steps);
            return;
        }
        // Not mouse-reporting (Issue 802 / Exp 23, porting upstream `scrollCallback`):
        // branch (1) alt-screen + alt-scroll → cursor keys; branch (3) → viewport scrollback.
        if self.readonly {
            return;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        let (alt_scroll, cursor_keys) = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            (
                terminal.is_alternate_screen() && terminal.mouse_alternate_scroll_enabled(),
                terminal.cursor_keys_enabled(),
            )
        });
        if alt_scroll {
            if y_steps == 0 {
                return;
            }
            // Branch (1): translate the wheel to cursor keys written to the PTY (the program,
            // e.g. a pager in the alt screen, scrolls). App-mode (`\x1bO…`) vs normal (`\x1b[…`).
            // Upstream clears the selection when sending wheel-as-cursor-keys.
            worker.with_termio_mut(|termio| {
                let _ = termio.terminal_mut().set_selection(None);
            });
            let seq = scroll_cursor_key_sequence(y_steps, cursor_keys);
            for _ in 0..y_steps.unsigned_abs() {
                if worker.queue_write(seq).is_err() {
                    break;
                }
            }
        } else {
            if y_steps == 0 {
                return;
            }
            // Branch (3): scroll the viewport (scrollback navigation). Viewport delta = -y_steps
            // (up/toward history is a negative row delta). This is a direct terminal mutation, so
            // mark dirty for the present driver to re-render.
            worker.with_termio_mut(|termio| {
                termio
                    .terminal_mut()
                    .scroll_viewport_delta_row(-(y_steps as isize));
            });
            self.dirty = true;
        }
    }

    fn mouse_scroll_cell_size(&self) -> (u32, u32) {
        if let Some(worker) = self.termio_worker.as_ref() {
            if let Some((width, height)) = worker.with_termio(|termio| {
                self.mouse_report_geometry(termio.terminal())
                    .map(|geometry| (geometry.cell.width, geometry.cell.height))
            }) {
                return (width.max(1), height.max(1));
            }
        }
        (
            self.size.cell_width_px.max(1),
            self.size.cell_height_px.max(1),
        )
    }

    fn mouse_scroll_steps(
        &mut self,
        x: f64,
        y: f64,
        precision: bool,
        cell_width: u32,
        cell_height: u32,
    ) -> (i64, i64) {
        let x_steps = if x == 0.0 {
            0
        } else if precision {
            scroll_steps(&mut self.mouse.pending_scroll_x, x, f64::from(cell_width))
        } else {
            x.round() as i64
        };

        let y_steps = if y == 0.0 {
            0
        } else {
            let cell_height = f64::from(cell_height.max(1));
            let y_adjusted = if precision {
                y * self.mouse_scroll_multiplier.precision
            } else {
                let y = if cfg!(target_os = "macos") {
                    if y > 0.0 {
                        y.max(1.0)
                    } else {
                        y.min(-1.0)
                    }
                } else {
                    y
                };
                y * cell_height * self.mouse_scroll_multiplier.discrete
            };
            scroll_steps(&mut self.mouse.pending_scroll_y, y_adjusted, cell_height)
        };

        (x_steps, y_steps)
    }

    fn mouse_pressure(&mut self, stage: u32, pressure: f64) {
        if self.app.is_null() || stage > 2 || !pressure.is_finite() {
            return;
        }
        self.mouse.pressure_stage = stage;
        self.mouse.pressure = pressure;
    }

    // --- Mouse-drag text selection (Issue 802 / Exp 25) ---
    // Faithful to upstream `Surface.zig`'s core selection: the renamed app forwards raw mouse
    // events, so `mouse_button`/`mouse_pos` drive an owned `SelectionGesture`. Anchors in VIEWPORT
    // space (so a drag over scrollback selects the visible history rows).

    /// Map the current mouse pixel position to a viewport cell, or `None` if outside the grid.
    fn position_to_cell(
        &self,
        terminal: &InnerTerminal,
        x: f64,
        y: f64,
    ) -> Option<point::Coordinate> {
        let geometry = self.mouse_report_geometry(terminal)?;
        let pos = mouse_encode::Position {
            x: x as f32,
            y: y as f32,
        };
        if geometry.pos_out_of_viewport(pos) {
            return None;
        }
        Some(geometry.pos_to_cell(pos))
    }

    /// Like [`Self::position_to_cell`] but clamps to the grid edge instead of returning `None` past
    /// the viewport edge (Issue 802 / Exp 28). A drag past the edge must still resolve to the edge
    /// cell so the gesture can set the autoscroll direction.
    fn position_to_cell_clamped(
        &self,
        terminal: &InnerTerminal,
        x: f64,
        y: f64,
    ) -> Option<point::Coordinate> {
        let geometry = self.mouse_report_geometry(terminal)?;
        Some(geometry.pos_to_cell(mouse_encode::Position {
            x: x as f32,
            y: y as f32,
        }))
    }

    /// Geometry the drag gesture needs (cell width / padding / screen height for x-mapping + edge
    /// autoscroll detection).
    fn selection_geometry(&self, terminal: &InnerTerminal) -> Option<SelectionGestureGeometry> {
        let geometry = self.mouse_report_geometry(terminal)?;
        Some(SelectionGestureGeometry {
            columns: u32::from(terminal.columns()).max(1),
            cell_width: geometry.cell.width,
            padding_left: geometry.padding.left,
            screen_height: geometry.screen.height,
        })
    }

    fn left_button_pressed(&self) -> bool {
        matches!(
            self.mouse.buttons[mouse_button_index(mouse::MouseButton::Left)],
            Some(SurfaceMouseButtonState::Press)
        )
    }

    /// Whether shift is captured by the program (so it does NOT override mouse-reporting for
    /// selection) — Issue 802 / Exp 33, upstream `mouseShiftCapture`. Flag-first: the terminal's
    /// `XTSHIFTESCAPE` flag (`CSI > 1 s`) decides; absent it, the default config (`.false`) → not
    /// captured (shift overrides). The config `Never`/`Always`/`True` is deferred (the App doesn't
    /// surface `mouse_shift_capture`).
    fn mouse_shift_capture(&self) -> bool {
        // Full upstream `mouseShiftCapture` (Issue 802 / Exp 34): config `Never`/`Always` decide
        // outright; otherwise the terminal's `XTSHIFTESCAPE` flag, else the config default — via the
        // shared, tested `MouseShiftCapture::capture_shift`.
        let config = app_from_handle(self.app)
            .map(|app| app.mouse_shift_capture)
            .unwrap_or(config::MouseShiftCapture::False);
        let flag = self.termio_worker.as_ref().and_then(|worker| {
            worker.with_termio(|termio| termio.terminal().mouse_shift_capture_flag())
        });
        config.capture_shift(flag)
    }

    /// Whether a left-press should EXTEND the existing selection (shift-click) rather than start a
    /// new one (Issue 802 / Exp 30, upstream `Surface.zig:3763-3797`): shift held + an in-progress
    /// gesture + an active selection + the click is not within the 500ms multi-click interval (else
    /// it's a double/triple-click increment). The `!shift_capture` clause is implicit (not modeled;
    /// faithful for the default config in the non-reporting branch this runs in).
    fn should_shift_extend(&self) -> bool {
        if !self.mouse.mods.shift || self.selection_gesture.click_count() == 0 {
            return false;
        }
        let Some(last) = self.selection_gesture.click_time_ns() else {
            return false;
        };
        if self.selection_time_ns().saturating_sub(last) <= self.click_repeat_interval_ns {
            return false;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };
        worker.with_termio(|termio| termio.terminal().active_selection().is_some())
    }

    /// Monotonic nanoseconds for click-repeat timing (Issue 802 / Exp 27). In tests a thread-local
    /// override makes the click-count deterministic (real wall-clock spacing between two FFI presses
    /// is load-dependent and can exceed the 500ms repeat interval under a parallel suite).
    fn selection_time_ns(&self) -> u64 {
        #[cfg(test)]
        {
            if let Some(ns) = SELECTION_TEST_CLOCK_NS.with(std::cell::Cell::get) {
                return ns;
            }
        }
        self.selection_click_epoch.elapsed().as_nanos() as u64
    }

    /// Left-press: begin a selection gesture at the cursor. A repeat click at the same cell within
    /// the interval advances the behavior (Cell → Word → Line) via the gesture's click count.
    fn selection_press(&mut self) {
        let Some((x, y)) = self.mouse.position else {
            return;
        };
        let time_ns = self.selection_time_ns();
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        let computed = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let cell = self.position_to_cell(terminal, x, y)?;
            let pin = terminal.viewport_pin(cell)?;
            let geometry = self.selection_geometry(terminal)?;
            Some((pin, f64::from(geometry.cell_width)))
        });
        let Some((pin, max_distance)) = computed else {
            return;
        };
        let word_boundary_codepoints = self.selection_word_chars.clone();
        worker.with_termio_mut(|termio| {
            let selection = self.selection_gesture.press(
                termio.terminal_mut(),
                SelectionGesturePress {
                    time_ns: Some(time_ns),
                    pin,
                    x,
                    y,
                    // Upstream `Surface.zig:3945-3952`: configured repeat interval, one-cell max distance.
                    max_distance,
                    repeat_interval_ns: self.click_repeat_interval_ns,
                    word_boundary_codepoints: Some(&word_boundary_codepoints),
                    behaviors: DEFAULT_BEHAVIORS,
                },
            );
            let _ = termio.terminal_mut().set_selection(selection);
        });
        self.dirty = true;
    }

    /// Drag (left held): extend the selection to the cursor.
    fn selection_drag(&mut self) {
        let Some((x, y)) = self.mouse.position else {
            return;
        };
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        let computed = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            // Clamp past-the-edge drags to the edge cell so a drag above/below the viewport sets the
            // autoscroll direction (Issue 802 / Exp 28).
            let cell = self.position_to_cell_clamped(terminal, x, y)?;
            let pin = terminal.viewport_pin(cell)?;
            let geometry = self.selection_geometry(terminal)?;
            Some((pin, geometry))
        });
        let Some((pin, geometry)) = computed else {
            return;
        };
        let word_boundary_codepoints = self.selection_word_chars.clone();
        worker.with_termio_mut(|termio| {
            let selection = self.selection_gesture.drag(
                termio.terminal_mut(),
                SelectionGestureDrag {
                    pin,
                    x,
                    y,
                    rectangle: false,
                    word_boundary_codepoints: Some(&word_boundary_codepoints),
                    geometry,
                },
            );
            let _ = termio.terminal_mut().set_selection(selection);
        });
        self.dirty = true;
    }

    /// Drive autoscroll while a drag is held past the top/bottom edge (Issue 802 / Exp 28): scroll
    /// one row toward the edge and extend the selection. No-op unless a left drag with an active
    /// `autoscroll` is in progress and we're not mouse-reporting. Called each present tick.
    fn selection_autoscroll_tick(&mut self) {
        if matches!(
            self.selection_gesture.autoscroll(),
            SelectionGestureAutoscroll::None
        ) {
            return;
        }
        if !self.left_button_pressed() || self.mouse_report_context().is_some() {
            return;
        }
        let Some((x, y)) = self.mouse.position else {
            return;
        };
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        // Clamped cell (the mouse is past the edge → `position_to_cell` would be `None`).
        let computed = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let cell = self.position_to_cell_clamped(terminal, x, y)?;
            let geometry = self.selection_geometry(terminal)?;
            Some((cell, geometry))
        });
        let Some((cell, geometry)) = computed else {
            return;
        };
        let word_boundary_codepoints = self.selection_word_chars.clone();
        worker.with_termio_mut(|termio| {
            let selection = self.selection_gesture.autoscroll_tick(
                termio.terminal_mut(),
                SelectionGestureAutoscrollTick {
                    viewport: cell,
                    x,
                    y,
                    rectangle: false,
                    word_boundary_codepoints: Some(&word_boundary_codepoints),
                    geometry,
                },
            );
            let _ = termio.terminal_mut().set_selection(selection);
        });
        self.dirty = true;
    }

    /// Left-release: end the gesture.
    fn selection_release(&mut self) {
        let Some((x, y)) = self.mouse.position else {
            return;
        };
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        let pin = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let cell = self.position_to_cell(terminal, x, y)?;
            terminal.viewport_pin(cell)
        });
        worker.with_termio_mut(|termio| {
            self.selection_gesture
                .release(termio.terminal_mut(), SelectionGestureRelease { pin });
        });
    }

    /// Reporting + non-shift press: clear any selection + reset the gesture (upstream), so a
    /// later report→no-report transition can't resume a stale selection.
    fn selection_clear_and_reset(&mut self) {
        let Some(worker) = self.termio_worker.as_ref() else {
            return;
        };
        worker.with_termio_mut(|termio| {
            let _ = termio.terminal_mut().set_selection(None);
            self.selection_gesture.reset(Some(termio.terminal_mut()));
        });
        self.dirty = true;
    }

    fn maybe_prompt_click(&mut self) -> bool {
        if !self.cursor_click_to_move || self.selection_gesture.dragged() {
            return false;
        }
        let Some((x, y)) = self.mouse.position else {
            return false;
        };
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };

        let action = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let viewport = self.position_to_cell(terminal, x, y)?;
            terminal.prompt_click_action(viewport)
        });
        let Some(PromptClickAction::Bytes(bytes)) = action else {
            return false;
        };
        if bytes.is_empty() {
            return true;
        }
        worker.queue_write(&bytes).is_ok()
    }

    fn dispatch_mouse_report(
        &mut self,
        action: mouse::MouseAction,
        button: Option<mouse::MouseButton>,
    ) -> bool {
        let Some((x, y)) = self.mouse.position else {
            return false;
        };
        if !self.mouse_reporting {
            return false;
        }
        if self.readonly {
            return false;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return false;
        };

        let Some((event_mode, format, geometry)) = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let event_mode = terminal.mouse_event_mode();
            if event_mode == mouse::MouseEventMode::None {
                return None;
            }
            let geometry = self.mouse_report_geometry(terminal)?;
            Some((event_mode, terminal.mouse_format(), geometry))
        }) else {
            return false;
        };

        let event = mouse_encode::Event {
            action,
            button,
            mods: mouse_mods_from_key_mods(self.mouse.mods),
            pos: mouse_encode::Position {
                x: x as f32,
                y: y as f32,
            },
        };
        let encoded = mouse_encode::encode(
            event,
            mouse_encode::Options {
                event: event_mode,
                format,
                geometry,
                any_button_pressed: self.any_mouse_button_pressed(),
                last_cell: Some(&mut self.mouse.last_reported_cell),
            },
        );
        let Some(encoded) = encoded.filter(|bytes| !bytes.is_empty()) else {
            return false;
        };

        if let Err(err) = worker.queue_write(&encoded) {
            self.apply_termio_event(termio::TermioWorkerEvent::Error(format!("{err:?}")));
            return false;
        }
        true
    }

    fn dispatch_scroll_reports(&mut self, x_steps: i64, y_steps: i64) {
        if self.mouse.position.is_none() {
            return;
        }
        let Some((_, _, _)) = self.mouse_report_context() else {
            return;
        };

        self.dispatch_scroll_axis(y_steps, mouse::MouseButton::Four, mouse::MouseButton::Five);
        self.dispatch_scroll_axis(x_steps, mouse::MouseButton::Six, mouse::MouseButton::Seven);
    }

    fn dispatch_scroll_axis(
        &mut self,
        steps: i64,
        positive_button: mouse::MouseButton,
        negative_button: mouse::MouseButton,
    ) {
        let button = match steps.cmp(&0) {
            std::cmp::Ordering::Greater => positive_button,
            std::cmp::Ordering::Less => negative_button,
            std::cmp::Ordering::Equal => return,
        };
        for _ in 0..steps.unsigned_abs() {
            if !self.dispatch_mouse_report(mouse::MouseAction::Press, Some(button)) {
                break;
            }
        }
    }

    fn mouse_report_context(
        &self,
    ) -> Option<(
        mouse::MouseEventMode,
        mouse::MouseFormat,
        mouse_encode::Geometry,
    )> {
        if !self.mouse_reporting || self.readonly {
            return None;
        }
        let worker = self.termio_worker.as_ref()?;
        worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let event_mode = terminal.mouse_event_mode();
            if event_mode == mouse::MouseEventMode::None {
                return None;
            }
            let geometry = self.mouse_report_geometry(terminal)?;
            Some((event_mode, terminal.mouse_format(), geometry))
        })
    }

    fn mouse_report_geometry(&self, terminal: &InnerTerminal) -> Option<mouse_encode::Geometry> {
        let screen_width = self.size.width_px;
        let screen_height = self.size.height_px;
        if screen_width == 0 || screen_height == 0 {
            return None;
        }

        let fallback_size = self.pty_size();
        let terminal_cols = u32::from(terminal.columns());
        let terminal_rows = terminal.rows();
        let cols = if terminal_cols == 0 {
            u32::from(fallback_size.cols).max(1)
        } else {
            terminal_cols
        };
        let rows = if terminal_rows == 0 {
            fallback_size.rows.max(1)
        } else {
            terminal_rows
        };
        let cell_width = if self.size.cell_width_px == 0 {
            screen_width / cols.max(1)
        } else {
            self.size.cell_width_px
        }
        .max(1);
        let cell_height = if self.size.cell_height_px == 0 {
            screen_height / u32::from(rows.max(1))
        } else {
            self.size.cell_height_px
        }
        .max(1);

        Some(mouse_encode::Geometry {
            screen: mouse_encode::PixelSize {
                width: screen_width,
                height: screen_height,
            },
            cell: mouse_encode::PixelSize {
                width: cell_width,
                height: cell_height,
            },
            padding: mouse_encode::Padding::default(),
        })
    }

    fn quicklook_word_text(&self) -> Result<RoasttyText, c_int> {
        if self.app.is_null() {
            return Err(ROASTTY_INVALID_VALUE);
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            return Err(ROASTTY_INVALID_VALUE);
        };
        let Some((x, y)) = self.mouse.position else {
            return Err(ROASTTY_INVALID_VALUE);
        };
        if !x.is_finite() || !y.is_finite() || x > f64::from(f32::MAX) || y > f64::from(f32::MAX) {
            return Err(ROASTTY_INVALID_VALUE);
        }

        let selection = worker.with_termio(|termio| {
            let terminal = termio.terminal();
            let geometry = self.mouse_report_geometry(terminal)?;
            let pos = mouse_encode::Position {
                x: x as f32,
                y: y as f32,
            };
            if geometry.pos_out_of_viewport(pos) {
                return None;
            }
            let cell = geometry.pos_to_cell(pos);
            let ref_ = terminal.grid_ref(TerminalPointTag::Viewport, cell)?;
            terminal
                .select_word(ref_, Some(self.selection_word_boundaries()))
                .ok()
                .flatten()
        });
        let Some(selection) = selection else {
            return Err(ROASTTY_INVALID_VALUE);
        };
        try_surface_selection_text(self, worker, Some(selection))
    }

    fn any_mouse_button_pressed(&self) -> bool {
        self.mouse
            .buttons
            .iter()
            .any(|state| matches!(state, Some(SurfaceMouseButtonState::Press)))
    }

    fn pressed_mouse_button(&self) -> Option<mouse::MouseButton> {
        self.mouse
            .buttons
            .iter()
            .position(|state| matches!(state, Some(SurfaceMouseButtonState::Press)))
            .and_then(mouse_button_from_index)
    }

    fn toggle_mouse_reporting(&mut self) -> bool {
        if self.app.is_null() {
            return false;
        }
        self.mouse_reporting = !self.mouse_reporting;
        true
    }

    fn toggle_readonly(&mut self) -> bool {
        if self.app.is_null() {
            return false;
        }
        self.readonly = !self.readonly;
        let mut storage = [0usize; 8];
        storage[0] = if self.readonly {
            ROASTTY_READONLY_ON
        } else {
            ROASTTY_READONLY_OFF
        } as usize;
        self.perform_action(ROASTTY_ACTION_READONLY, storage);
        true
    }

    fn default_binding_release_identity(event: &key::KeyEvent) -> DefaultBindingReleaseIdentity {
        DefaultBindingReleaseIdentity {
            key: event.key,
            mods: key_mods_to_raw(event.mods.binding()),
        }
    }

    fn consume_default_binding_release(&mut self, event: &key::KeyEvent) -> bool {
        if event.action != key::KeyAction::Release {
            return false;
        }
        if self
            .last_consumed_default_binding
            .is_some_and(|identity| identity == Self::default_binding_release_identity(event))
        {
            self.last_consumed_default_binding = None;
            return true;
        }
        false
    }

    fn dispatch_default_binding(&mut self, binding: DefaultBindingMatch) -> Option<bool> {
        let action = binding.action?;
        let parsed = parse_binding_action(self, action)?;
        let performed = perform_parsed_binding_action(self, parsed);
        if performed || binding.flags & ROASTTY_KEYBIND_FLAG_PERFORMABLE == 0 {
            self.last_consumed_default_binding = Some(binding.release_identity);
            return Some(true);
        }
        None
    }

    fn configured_exact_binding(&self, event: &key::KeyEvent) -> Option<ConfiguredBindingMatch> {
        if self.app.is_null() {
            return None;
        }
        app_from_handle(self.app)
            .and_then(|app| configured_key_event_exact_binding(&app.keybind_triggers, event))
    }

    fn configured_catch_all_binding(
        &self,
        event: &key::KeyEvent,
    ) -> Option<ConfiguredBindingMatch> {
        if self.app.is_null() {
            return None;
        }
        app_from_handle(self.app)
            .and_then(|app| configured_key_event_catch_all_binding(&app.keybind_triggers, event))
    }

    fn configured_table_entry(
        &self,
        table_name: &[u8],
        event: &key::KeyEvent,
    ) -> Option<ConfigKeybindSetEntry<'_>> {
        if self.app.is_null() {
            return None;
        }
        app_from_handle(self.app).and_then(|app| {
            let table = app
                .keybind_tables
                .iter()
                .find(|table| table.name == table_name)?;
            table.sequences.event_entry(event)
        })
    }

    fn configured_table_catch_all_entry(
        &self,
        table_name: &[u8],
        event: &key::KeyEvent,
    ) -> Option<ConfigKeybindSetEntry<'_>> {
        if self.app.is_null() {
            return None;
        }
        app_from_handle(self.app).and_then(|app| {
            let table = app
                .keybind_tables
                .iter()
                .find(|table| table.name == table_name)?;
            table.sequences.catch_all_entry(event)
        })
    }

    fn configured_active_table_entry(
        &self,
        event: &key::KeyEvent,
    ) -> Option<(usize, OwnedConfigKeybindSetEntry)> {
        for index in (0..self.active_key_tables.len()).rev() {
            let table = &self.active_key_tables[index];
            if let Some(entry) = self.configured_table_entry(&table.name, event) {
                return Some((index, entry.cloned()));
            }
        }
        None
    }

    fn configured_root_sequence_entry(
        &self,
        event: &key::KeyEvent,
    ) -> Option<ConfigKeybindSetEntry<'_>> {
        if self.app.is_null() {
            return None;
        }
        app_from_handle(self.app).and_then(|app| app.keybind_sequences.exact_entry(event))
    }

    fn configured_root_catch_all_entry(
        &self,
        event: &key::KeyEvent,
    ) -> Option<ConfigKeybindSetEntry<'_>> {
        if self.app.is_null() {
            return None;
        }
        app_from_handle(self.app).and_then(|app| app.keybind_sequences.catch_all_entry(event))
    }

    fn configured_entry_is_ignore(entry: ConfigKeybindSetEntry<'_>) -> bool {
        matches!(
            entry,
            ConfigKeybindSetEntry::Leaf(binding)
                if binding.actions.iter().any(|action| matches!(
                    parse_config_binding_action(action),
                    Some(ParsedBindingAction::Ignore)
                ))
        )
    }

    fn catch_all_is_ignore(&self, event: &key::KeyEvent) -> bool {
        for table in self.active_key_tables.iter().rev() {
            if let Some(entry) = self.configured_table_catch_all_entry(&table.name, event) {
                return Self::configured_entry_is_ignore(entry);
            }
        }
        self.configured_root_catch_all_entry(event)
            .map(Self::configured_entry_is_ignore)
            .unwrap_or(false)
    }

    fn key_sequence_storage(active: bool, trigger: RoasttyInputTrigger) -> [usize; 8] {
        let mut storage = [0usize; 8];
        storage[0] = usize::from(active);
        storage[1] = trigger.tag as usize;
        storage[2] = match trigger.tag {
            ROASTTY_TRIGGER_PHYSICAL => (unsafe { trigger.key.physical }) as usize,
            ROASTTY_TRIGGER_UNICODE | ROASTTY_TRIGGER_CATCH_ALL => {
                (unsafe { trigger.key.unicode }) as usize
            }
            _ => 0,
        };
        storage[3] = trigger.mods as usize;
        storage
    }

    fn notify_key_sequence(&self, active: bool, trigger: RoasttyInputTrigger) -> bool {
        self.perform_action_result(
            ROASTTY_ACTION_KEY_SEQUENCE,
            Self::key_sequence_storage(active, trigger),
        )
    }

    fn queue_key_sequence_event(&mut self, event: &key::KeyEvent) {
        let encoded = key_encode::encode(event, self.key_encode_options());
        if !encoded.is_empty() {
            self.queued_key_sequence.push(encoded);
        }
    }

    fn flush_queued_key_sequence(&mut self) {
        if self.queued_key_sequence.is_empty() || self.readonly {
            self.queued_key_sequence.clear();
            return;
        }

        let error = {
            let Some(worker) = self.termio_worker.as_ref() else {
                self.queued_key_sequence.clear();
                return;
            };
            let mut error = None;
            for encoded in &self.queued_key_sequence {
                if let Err(err) = worker.queue_write(encoded) {
                    error = Some(format!("{err:?}"));
                    break;
                }
            }
            error
        };

        self.queued_key_sequence.clear();
        if let Some(error) = error {
            self.apply_termio_event(termio::TermioWorkerEvent::Error(error));
        }
    }

    fn end_key_sequence(&mut self, flush: bool) {
        let was_active = self.active_key_sequence.take().is_some();
        if flush {
            self.flush_queued_key_sequence();
        } else {
            self.queued_key_sequence.clear();
        }
        if was_active {
            let _ = self.notify_key_sequence(false, empty_trigger());
        }
    }

    fn start_key_sequence(
        &mut self,
        set: &ConfigKeybindSet,
        trigger: RoasttyInputTrigger,
        event: &key::KeyEvent,
    ) -> bool {
        self.active_key_sequence = Some(set.clone());
        self.queue_key_sequence_event(event);
        let _ = self.notify_key_sequence(true, trigger);
        true
    }

    fn dispatch_sequence_leaf(
        &mut self,
        binding: ConfiguredBindingMatch,
    ) -> SurfaceKeySequenceResult {
        let consumed = self.dispatch_configured_binding(binding);
        match consumed {
            Some(true) => {
                self.end_key_sequence(false);
                SurfaceKeySequenceResult::Handled(true)
            }
            Some(false) => {
                self.end_key_sequence(true);
                SurfaceKeySequenceResult::Handled(false)
            }
            None => {
                self.end_key_sequence(true);
                SurfaceKeySequenceResult::EncodeCurrent
            }
        }
    }

    fn handle_active_key_sequence(
        &mut self,
        event: &key::KeyEvent,
    ) -> Option<SurfaceKeySequenceResult> {
        let set = self.active_key_sequence.clone()?;
        if event.action == key::KeyAction::Release {
            return Some(SurfaceKeySequenceResult::Handled(false));
        }

        match set.event_entry(event) {
            Some(ConfigKeybindSetEntry::Leader { trigger, set }) => Some(
                SurfaceKeySequenceResult::Handled(self.start_key_sequence(set, trigger, event)),
            ),
            Some(ConfigKeybindSetEntry::Leaf(binding)) => {
                Some(self.dispatch_sequence_leaf(binding))
            }
            None if key_is_modifier(event.key) => Some(SurfaceKeySequenceResult::Handled(
                self.write_encoded_key_event(event),
            )),
            None if self.catch_all_is_ignore(event) => {
                self.end_key_sequence(false);
                Some(SurfaceKeySequenceResult::Handled(true))
            }
            None => {
                self.end_key_sequence(true);
                Some(SurfaceKeySequenceResult::EncodeCurrent)
            }
        }
    }

    fn keybind_table_exists(&self, name: &[u8]) -> bool {
        if self.app.is_null() {
            return false;
        }
        app_from_handle(self.app)
            .map(|app| app.keybind_tables.iter().any(|table| table.name == name))
            .unwrap_or(false)
    }

    fn key_table_action_storage(tag: c_int, name: Option<&[u8]>) -> [usize; 8] {
        let mut storage = [0usize; 8];
        storage[0] = tag as usize;
        if let Some(name) = name {
            storage[1] = name.as_ptr() as usize;
            storage[2] = name.len();
        }
        storage
    }

    fn notify_key_table_action(&self, tag: c_int, name: Option<&[u8]>) -> bool {
        self.perform_action_result(
            ROASTTY_ACTION_KEY_TABLE,
            Self::key_table_action_storage(tag, name),
        )
    }

    fn activate_key_table(&mut self, name: &[u8], once: bool) -> bool {
        if !self.keybind_table_exists(name) {
            return false;
        }
        if self
            .active_key_tables
            .last()
            .is_some_and(|table| table.name == name)
        {
            return false;
        }
        if self.active_key_tables.len() >= MAX_ACTIVE_KEY_TABLES {
            return false;
        }
        self.active_key_tables.push(ActiveKeyTable {
            name: name.to_vec(),
            once,
        });
        let _ = self.notify_key_table_action(ROASTTY_KEY_TABLE_ACTIVATE, Some(name));
        true
    }

    fn deactivate_key_table(&mut self) -> bool {
        if self.active_key_tables.is_empty() {
            return false;
        }
        self.active_key_tables.pop();
        let _ = self.notify_key_table_action(ROASTTY_KEY_TABLE_DEACTIVATE, None);
        true
    }

    fn deactivate_all_key_tables(&mut self) -> bool {
        if self.active_key_tables.is_empty() {
            return false;
        }
        self.active_key_tables.clear();
        let _ = self.notify_key_table_action(ROASTTY_KEY_TABLE_DEACTIVATE_ALL, None);
        true
    }

    fn remapped_key_event(&self, event: &key::KeyEvent) -> key::KeyEvent {
        let mut event = event.clone();
        if self.key_remaps.is_remapped(event.mods) {
            event.mods = self.key_remaps.apply(event.mods);
        }
        event
    }

    fn dispatch_configured_binding(&mut self, binding: ConfiguredBindingMatch) -> Option<bool> {
        if binding.flags & (ROASTTY_KEYBIND_FLAG_GLOBAL | ROASTTY_KEYBIND_FLAG_ALL) != 0 {
            let app_handle = self.app;
            let current_surface = self as *mut Surface;
            let actions = binding
                .actions
                .iter()
                .map(|action| App::app_wide_configured_action(action))
                .collect::<Option<Vec<_>>>()?;
            for action in actions {
                match action {
                    AppKeyConfiguredAction::App(action) => {
                        let app = app_from_handle(app_handle)?;
                        let _ = app.perform_app_key_app_action(app_handle, action);
                    }
                    AppKeyConfiguredAction::Surface(action) => {
                        let live_surfaces = app_from_handle(app_handle)?
                            .surfaces
                            .iter()
                            .copied()
                            .filter(|surface| {
                                surface.as_ptr() == current_surface
                                    || unsafe { surface.as_ref().app == app_handle }
                            })
                            .collect::<Vec<_>>();
                        for mut surface in live_surfaces.iter().copied() {
                            if surface.as_ptr() == current_surface {
                                if let Some(parsed) = parse_binding_action(self, &action) {
                                    let _ = perform_parsed_binding_action(self, parsed);
                                }
                            } else {
                                let target = unsafe { surface.as_mut() };
                                if let Some(parsed) = parse_binding_action(target, &action) {
                                    let _ = perform_parsed_binding_action(target, parsed);
                                }
                            }
                        }
                    }
                }
            }
            self.last_consumed_default_binding = Some(binding.release_identity);
            return Some(true);
        }

        let mut ignores_input = false;
        let mut performed = false;
        for action in &binding.actions {
            let parsed = parse_binding_action(self, action)?;
            let is_ignore = matches!(parsed, ParsedBindingAction::Ignore);
            let action_performed = perform_parsed_binding_action(self, parsed);
            ignores_input |= is_ignore && action_performed;
            performed |= action_performed;
        }
        let consumed = binding.flags & ROASTTY_KEYBIND_FLAG_CONSUMED != 0;
        if ignores_input {
            self.last_consumed_default_binding = Some(binding.release_identity);
            return Some(true);
        }
        if binding.flags & ROASTTY_KEYBIND_FLAG_PERFORMABLE != 0 && !performed {
            return None;
        }
        if consumed {
            self.last_consumed_default_binding = Some(binding.release_identity);
            return Some(true);
        }
        None
    }

    fn key(&mut self, event: &KeyEvent) -> bool {
        if self.app.is_null() {
            return false;
        }
        let event = self.remapped_key_event(&event.event);
        self.last_key_event = Some(event.clone());
        if self.consume_default_binding_release(&event) {
            return true;
        }
        if let Some(result) = self.handle_active_key_sequence(&event) {
            return match result {
                SurfaceKeySequenceResult::Handled(consumed) => consumed,
                SurfaceKeySequenceResult::EncodeCurrent => {
                    if event.action != key::KeyAction::Release {
                        self.last_consumed_default_binding = None;
                    }
                    if self.vt_kam_allowed && self.terminal_kam_enabled() {
                        true
                    } else {
                        self.write_encoded_key_event(&event)
                    }
                }
            };
        }
        if let Some((table_index, entry)) = self.configured_active_table_entry(&event) {
            if table_index + 1 == self.active_key_tables.len()
                && self.active_key_tables[table_index].once
            {
                let _ = self.deactivate_key_table();
            }
            match entry {
                OwnedConfigKeybindSetEntry::Leader { trigger, set } => {
                    return self.start_key_sequence(&set, trigger, &event);
                }
                OwnedConfigKeybindSetEntry::Leaf(binding) => {
                    if let Some(consumed) = self.dispatch_configured_binding(binding) {
                        return consumed;
                    }
                }
            }
            if event.action != key::KeyAction::Release {
                self.last_consumed_default_binding = None;
            }
            if self.vt_kam_allowed && self.terminal_kam_enabled() {
                return true;
            }
            return self.write_encoded_key_event(&event);
        }
        if let Some(ConfigKeybindSetEntry::Leader { trigger, set }) =
            self.configured_root_sequence_entry(&event)
        {
            let set = set.clone();
            return self.start_key_sequence(&set, trigger, &event);
        }
        if let Some(binding) = self.configured_exact_binding(&event) {
            if let Some(consumed) = self.dispatch_configured_binding(binding) {
                return consumed;
            }
            if event.action != key::KeyAction::Release {
                self.last_consumed_default_binding = None;
            }
            if self.vt_kam_allowed && self.terminal_kam_enabled() {
                return true;
            }
            return self.write_encoded_key_event(&event);
        }
        if let Some(binding) = default_key_event_binding(&event) {
            if let Some(consumed) = self.dispatch_default_binding(binding) {
                return consumed;
            }
            if event.action != key::KeyAction::Release {
                self.last_consumed_default_binding = None;
            }
            if self.vt_kam_allowed && self.terminal_kam_enabled() {
                return true;
            }
            return self.write_encoded_key_event(&event);
        }
        if let Some(binding) = self.configured_catch_all_binding(&event) {
            if let Some(consumed) = self.dispatch_configured_binding(binding) {
                return consumed;
            }
            if event.action != key::KeyAction::Release {
                self.last_consumed_default_binding = None;
            }
            if self.vt_kam_allowed && self.terminal_kam_enabled() {
                return true;
            }
            return self.write_encoded_key_event(&event);
        }
        if event.action != key::KeyAction::Release {
            self.last_consumed_default_binding = None;
        }
        if self.vt_kam_allowed && self.terminal_kam_enabled() {
            return true;
        }
        self.write_encoded_key_event(&event)
    }

    fn terminal_kam_enabled(&self) -> bool {
        self.termio_worker
            .as_ref()
            .and_then(|worker| worker.with_termio(|termio| termio.terminal().mode_get(2, true)))
            .unwrap_or(false)
    }

    fn write_encoded_key_event(&mut self, event: &key::KeyEvent) -> bool {
        let encoded = key_encode::encode(event, self.key_encode_options());
        append_ui_key_trace(format!(
            "rust write_encoded_key_event encoded_len={} encoded_hex={} utf8_hex={} readonly={} has_worker={}",
            encoded.len(),
            trace_hex(&encoded),
            trace_hex(&event.utf8),
            self.readonly,
            self.termio_worker.is_some()
        ));
        if encoded.is_empty() {
            append_ui_key_trace("rust write_encoded_key_event result=false reason=empty-encoded");
            return false;
        }
        if self.readonly {
            append_ui_key_trace("rust write_encoded_key_event result=true reason=readonly");
            return true;
        }
        let Some(worker) = self.termio_worker.as_ref() else {
            append_ui_key_trace("rust write_encoded_key_event result=false reason=no-worker");
            return false;
        };
        if let Err(err) = worker.queue_write(&encoded) {
            append_ui_key_trace(format!(
                "rust write_encoded_key_event result=false reason=queue-write-error error={err:?}"
            ));
            self.apply_termio_event(termio::TermioWorkerEvent::Error(format!("{err:?}")));
            return false;
        }
        append_ui_key_trace("rust write_encoded_key_event result=true reason=queued");
        if event.key == key::Key::Escape
            || (self.selection_clear_on_typing && !key_is_modifier(event.key))
        {
            self.selection_clear_and_reset();
        }
        true
    }

    fn key_is_binding(&self, event: Option<&KeyEvent>, flags: *mut u8) -> bool {
        if !flags.is_null() {
            unsafe {
                flags.write(0);
            }
        }
        if self.app.is_null() || event.is_none() {
            return false;
        }
        let event = event.unwrap();
        let event = self.remapped_key_event(&event.event);
        let flags_value = if let Some(sequence) = self.active_key_sequence.as_ref() {
            match sequence.exact_entry(&event) {
                Some(ConfigKeybindSetEntry::Leader { .. }) => 0,
                Some(ConfigKeybindSetEntry::Leaf(binding)) => binding.flags,
                None => return false,
            }
        } else if let Some((_, entry)) = self.configured_active_table_entry(&event) {
            match entry {
                OwnedConfigKeybindSetEntry::Leader { .. } => 0,
                OwnedConfigKeybindSetEntry::Leaf(binding) => binding.flags,
            }
        } else if let Some(ConfigKeybindSetEntry::Leader { .. }) =
            self.configured_root_sequence_entry(&event)
        {
            0
        } else if let Some(binding) = app_from_handle(self.app)
            .and_then(|app| configured_key_event_exact_binding(&app.keybind_triggers, &event))
        {
            binding.flags
        } else if let Some(flags) = default_key_event_binding_flags(&event) {
            flags
        } else if let Some(binding) = app_from_handle(self.app)
            .and_then(|app| configured_key_event_catch_all_binding(&app.keybind_triggers, &event))
        {
            binding.flags
        } else {
            return false;
        };
        if !flags.is_null() {
            unsafe {
                flags.write(flags_value);
            }
        }
        true
    }

    fn key_encode_options(&self) -> key_encode::Options {
        self.termio_worker
            .as_ref()
            .map(|worker| worker.with_termio(|termio| termio.terminal().key_encode_options()))
            .unwrap_or_default()
    }

    fn tick_termio(&mut self) {
        #[cfg(test)]
        while let Some(event) = self.test_termio_events.pop_front() {
            self.apply_termio_event(event);
        }

        let mut events = Vec::new();
        if let Some(worker) = &self.termio_worker {
            while let Some(event) = worker.try_recv_event() {
                events.push(event);
            }
        }

        if !events.is_empty() {
            append_ui_key_trace(format!(
                "rust surface_drain_termio_events count={}",
                events.len()
            ));
        }

        for event in events {
            self.apply_termio_event(event);
        }
    }

    fn apply_termio_event(&mut self, event: termio::TermioWorkerEvent) {
        match event {
            termio::TermioWorkerEvent::Pump(pump) => {
                append_ui_key_trace(format!(
                    "rust surface_apply_termio_event pump bytes_read={} bytes_written={} pending_write={} eof={} child_exited={}",
                    pump.bytes_read,
                    pump.bytes_written,
                    pump.pending_write_bytes,
                    pump.eof,
                    pump.child_exited
                ));
                if pump.bytes_read > 0 {
                    self.reset_cursor_blink_for_output(std::time::Instant::now());
                }
                if pump.bytes_read > 0
                    || pump.bytes_written > 0
                    || pump.pending_write_bytes > 0
                    || pump.eof
                    || pump.child_exited
                {
                    self.dirty = true;
                }
                if pump.eof || pump.child_exited {
                    self.process_exited = true;
                }
            }
            termio::TermioWorkerEvent::Error(err) => {
                append_ui_key_trace(format!("rust surface_apply_termio_event error={err}"));
                self.last_termio_error = Some(err);
                self.process_exited = true;
                self.dirty = true;
            }
            termio::TermioWorkerEvent::Clipboard(event) => {
                append_ui_key_trace("rust surface_apply_termio_event clipboard");
                self.handle_terminal_clipboard_event(event);
            }
        }
    }
}

