fn scroll_steps(pending: &mut f64, offset: f64, unit: f64) -> i64 {
    let unit = unit.max(1.0);
    let total = *pending + offset;
    if total.abs() < unit {
        *pending = total;
        return 0;
    }

    let steps = (total / unit).trunc() as i64;
    *pending = total - (steps as f64 * unit);
    steps
}

