fn default_config_action_alias(action: &[u8]) -> &[u8] {
    match action {
        b"close_tab" => b"close_tab:this".as_slice(),
        b"copy_to_clipboard" => b"copy_to_clipboard:mixed".as_slice(),
        _ => action,
    }
}

#[cfg(test)]
fn default_config_trigger(action: &[u8]) -> RoasttyInputTrigger {
    let action = default_config_action_alias(action);
    DEFAULT_BINDINGS
        .iter()
        .rev()
        .find(|entry| entry.action == action && entry.flags & ROASTTY_KEYBIND_FLAG_PERFORMABLE == 0)
        .map(default_binding_entry_trigger)
        .unwrap_or_else(empty_trigger)
}

fn default_binding_entry_trigger(entry: &DefaultBindingEntry) -> RoasttyInputTrigger {
    match entry.trigger {
        DefaultBindingTrigger::Physical(key) => physical_trigger(key, entry.mods),
        DefaultBindingTrigger::Unicode(codepoint) => unicode_trigger(codepoint, entry.mods),
    }
}

fn default_binding_entry_matches_event(
    entry: &DefaultBindingEntry,
    event: &key::KeyEvent,
    mods: c_int,
) -> bool {
    if entry.mods != mods {
        return false;
    }
    match entry.trigger {
        DefaultBindingTrigger::Physical(key) => event.key == key,
        DefaultBindingTrigger::Unicode(codepoint) => {
            if let Ok(text) = std::str::from_utf8(&event.utf8) {
                let mut chars = text.chars();
                if let Some(ch) = chars.next() {
                    if chars.next().is_none() && ch as u32 == codepoint {
                        return true;
                    }
                }
            }

            event.unshifted_codepoint > 0 && event.unshifted_codepoint == codepoint
        }
    }
}

fn default_binding_match(
    flags: u8,
    action: Option<&'static [u8]>,
    key: key::Key,
    mods: c_int,
) -> DefaultBindingMatch {
    DefaultBindingMatch {
        flags,
        action,
        release_identity: DefaultBindingReleaseIdentity { key, mods },
    }
}

fn default_key_event_binding(event: &key::KeyEvent) -> Option<DefaultBindingMatch> {
    if event.action == key::KeyAction::Release {
        return None;
    }

    let release_key = event.key;
    let release_mods = key_mods_to_raw(event.mods.binding());
    DEFAULT_BINDINGS
        .iter()
        .find(|entry| default_binding_entry_matches_event(entry, event, release_mods))
        .map(|entry| {
            default_binding_match(entry.flags, Some(entry.action), release_key, release_mods)
        })
}

fn config_trigger_matches_candidate(
    trigger: RoasttyInputTrigger,
    candidate: RoasttyInputTrigger,
) -> bool {
    if trigger.tag != candidate.tag || trigger.mods != candidate.mods {
        return false;
    }

    match trigger.tag {
        ROASTTY_TRIGGER_PHYSICAL => {
            (unsafe { trigger.key.physical }) == (unsafe { candidate.key.physical })
        }
        ROASTTY_TRIGGER_UNICODE => {
            (unsafe { trigger.key.unicode }) == (unsafe { candidate.key.unicode })
        }
        ROASTTY_TRIGGER_CATCH_ALL => true,
        _ => false,
    }
}

fn configured_key_event_candidate_binding(
    bindings: &[ConfigKeybind],
    event: &key::KeyEvent,
    candidate: RoasttyInputTrigger,
) -> Option<ConfiguredBindingMatch> {
    let release_identity = Surface::default_binding_release_identity(event);
    bindings
        .iter()
        .rev()
        .find(|binding| config_trigger_matches_candidate(binding.trigger, candidate))
        .map(|binding| ConfiguredBindingMatch {
            actions: binding.actions.clone(),
            flags: binding.flags,
            release_identity,
        })
}

fn configured_key_event_exact_binding(
    bindings: &[ConfigKeybind],
    event: &key::KeyEvent,
) -> Option<ConfiguredBindingMatch> {
    if event.action == key::KeyAction::Release {
        return None;
    }

    let mods = key_mods_to_raw(event.mods.binding());
    if let Some(binding) =
        configured_key_event_candidate_binding(bindings, event, physical_trigger(event.key, mods))
    {
        return Some(binding);
    }

    if let Ok(text) = std::str::from_utf8(&event.utf8) {
        let mut chars = text.chars();
        if let Some(ch) = chars.next() {
            if chars.next().is_none() {
                if let Some(binding) = configured_key_event_candidate_binding(
                    bindings,
                    event,
                    unicode_trigger(ch as u32, mods),
                ) {
                    return Some(binding);
                }
            }
        }
    }

    if event.unshifted_codepoint > 0 {
        if let Some(binding) = configured_key_event_candidate_binding(
            bindings,
            event,
            unicode_trigger(event.unshifted_codepoint, mods),
        ) {
            return Some(binding);
        }
    }

    None
}

fn configured_key_event_catch_all_binding(
    bindings: &[ConfigKeybind],
    event: &key::KeyEvent,
) -> Option<ConfiguredBindingMatch> {
    if event.action == key::KeyAction::Release {
        return None;
    }

    let mods = key_mods_to_raw(event.mods.binding());
    if let Some(binding) =
        configured_key_event_candidate_binding(bindings, event, catch_all_trigger(mods))
    {
        return Some(binding);
    }

    if mods != ROASTTY_MODS_NONE {
        return configured_key_event_candidate_binding(
            bindings,
            event,
            catch_all_trigger(ROASTTY_MODS_NONE),
        );
    }

    None
}

fn configured_key_event_binding(
    bindings: &[ConfigKeybind],
    event: &key::KeyEvent,
) -> Option<ConfiguredBindingMatch> {
    configured_key_event_exact_binding(bindings, event)
        .or_else(|| configured_key_event_catch_all_binding(bindings, event))
}

fn default_key_event_binding_flags(event: &key::KeyEvent) -> Option<u8> {
    default_key_event_binding(event).map(|binding| binding.flags)
}

fn empty_text() -> RoasttyText {
    RoasttyText {
        tl_px_x: -1.0,
        tl_px_y: -1.0,
        offset_start: 0,
        offset_len: 0,
        text: ptr::null(),
        text_len: 0,
    }
}

fn write_empty_text(out: *mut RoasttyText) {
    if !out.is_null() {
        unsafe {
            out.write(empty_text());
        }
    }
}

fn try_allocated_text(bytes: &[u8]) -> Result<RoasttyText, c_int> {
    let len = bytes.len();
    let alloc_len = len.checked_add(1).ok_or(ROASTTY_OUT_OF_MEMORY)?;
    let layout = Layout::array::<u8>(alloc_len).map_err(|_| ROASTTY_OUT_OF_MEMORY)?;
    let ptr = unsafe { alloc::alloc(layout) };
    if ptr.is_null() {
        return Err(ROASTTY_OUT_OF_MEMORY);
    }
    if len > 0 {
        unsafe {
            ptr::copy_nonoverlapping(bytes.as_ptr(), ptr, len);
        }
    }
    unsafe {
        ptr.add(len).write(0);
    }

    Ok(RoasttyText {
        text: ptr.cast::<c_char>(),
        text_len: len,
        ..empty_text()
    })
}

fn viewport_text_offset(coord: point::Coordinate, columns: u16) -> u32 {
    u32::from(coord.y)
        .saturating_mul(u32::from(columns))
        .saturating_add(u32::from(coord.x))
}

fn free_text_allocation(value: *mut RoasttyText) {
    if value.is_null() {
        return;
    }
    let text = unsafe { (*value).text };
    let text_len = unsafe { (*value).text_len };
    if !text.is_null() {
        if let Some(alloc_len) = text_len.checked_add(1) {
            if let Ok(layout) = Layout::array::<u8>(alloc_len) {
                unsafe {
                    alloc::dealloc(text.cast::<u8>().cast_mut(), layout);
                }
            }
        }
    }
    write_empty_text(value);
}

fn try_surface_selection_text(
    surface: &Surface,
    worker: &termio::TermioWorker,
    selection: Option<TerminalSelection>,
) -> Result<RoasttyText, c_int> {
    let (text, metadata) = worker.with_termio(|termio| {
        let terminal = termio.terminal();
        let metadata_selection = selection.or_else(|| terminal.active_selection());
        let metadata = metadata_selection
            .map(|selection| surface.selection_text_metadata(terminal, selection))
            .unwrap_or_else(empty_text);
        (
            terminal.selection_format(TerminalSelectionFormat::Plain, true, false, selection),
            metadata,
        )
    });
    let Ok(text) = text else {
        return Err(ROASTTY_INVALID_VALUE);
    };
    let mut text = try_allocated_text(text.as_bytes())?;
    text.tl_px_x = metadata.tl_px_x;
    text.tl_px_y = metadata.tl_px_y;
    text.offset_start = metadata.offset_start;
    text.offset_len = metadata.offset_len;
    Ok(text)
}

/// Resolve an embedded selection and read its text under a SINGLE `with_termio` lock hold,
/// so the resolved `TerminalSelection` (raw page-node refs) never outlives the lock (Issue
/// 802 / Exp 11). Mirrors upstream's single-mutex `read_text`.
fn try_surface_embedded_selection_text(
    surface: &Surface,
    worker: &termio::TermioWorker,
    start: (TerminalPointTag, EmbeddedPointCoord, point::Coordinate),
    end: (TerminalPointTag, EmbeddedPointCoord, point::Coordinate),
    rectangle: bool,
) -> Result<RoasttyText, c_int> {
    let resolved = worker.with_termio(|termio| {
        let terminal = termio.terminal();
        let selection = terminal.resolve_embedded_selection(start, end, rectangle)?;
        let metadata = surface.selection_text_metadata(terminal, selection);
        let text =
            terminal.selection_format(TerminalSelectionFormat::Plain, true, false, Some(selection));
        Some((text, metadata))
    });
    let Some((text, metadata)) = resolved else {
        return Err(ROASTTY_INVALID_VALUE);
    };
    let Ok(text) = text else {
        return Err(ROASTTY_INVALID_VALUE);
    };
    let mut text = try_allocated_text(text.as_bytes())?;
    text.tl_px_x = metadata.tl_px_x;
    text.tl_px_y = metadata.tl_px_y;
    text.offset_start = metadata.offset_start;
    text.offset_len = metadata.offset_len;
    Ok(text)
}

fn try_allocated_string(bytes: &[u8]) -> Result<RoasttyString, c_int> {
    if bytes.is_empty() {
        return Ok(empty_string());
    }

    let mut owned = Vec::new();
    owned
        .try_reserve_exact(bytes.len())
        .map_err(|_| ROASTTY_OUT_OF_MEMORY)?;
    owned.extend_from_slice(bytes);
    let len = owned.len();
    let ptr = Box::into_raw(owned.into_boxed_slice()).cast::<u8>();
    Ok(RoasttyString {
        ptr: ptr.cast::<c_char>(),
        len,
        sentinel: false,
    })
}

fn write_copied_string(out: *mut RoasttyString, bytes: &[u8]) -> c_int {
    if out.is_null() {
        return ROASTTY_INVALID_VALUE;
    }

    write_empty_string(out);
    match try_allocated_string(bytes) {
        Ok(value) => {
            unsafe {
                out.write(value);
            }
            ROASTTY_SUCCESS
        }
        Err(error) => error,
    }
}

fn terminal_data_selector_is_valid(data: c_int) -> bool {
    data != ROASTTY_TERMINAL_DATA_INVALID
        && matches!(
            data,
            ROASTTY_TERMINAL_DATA_COLS..=ROASTTY_TERMINAL_DATA_VIEWPORT_ACTIVE
        )
}

fn mode_tag_parts(tag: u16) -> (u16, bool) {
    (
        tag & ROASTTY_MODE_TAG_VALUE_MASK,
        tag & ROASTTY_MODE_TAG_ANSI_BIT != 0,
    )
}

fn staged_terminal_string(value: *const c_void) -> Result<Option<String>, c_int> {
    if value.is_null() {
        return Ok(None);
    }

    let value = unsafe { value.cast::<RoasttyString>().read() };
    if value.ptr.is_null() {
        return if value.len == 0 {
            Ok(Some(String::new()))
        } else {
            Err(ROASTTY_INVALID_VALUE)
        };
    }

    let bytes = unsafe { slice::from_raw_parts(value.ptr.cast::<u8>(), value.len) };
    let text = std::str::from_utf8(bytes).map_err(|_| ROASTTY_INVALID_VALUE)?;
    let mut owned = String::new();
    owned
        .try_reserve_exact(text.len())
        .map_err(|_| ROASTTY_OUT_OF_MEMORY)?;
    owned.push_str(text);
    Ok(Some(owned))
}

fn staged_terminal_pwd(value: *const c_void) -> Result<Option<String>, c_int> {
    let Some(text) = staged_terminal_string(value)? else {
        return Ok(None);
    };
    if text.is_empty() {
        return Ok(Some(text));
    }

    let mut stored = String::new();
    stored
        .try_reserve_exact(text.len() + 1)
        .map_err(|_| ROASTTY_OUT_OF_MEMORY)?;
    stored.push_str(&text);
    stored.push('\0');
    Ok(Some(stored))
}

fn read_rgb(value: *const c_void) -> Option<(u8, u8, u8)> {
    if value.is_null() {
        return None;
    }
    let rgb = unsafe { value.cast::<RoasttyRgb>().read() };
    Some((rgb.r, rgb.g, rgb.b))
}

fn read_palette(value: *const c_void) -> Option<[(u8, u8, u8); 256]> {
    if value.is_null() {
        return None;
    }
    let palette = unsafe { value.cast::<RoasttyPalette>().read() };
    Some(palette_to_tuples(palette))
}

fn read_optional_u64(value: *const c_void) -> Option<u64> {
    if value.is_null() {
        return None;
    }
    Some(unsafe { value.cast::<u64>().read() })
}

fn read_optional_usize(value: *const c_void) -> Option<usize> {
    if value.is_null() {
        return None;
    }
    Some(unsafe { value.cast::<usize>().read() })
}

fn read_optional_bool(value: *const c_void) -> Option<bool> {
    if value.is_null() {
        return None;
    }
    Some(unsafe { value.cast::<bool>().read() })
}

fn palette_to_tuples(palette: RoasttyPalette) -> [(u8, u8, u8); 256] {
    let mut result = [(0, 0, 0); 256];
    for (index, rgb) in palette.into_iter().enumerate() {
        result[index] = (rgb.r, rgb.g, rgb.b);
    }
    result
}

fn palette_from_tuples(palette: [(u8, u8, u8); 256]) -> RoasttyPalette {
    let mut result = [RoasttyRgb::default(); 256];
    for (index, rgb) in palette.into_iter().enumerate() {
        result[index] = RoasttyRgb {
            r: rgb.0,
            g: rgb.1,
            b: rgb.2,
        };
    }
    result
}

fn roastty_rgb(rgb: (u8, u8, u8)) -> RoasttyRgb {
    RoasttyRgb {
        r: rgb.0,
        g: rgb.1,
        b: rgb.2,
    }
}

fn palette_from_color(palette: color::Palette) -> RoasttyPalette {
    let mut result = [RoasttyRgb::default(); 256];
    for (index, rgb) in palette.into_iter().enumerate() {
        result[index] = RoasttyRgb {
            r: rgb.r,
            g: rgb.g,
            b: rgb.b,
        };
    }
    result
}

fn write_rgb(out: *mut c_void, rgb: (u8, u8, u8)) {
    unsafe {
        out.cast::<RoasttyRgb>().write(roastty_rgb(rgb));
    }
}

fn write_palette(out: *mut c_void, palette: [(u8, u8, u8); 256]) {
    unsafe {
        out.cast::<RoasttyPalette>()
            .write(palette_from_tuples(palette));
    }
}

fn render_state_default() -> RenderStateScalar {
    RenderStateScalar {
        cols: 0,
        rows: 0,
        display_id: 0,
        background: RoasttyRgb { r: 0, g: 0, b: 0 },
        foreground: RoasttyRgb {
            r: 0xff,
            g: 0xff,
            b: 0xff,
        },
        cursor: None,
        palette: palette_from_color(color::DEFAULT_PALETTE),
        dirty: ROASTTY_RENDER_STATE_DIRTY_FALSE,
        cursor_visual_style: ROASTTY_RENDER_STATE_CURSOR_VISUAL_STYLE_BLOCK,
        cursor_visible: true,
        cursor_blinking: false,
        cursor_password_input: false,
        cursor_viewport: None,
        rows_snapshot: Vec::new(),
        kitty_render_placements: Vec::new(),
    }
}

fn render_cursor_visual_style(value: cursor::VisualStyle) -> c_int {
    match value {
        cursor::VisualStyle::Bar => ROASTTY_RENDER_STATE_CURSOR_VISUAL_STYLE_BAR,
        cursor::VisualStyle::Block => ROASTTY_RENDER_STATE_CURSOR_VISUAL_STYLE_BLOCK,
        cursor::VisualStyle::Underline => ROASTTY_RENDER_STATE_CURSOR_VISUAL_STYLE_UNDERLINE,
        cursor::VisualStyle::BlockHollow => ROASTTY_RENDER_STATE_CURSOR_VISUAL_STYLE_BLOCK_HOLLOW,
    }
}

fn render_state_from_terminal(terminal: &InnerTerminal) -> RenderStateScalar {
    let background = terminal
        .color_effective(TerminalColorKind::Background)
        .map(roastty_rgb)
        .unwrap_or(RoasttyRgb { r: 0, g: 0, b: 0 });
    let foreground = terminal
        .color_effective(TerminalColorKind::Foreground)
        .map(roastty_rgb)
        .unwrap_or(RoasttyRgb {
            r: 0xff,
            g: 0xff,
            b: 0xff,
        });
    let cursor = terminal
        .color_effective(TerminalColorKind::Cursor)
        .map(roastty_rgb);
    // Issue 802 / Exp 24: viewport-aware cursor (None when scrolled into scrollback) so the cursor
    // block isn't drawn on a history row. The accessor already bounds x<cols and the row to the
    // viewport (0..rows).
    let cursor_viewport =
        terminal
            .cursor_viewport_position()
            .map(|(x, y)| RenderStateCursorViewport {
                x,
                y,
                wide_tail: false,
            });

    RenderStateScalar {
        cols: terminal.columns(),
        rows: terminal.rows(),
        display_id: 0,
        background,
        foreground,
        cursor,
        palette: palette_from_tuples(terminal.palette_current()),
        dirty: ROASTTY_RENDER_STATE_DIRTY_FULL,
        cursor_visual_style: render_cursor_visual_style(terminal.cursor_visual_style()),
        cursor_visible: terminal.cursor_visible(),
        cursor_blinking: terminal.cursor_blinking(),
        cursor_password_input: false,
        cursor_viewport,
        rows_snapshot: terminal
            .render_rows_snapshot()
            .into_iter()
            .map(|row| RenderStateRowSnapshot {
                raw: row.raw,
                dirty: row.dirty,
                selection: row.selection.map(|selection| RenderStateRowSelectionRange {
                    start_x: selection.start_x,
                    end_x: selection.end_x,
                }),
                cells: row
                    .cells
                    .into_iter()
                    .map(|cell| RenderStateCellSnapshot {
                        raw: cell.raw,
                        style: cell.style,
                        graphemes: cell.graphemes,
                    })
                    .collect(),
            })
            .collect(),
        kitty_render_placements: kitty_render_placement_snapshots(terminal),
    }
}

