#[no_mangle]
pub extern "C" fn roastty_render_state_colors_get(
    state: RoasttyRenderStateHandle,
    out: *mut RoasttyRenderStateColors,
) -> c_int {
    let Some(state) = render_state_from_handle(state) else {
        return ROASTTY_INVALID_VALUE;
    };
    if out.is_null() {
        return ROASTTY_INVALID_VALUE;
    }

    let out_size = unsafe { ptr::addr_of!((*out).size).read() };
    if out_size < std::mem::size_of::<usize>() {
        return ROASTTY_INVALID_VALUE;
    }

    unsafe {
        if out_size
            >= std::mem::offset_of!(RoasttyRenderStateColors, background)
                + std::mem::size_of::<RoasttyRgb>()
        {
            ptr::addr_of_mut!((*out).background).write(state.background);
        }
        if out_size
            >= std::mem::offset_of!(RoasttyRenderStateColors, foreground)
                + std::mem::size_of::<RoasttyRgb>()
        {
            ptr::addr_of_mut!((*out).foreground).write(state.foreground);
        }
        if let Some(cursor) = state.cursor {
            if out_size
                >= std::mem::offset_of!(RoasttyRenderStateColors, cursor)
                    + std::mem::size_of::<RoasttyRgb>()
            {
                ptr::addr_of_mut!((*out).cursor).write(cursor);
            }
        }
        if out_size
            >= std::mem::offset_of!(RoasttyRenderStateColors, cursor_has_value)
                + std::mem::size_of::<bool>()
        {
            ptr::addr_of_mut!((*out).cursor_has_value).write(state.cursor.is_some());
        }

        let palette_offset = std::mem::offset_of!(RoasttyRenderStateColors, palette);
        if out_size > palette_offset {
            let available = out_size - palette_offset;
            let entries = std::cmp::min(
                state.palette.len(),
                available / std::mem::size_of::<RoasttyRgb>(),
            );
            for index in 0..entries {
                ptr::addr_of_mut!((*out).palette)
                    .cast::<RoasttyRgb>()
                    .add(index)
                    .write(state.palette[index]);
            }
        }
    }

    ROASTTY_SUCCESS
}

#[no_mangle]
pub extern "C" fn roastty_init(argc: usize, argv: *mut *mut c_char) -> c_int {
    let mut copied = Vec::new();
    if !argv.is_null() {
        for index in 0..argc {
            let arg = unsafe { *argv.add(index) };
            if arg.is_null() {
                copied.clear();
                break;
            }
            copied.push(unsafe { CStr::from_ptr(arg) }.to_bytes().to_vec());
        }
    }
    *INIT_ARGV.lock().unwrap() = copied;
    crash::init();
    ROASTTY_SUCCESS
}

#[no_mangle]
pub extern "C" fn roastty_info() -> RoasttyInfo {
    RoasttyInfo {
        build_mode: ROASTTY_BUILD_MODE_DEBUG,
        version: VERSION.as_ptr().cast::<c_char>(),
        version_len: VERSION.len() - 1,
    }
}

#[no_mangle]
pub extern "C" fn roastty_translate(msgid: *const c_char) -> *const c_char {
    msgid
}

fn version_component(index: usize) -> usize {
    let version = std::str::from_utf8(&VERSION[..VERSION.len() - 1]).unwrap_or("");
    let core = version.split(['-', '+']).next().unwrap_or("");
    core.split('.')
        .nth(index)
        .and_then(|value| value.parse::<usize>().ok())
        .unwrap_or(0)
}

fn borrowed_string(bytes: &'static [u8]) -> RoasttyString {
    RoasttyString {
        ptr: bytes.as_ptr().cast::<c_char>(),
        len: bytes.len().saturating_sub(1),
        sentinel: false,
    }
}

fn current_optimize_mode() -> c_int {
    if cfg!(debug_assertions) {
        ROASTTY_OPTIMIZE_DEBUG
    } else {
        ROASTTY_OPTIMIZE_RELEASE_FAST
    }
}

#[no_mangle]
pub extern "C" fn roastty_build_info(data: c_int, out: *mut c_void) -> c_int {
    if out.is_null() {
        return ROASTTY_INVALID_VALUE;
    }

    unsafe {
        match data {
            ROASTTY_BUILD_INFO_INVALID => ROASTTY_INVALID_VALUE,
            ROASTTY_BUILD_INFO_SIMD => {
                out.cast::<bool>().write(simd_build_enabled());
                ROASTTY_SUCCESS
            }
            ROASTTY_BUILD_INFO_KITTY_GRAPHICS => {
                out.cast::<bool>().write(false);
                ROASTTY_SUCCESS
            }
            ROASTTY_BUILD_INFO_TMUX_CONTROL_MODE => {
                out.cast::<bool>().write(false);
                ROASTTY_SUCCESS
            }
            ROASTTY_BUILD_INFO_OPTIMIZE => {
                out.cast::<c_int>().write(current_optimize_mode());
                ROASTTY_SUCCESS
            }
            ROASTTY_BUILD_INFO_VERSION_STRING => {
                out.cast::<RoasttyString>().write(borrowed_string(VERSION));
                ROASTTY_SUCCESS
            }
            ROASTTY_BUILD_INFO_VERSION_MAJOR => {
                out.cast::<usize>().write(version_component(0));
                ROASTTY_SUCCESS
            }
            ROASTTY_BUILD_INFO_VERSION_MINOR => {
                out.cast::<usize>().write(version_component(1));
                ROASTTY_SUCCESS
            }
            ROASTTY_BUILD_INFO_VERSION_PATCH => {
                out.cast::<usize>().write(version_component(2));
                ROASTTY_SUCCESS
            }
            ROASTTY_BUILD_INFO_VERSION_PRE | ROASTTY_BUILD_INFO_VERSION_BUILD => {
                out.cast::<RoasttyString>()
                    .write(borrowed_string(EMPTY_STRING));
                ROASTTY_SUCCESS
            }
            _ => ROASTTY_INVALID_VALUE,
        }
    }
}

fn simd_build_enabled() -> bool {
    cfg!(any(
        target_arch = "aarch64",
        target_arch = "wasm32",
        target_arch = "x86_64"
    ))
}

fn keyboard_layout_to_abi(layout: input_keyboard::Layout) -> c_int {
    match layout {
        input_keyboard::Layout::Unknown => ROASTTY_KEYBOARD_LAYOUT_UNKNOWN,
        input_keyboard::Layout::UsStandard => ROASTTY_KEYBOARD_LAYOUT_US_STANDARD,
        input_keyboard::Layout::UsInternational => ROASTTY_KEYBOARD_LAYOUT_US_INTERNATIONAL,
    }
}

#[no_mangle]
pub extern "C" fn roastty_current_keyboard_layout() -> c_int {
    keyboard_layout_to_abi(input_keyboard::Layout::current())
}

#[no_mangle]
pub extern "C" fn roastty_alloc(allocator: *const RoasttyAllocator, len: usize) -> *mut u8 {
    if len == 0 {
        return ptr::null_mut();
    }

    if allocator.is_null() {
        let Ok(layout) = Layout::array::<u8>(len) else {
            return ptr::null_mut();
        };
        return unsafe { alloc::alloc(layout) };
    }

    let allocator = unsafe { &*allocator };
    if allocator.vtable.is_null() {
        return ptr::null_mut();
    }
    let vtable = unsafe { &*allocator.vtable };
    let Some(alloc_fn) = vtable.alloc else {
        return ptr::null_mut();
    };
    unsafe { alloc_fn(allocator.ctx, len, 1, 0) }
}

#[no_mangle]
pub extern "C" fn roastty_free(allocator: *const RoasttyAllocator, ptr: *mut u8, len: usize) {
    if ptr.is_null() || len == 0 {
        return;
    }

    if allocator.is_null() {
        let Ok(layout) = Layout::array::<u8>(len) else {
            return;
        };
        unsafe {
            alloc::dealloc(ptr, layout);
        }
        return;
    }

    let allocator = unsafe { &*allocator };
    if allocator.vtable.is_null() {
        return;
    }
    let vtable = unsafe { &*allocator.vtable };
    let Some(free_fn) = vtable.free else {
        return;
    };
    unsafe {
        free_fn(allocator.ctx, ptr.cast::<c_void>(), len, 1, 0);
    }
}

#[no_mangle]
pub extern "C" fn roastty_sys_set(option: c_int, value: *const c_void) -> c_int {
    let Ok(mut state) = SYS_STATE.lock() else {
        return ROASTTY_INVALID_VALUE;
    };
    match option {
        ROASTTY_SYS_OPT_USERDATA => {
            state.userdata = value as usize;
            ROASTTY_SUCCESS
        }
        ROASTTY_SYS_OPT_DECODE_PNG => {
            state.decode_png = if value.is_null() {
                None
            } else {
                Some(unsafe { std::mem::transmute::<*const c_void, SysDecodePngCallback>(value) })
            };
            ROASTTY_SUCCESS
        }
        ROASTTY_SYS_OPT_LOG => {
            state.log = if value.is_null() {
                None
            } else {
                Some(unsafe { std::mem::transmute::<*const c_void, SysLogCallback>(value) })
            };
            ROASTTY_SUCCESS
        }
        _ => ROASTTY_INVALID_VALUE,
    }
}

fn log_level_name(level: c_int) -> &'static str {
    match level {
        ROASTTY_SYS_LOG_LEVEL_ERROR => "error",
        ROASTTY_SYS_LOG_LEVEL_WARNING => "warning",
        ROASTTY_SYS_LOG_LEVEL_INFO => "info",
        ROASTTY_SYS_LOG_LEVEL_DEBUG => "debug",
        _ => "unknown",
    }
}

unsafe fn nullable_bytes<'a>(ptr: *const u8, len: usize) -> &'a [u8] {
    if ptr.is_null() || len == 0 {
        &[]
    } else {
        slice::from_raw_parts(ptr, len)
    }
}

#[no_mangle]
pub extern "C" fn roastty_sys_log_stderr(
    _userdata: *mut c_void,
    level: c_int,
    scope: *const u8,
    scope_len: usize,
    message: *const u8,
    message_len: usize,
) {
    let scope = unsafe { nullable_bytes(scope, scope_len) };
    let message = unsafe { nullable_bytes(message, message_len) };
    let level = log_level_name(level);
    let mut stderr = std::io::stderr().lock();
    if scope.is_empty() {
        let _ = writeln!(stderr, "[{level}]: {}", String::from_utf8_lossy(message));
    } else {
        let _ = writeln!(
            stderr,
            "[{level}]({}): {}",
            String::from_utf8_lossy(scope),
            String::from_utf8_lossy(message)
        );
    }
}

#[no_mangle]
pub extern "C" fn roastty_string_free(value: RoasttyString) {
    if value.ptr.is_null() || value.len == 0 {
        return;
    }

    unsafe {
        if value.sentinel {
            drop(CString::from_raw(value.ptr.cast_mut()));
        } else {
            let slice = ptr::slice_from_raw_parts_mut(value.ptr.cast::<u8>().cast_mut(), value.len);
            drop(Box::from_raw(slice));
        }
    }
}

#[no_mangle]
pub extern "C" fn roastty_size_report_encode(
    style: c_int,
    size: RoasttySizeReportSize,
    buf: *mut c_char,
    buf_len: usize,
    out_written: *mut usize,
) -> c_int {
    if out_written.is_null() {
        return ROASTTY_INVALID_VALUE;
    }

    let Some(style) = size_report::style_from_int(style) else {
        unsafe {
            out_written.write(0);
        }
        return ROASTTY_INVALID_VALUE;
    };

    let encoded = size_report::encode(
        style,
        size_report::Size {
            rows: size.rows,
            columns: size.columns,
            cell_width: size.cell_width,
            cell_height: size.cell_height,
        },
    );

    unsafe {
        out_written.write(encoded.len());
    }

    if buf.is_null() || buf_len < encoded.len() {
        return ROASTTY_OUT_OF_SPACE;
    }

    unsafe {
        ptr::copy_nonoverlapping(encoded.as_ptr(), buf.cast::<u8>(), encoded.len());
    }
    ROASTTY_SUCCESS
}

fn write_byte_segments(
    segments: &[&[u8]],
    out: *mut u8,
    out_len: usize,
    out_written: *mut usize,
) -> c_int {
    if out_written.is_null() {
        return ROASTTY_INVALID_VALUE;
    }

    let required = segments.iter().map(|segment| segment.len()).sum::<usize>();
    unsafe {
        out_written.write(required);
    }

    if (out.is_null() && required > 0) || out_len < required {
        return ROASTTY_OUT_OF_SPACE;
    }

    let mut offset = 0;
    for segment in segments {
        if !segment.is_empty() {
            unsafe {
                ptr::copy_nonoverlapping(segment.as_ptr(), out.add(offset), segment.len());
            }
        }
        offset += segment.len();
    }

    ROASTTY_SUCCESS
}

fn focus_event_from_raw(event: c_int) -> Option<focus::FocusEvent> {
    match event {
        ROASTTY_FOCUS_EVENT_GAINED => Some(focus::FocusEvent::Gained),
        ROASTTY_FOCUS_EVENT_LOST => Some(focus::FocusEvent::Lost),
        _ => None,
    }
}

#[no_mangle]
pub extern "C" fn roastty_focus_encode(
    event: c_int,
    out: *mut u8,
    out_len: usize,
    out_written: *mut usize,
) -> c_int {
    if out_written.is_null() {
        return ROASTTY_INVALID_VALUE;
    }
    let Some(event) = focus_event_from_raw(event) else {
        unsafe {
            out_written.write(0);
        }
        return ROASTTY_INVALID_VALUE;
    };
    write_byte_segments(&[focus::encode(event)], out, out_len, out_written)
}

#[no_mangle]
pub extern "C" fn roastty_paste_is_safe(data: *const u8, len: usize) -> bool {
    if data.is_null() {
        return true;
    }
    paste::is_safe(unsafe { slice::from_raw_parts(data, len) })
}

#[no_mangle]
pub extern "C" fn roastty_paste_encode(
    data: *mut u8,
    data_len: usize,
    bracketed: bool,
    out: *mut u8,
    out_len: usize,
    out_written: *mut usize,
) -> c_int {
    if out_written.is_null() {
        return ROASTTY_INVALID_VALUE;
    }
    let data = if data.is_null() {
        &mut []
    } else {
        unsafe { slice::from_raw_parts_mut(data, data_len) }
    };
    let segments = paste::encode(data, paste::PasteOptions { bracketed });
    write_byte_segments(&segments, out, out_len, out_written)
}

fn mode_report_state_from_raw(state: c_int) -> Option<modes::ReportState> {
    match state {
        ROASTTY_MODE_REPORT_NOT_RECOGNIZED => Some(modes::ReportState::NotRecognized),
        ROASTTY_MODE_REPORT_SET => Some(modes::ReportState::Set),
        ROASTTY_MODE_REPORT_RESET => Some(modes::ReportState::Reset),
        ROASTTY_MODE_REPORT_PERMANENTLY_SET => Some(modes::ReportState::PermanentlySet),
        ROASTTY_MODE_REPORT_PERMANENTLY_RESET => Some(modes::ReportState::PermanentlyReset),
        _ => None,
    }
}

#[no_mangle]
pub extern "C" fn roastty_mode_report_encode(
    tag: u16,
    state: c_int,
    out: *mut u8,
    out_len: usize,
    out_written: *mut usize,
) -> c_int {
    if out_written.is_null() {
        return ROASTTY_INVALID_VALUE;
    }
    let Some(state) = mode_report_state_from_raw(state) else {
        unsafe {
            out_written.write(0);
        }
        return ROASTTY_INVALID_VALUE;
    };
    let (value, ansi) = mode_tag_parts(tag);
    let output = modes::Report::new(modes::ModeTag::new(value, ansi), state).encode_vt();
    write_byte_segments(&[output.as_bytes()], out, out_len, out_written)
}

#[no_mangle]
pub extern "C" fn roastty_config_new() -> RoasttyConfig {
    let mut config = Config {
        parsed: config::Config::default(),
        before_default_files: None,
        before_default_files_diagnostics_len: None,
        finalized: false,
        confirm_close_surface: config::ConfirmCloseSurface::True,
        has_global_keybinds: false,
        keybind_triggers: Vec::new(),
        keybind_sequences: ConfigKeybindSet::default(),
        keybind_tables: Vec::new(),
        keybind_chain_parent: None,
        cached_title: None,
        cached_window_title_font_family: None,
        cached_background_image: None,
        cached_bell_audio_path: None,
        cached_command_strings: Vec::new(),
        cached_commands: Vec::new(),
        diagnostics: Vec::new(),
    };
    config.sync_from_parsed_config();
    Box::into_raw(Box::new(config)).cast()
}

#[no_mangle]
pub extern "C" fn roastty_config_free(config: RoasttyConfig) {
    if !config.is_null() {
        unsafe {
            drop(Box::from_raw(config.cast::<Config>()));
        }
    }
}

#[no_mangle]
pub extern "C" fn roastty_config_clone(config: RoasttyConfig) -> RoasttyConfig {
    let (
        parsed,
        before_default_files,
        before_default_files_diagnostics_len,
        finalized,
        confirm_close_surface,
        has_global_keybinds,
        keybind_triggers,
        keybind_sequences,
        keybind_tables,
        diagnostics,
    ) = config_from_handle(config)
        .map(|config| {
            (
                config.parsed.clone(),
                config.before_default_files.clone(),
                config.before_default_files_diagnostics_len,
                config.finalized,
                config.confirm_close_surface,
                config.has_global_keybinds,
                config.keybind_triggers.clone(),
                config.keybind_sequences.clone(),
                config.keybind_tables.clone(),
                config.diagnostics.clone(),
            )
        })
        .unwrap_or((
            config::Config::default(),
            None,
            None,
            false,
            config::ConfirmCloseSurface::True,
            false,
            Vec::new(),
            ConfigKeybindSet::default(),
            Vec::new(),
            Vec::new(),
        ));
    let mut cloned = Config {
        parsed,
        before_default_files,
        before_default_files_diagnostics_len,
        finalized,
        confirm_close_surface,
        has_global_keybinds,
        keybind_triggers,
        keybind_sequences,
        keybind_tables,
        keybind_chain_parent: None,
        cached_title: None,
        cached_window_title_font_family: None,
        cached_background_image: None,
        cached_bell_audio_path: None,
        cached_command_strings: Vec::new(),
        cached_commands: Vec::new(),
        diagnostics,
    };
    cloned.sync_from_parsed_config();
    Box::into_raw(Box::new(cloned)).cast()
}

#[no_mangle]
pub extern "C" fn roastty_config_load_cli_args(config: RoasttyConfig) {
    let Some(config) = config_from_handle(config) else {
        return;
    };
    let argv = INIT_ARGV.lock().unwrap().clone();
    let mut config_args = Vec::new();
    let cli_outer_diagnostics_start = config.diagnostics.len();
    let mut index = 1;
    while index < argv.len() {
        let arg = &argv[index];
        if let Some(value) = arg.strip_prefix(b"--keybind=") {
            config.apply_cli_keybind_arg(value);
            index += 1;
            continue;
        }
        if arg == b"--keybind" {
            if let Some(value) = argv
                .get(index + 1)
                .filter(|value| !value.starts_with(b"--"))
            {
                config.apply_cli_keybind_arg(value);
                index += 2;
            } else {
                config.push_diagnostic("invalid keybind: value required");
                index += 1;
            }
            continue;
        }
        if arg.starts_with(b"--") {
            match std::str::from_utf8(arg) {
                Ok(arg) => config_args.push(arg.to_string()),
                Err(_) => config.push_cli_config_arg_utf8_diagnostic(arg),
            }
        }
        index += 1;
    }
    let diagnostics = config.apply_cli_config_args(&config_args, cli_outer_diagnostics_start);
    for diagnostic in &diagnostics {
        config.push_config_diagnostic("cli", diagnostic);
    }
    config.sync_from_parsed_config();
}

#[no_mangle]
pub extern "C" fn roastty_config_load_file(config: RoasttyConfig, path: *const c_char) {
    let Some(config) = config_from_handle(config) else {
        return;
    };
    if path.is_null() {
        return;
    }

    let path = unsafe { CStr::from_ptr(path) };
    let path = Path::new(OsStr::from_bytes(path.to_bytes()));
    match config.parsed.load_file(path) {
        Ok(diagnostics) => {
            config.push_config_load_diagnostics(path.display(), &diagnostics);
            config.sync_from_parsed_config();
        }
        Err(error) => config.push_config_file_error(path.display(), &error),
    }
}

#[no_mangle]
pub extern "C" fn roastty_config_load_default_files(config: RoasttyConfig) {
    let Some(config) = config_from_handle(config) else {
        return;
    };

    config.snapshot_default_files_boundary();
    let report = config.parsed.load_default_files();
    for load in &report.loaded {
        config.push_config_load_diagnostics(load.path.display(), &load.diagnostics);
    }
    for error in &report.errors {
        config.push_config_file_error(error.path.display(), &error.error);
    }
    config.sync_from_parsed_config();
}

#[no_mangle]
pub extern "C" fn roastty_config_load_recursive_files(config: RoasttyConfig) {
    let Some(config) = config_from_handle(config) else {
        return;
    };

    let report = config.parsed.load_recursive_files_from_config();
    for load in &report.loaded {
        config.push_config_load_diagnostics(load.path.display(), &load.diagnostics);
    }
    for error in &report.errors {
        match &error.error {
            config::ConfigRecursiveFileErrorKind::RelativePath => {
                config.push_config_recursive_relative_path(error.path.display());
            }
            config::ConfigRecursiveFileErrorKind::Io(io_error) => {
                config.push_config_file_error(error.path.display(), io_error);
            }
        }
    }
    for cycle in &report.cycles {
        config.push_config_recursive_cycle(cycle.display());
    }
    config.sync_from_parsed_config();
}

#[no_mangle]
pub extern "C" fn roastty_config_finalize(config: RoasttyConfig) {
    if let Some(config) = config_from_handle(config) {
        config.parsed.finalize();
        config.sync_from_parsed_config();
        config.finalized = true;
    }
}

#[no_mangle]
pub extern "C" fn roastty_config_get(
    config: RoasttyConfig,
    output: *mut c_void,
    key: *const c_char,
    key_len: usize,
) -> bool {
    if config.is_null() || output.is_null() || key.is_null() {
        return false;
    }

    let key = unsafe { slice::from_raw_parts(key.cast::<u8>(), key_len) };
    unsafe {
        match key {
            b"initial-window" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output.cast::<bool>().write(config.parsed.initial_window);
                true
            }
            b"quit-after-last-window-closed" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<bool>()
                    .write(config.parsed.quit_after_last_window_closed);
                true
            }
            b"auto-update-channel" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                let Some(value) = config.parsed.auto_update_channel else {
                    return false;
                };
                output
                    .cast::<*const c_char>()
                    .write(release_channel_keyword(value));
                true
            }
            b"focus-follows-mouse" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<bool>()
                    .write(config.parsed.focus_follows_mouse);
                true
            }
            b"maximize" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output.cast::<bool>().write(config.parsed.maximize);
                true
            }
            b"window-save-state" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<*const c_char>()
                    .write(window_save_state_keyword(config.parsed.window_save_state));
                true
            }
            b"window-decoration" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<*const c_char>()
                    .write(window_decoration_keyword(config.parsed.window_decoration));
                true
            }
            b"window-theme" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<*const c_char>()
                    .write(window_theme_keyword(config.parsed.window_theme));
                true
            }
            b"window-title-font-family" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                let Some(value) = config.cached_window_title_font_family.as_ref() else {
                    return false;
                };
                output.cast::<*const c_char>().write(value.as_ptr());
                true
            }
            b"macos-titlebar-style" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<*const c_char>()
                    .write(macos_titlebar_style_keyword(
                        config.parsed.macos_titlebar_style,
                    ));
                true
            }
            b"macos-window-shadow" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<bool>()
                    .write(config.parsed.macos_window_shadow);
                true
            }
            b"resize-overlay" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<*const c_char>()
                    .write(resize_overlay_keyword(config.parsed.resize_overlay));
                true
            }
            b"scrollbar" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<*const c_char>()
                    .write(scrollbar_keyword(config.parsed.scrollbar));
                true
            }
            b"background-opacity" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output.cast::<f64>().write(config.parsed.background_opacity);
                true
            }
            b"palette" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<RoasttyPalette>()
                    .write(palette_from_color(config.parsed.palette.value));
                true
            }
            b"palette-generate" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output.cast::<bool>().write(config.parsed.palette_generate);
                true
            }
            b"palette-harmonious" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<bool>()
                    .write(config.parsed.palette_harmonious);
                true
            }
            b"background-image" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                let Some(path) = config.cached_background_image.as_ref() else {
                    return false;
                };
                output.cast::<RoasttyConfigPath>().write(RoasttyConfigPath {
                    path: path.path.as_ptr(),
                    optional: path.optional,
                });
                true
            }
            b"bell-audio-volume" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output.cast::<f64>().write(config.parsed.bell_audio_volume);
                true
            }
            b"notify-on-command-finish-after" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output.cast::<usize>().write(
                    config
                        .parsed
                        .notify_on_command_finish_after
                        .as_milliseconds(),
                );
                true
            }
            b"title" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                let value = config
                    .cached_title
                    .as_ref()
                    .map(|title| title.as_ptr())
                    .unwrap_or(ptr::null());
                output.cast::<*const c_char>().write(value);
                true
            }
            b"window-position-x" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                let Some(value) = config.parsed.window_position_x else {
                    return false;
                };
                output.cast::<c_short>().write(value as c_short);
                true
            }
            b"window-position-y" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                let Some(value) = config.parsed.window_position_y else {
                    return false;
                };
                output.cast::<c_short>().write(value as c_short);
                true
            }
            b"bell-audio-path" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                let Some(path) = config.cached_bell_audio_path.as_ref() else {
                    return false;
                };
                output.cast::<RoasttyConfigPath>().write(RoasttyConfigPath {
                    path: path.path.as_ptr(),
                    optional: path.optional,
                });
                true
            }
            b"command-palette-entry" => {
                let Some(config) = config_from_handle(config) else {
                    return false;
                };
                output
                    .cast::<RoasttyConfigCommandList>()
                    .write(RoasttyConfigCommandList {
                        commands: config.cached_commands.as_ptr(),
                        len: config.cached_commands.len(),
                    });
                true
            }
            _ => false,
        }
    }
}

#[no_mangle]
pub extern "C" fn roastty_config_trigger(
    config: RoasttyConfig,
    action: *const c_char,
    action_len: usize,
) -> RoasttyInputTrigger {
    let Some(config) = config_from_handle(config) else {
        return empty_trigger();
    };
    if action.is_null() {
        return empty_trigger();
    }
    let action = unsafe { slice::from_raw_parts(action.cast::<u8>(), action_len) };
    let default_action = default_config_action_alias(action);
    if let Some(binding) = config.keybind_triggers.iter().rev().find(|binding| {
        !binding.is_chained()
            && !binding.is_unbind()
            && (binding.first_action() == action || binding.first_action() == default_action)
    }) {
        return binding.trigger;
    }
    empty_trigger()
}

/// Embedded by-value `config_key_is_binding` (the app's path) — supersedes the opaque
/// `*_handle` variant (Issue 802 / Exp 13). Mirrors the handle body: config match OR a
/// built-in default keybind.
#[no_mangle]
pub extern "C" fn roastty_config_key_is_binding(
    config: RoasttyConfig,
    event: RoasttyInputKey,
) -> bool {
    let Some(config) = config_from_handle(config) else {
        return false;
    };
    let ev = input_key_to_event(&event);
    config.key_event_is_binding(&ev.event)
}

/// Opaque-handle `config_key_is_binding` (pre-Exp-13 API) — retained for the existing tests.
#[no_mangle]
pub extern "C" fn roastty_config_key_is_binding_handle(
    config: RoasttyConfig,
    event: RoasttyKeyEvent,
) -> bool {
    let Some(config) = config_from_handle(config) else {
        return false;
    };
    let Some(event) = key_event_from_handle(event) else {
        return false;
    };
    config.key_event_is_binding(&event.event)
}

#[no_mangle]
pub extern "C" fn roastty_config_diagnostics_count(config: RoasttyConfig) -> u32 {
    config_from_handle(config)
        .map(|config| config.diagnostics.len().min(u32::MAX as usize) as u32)
        .unwrap_or(0)
}

#[no_mangle]
pub extern "C" fn roastty_config_get_diagnostic(
    config: RoasttyConfig,
    index: u32,
) -> RoasttyDiagnostic {
    let Some(config) = config_from_handle(config) else {
        return RoasttyDiagnostic {
            message: EMPTY_DIAGNOSTIC.as_ptr().cast::<c_char>(),
        };
    };
    if let Some(message) = config.diagnostics.get(index as usize) {
        return RoasttyDiagnostic {
            message: message.as_ptr(),
        };
    }
    RoasttyDiagnostic {
        message: EMPTY_DIAGNOSTIC.as_ptr().cast::<c_char>(),
    }
}

#[no_mangle]
pub extern "C" fn roastty_config_open_path() -> RoasttyString {
    allocated_string(b"roastty-config")
}

#[no_mangle]
pub extern "C" fn roastty_app_new(
    runtime: *const RoasttyRuntimeConfig,
    config: RoasttyConfig,
) -> RoasttyApp {
    let runtime = if runtime.is_null() {
        RoasttyRuntimeConfig {
            userdata: ptr::null_mut(),
            supports_selection_clipboard: false,
            wakeup_cb: None,
            action_cb: None,
            read_clipboard_cb: None,
            confirm_read_clipboard_cb: None,
            write_clipboard_cb: None,
            close_surface_cb: None,
        }
    } else {
        unsafe { *runtime }
    };
    let keymap = AppKeymap::new();
    let keyboard_layout = app_keyboard_layout_from_keymap(&keymap);

    let (
        confirm_close_surface,
        clipboard_read,
        clipboard_write,
        mouse_shift_capture,
        has_global_keybinds,
        keybind_triggers,
        keybind_sequences,
        keybind_tables,
        source_config,
        parsed_config,
    ) = config_from_handle(config)
        .map(|config| {
            let source_config = config.parsed.clone();
            let parsed = finalized_parsed_config_with_conditional_state(
                &source_config,
                config::conditional::State::default(),
            );
            (
                config.confirm_close_surface,
                parsed.clipboard_read,
                parsed.clipboard_write,
                parsed.mouse_shift_capture,
                config.has_global_keybinds,
                config.keybind_triggers.clone(),
                config.keybind_sequences.clone(),
                config.keybind_tables.clone(),
                source_config,
                parsed,
            )
        })
        .unwrap_or_else(|| {
            let source_config = config::Config::default();
            (
                config::ConfirmCloseSurface::True,
                config::ClipboardAccess::Ask,
                config::ClipboardAccess::Allow,
                config::MouseShiftCapture::False,
                false,
                Vec::new(),
                ConfigKeybindSet::default(),
                Vec::new(),
                source_config,
                default_finalized_config(),
            )
        });

    Box::into_raw(Box::new(App {
        runtime,
        focused: false,
        color_scheme: 0,
        config_conditional_state: config::conditional::State::default(),
        source_config,
        parsed_config,
        confirm_close_surface,
        clipboard_read,
        clipboard_write,
        mouse_shift_capture,
        has_global_keybinds,
        keymap,
        keyboard_layout,
        keybind_triggers,
        keybind_sequences,
        keybind_tables,
        initial_surface_pending: true,
        surfaces: Vec::new(),
    }))
    .cast()
}

#[no_mangle]
pub extern "C" fn roastty_app_free(app: RoasttyApp) {
    if !app.is_null() {
        unsafe {
            let mut app_box = Box::from_raw(app.cast::<App>());
            for mut surface in app_box.surfaces.drain(..) {
                let surface = surface.as_mut();
                surface.app = ptr::null_mut();
                surface.termio_worker = None;
            }
            drop(app_box);
        }
    }
}

#[no_mangle]
pub extern "C" fn roastty_app_tick(app: RoasttyApp) {
    let surfaces = app_from_handle(app)
        .map(|app| app.surfaces.clone())
        .unwrap_or_default();
    for mut surface in surfaces {
        let surface = unsafe { surface.as_mut() };
        if surface.app == app {
            surface.tick_termio();
        }
    }
}

#[no_mangle]
pub extern "C" fn roastty_app_userdata(app: RoasttyApp) -> *mut c_void {
    app_from_handle(app)
        .map(|app| app.runtime.userdata)
        .unwrap_or(ptr::null_mut())
}

#[no_mangle]
pub extern "C" fn roastty_app_set_focus(app: RoasttyApp, focused: bool) {
    if let Some(app) = app_from_handle(app) {
        app.focused = focused;
    }
}

#[no_mangle]
pub extern "C" fn roastty_app_update_config(app: RoasttyApp, config: RoasttyConfig) {
    let Some(app) = app_from_handle(app) else {
        return;
    };
    let Some(config) = config_from_handle(config) else {
        return;
    };
    let source_config = config.parsed.clone();
    let parsed_config = finalized_parsed_config_with_conditional_state(
        &source_config,
        app.config_conditional_state,
    );
    app.confirm_close_surface = config.confirm_close_surface;
    app.source_config = source_config;
    app.parsed_config = parsed_config;
    app.mouse_shift_capture = app.parsed_config.mouse_shift_capture;
    app.has_global_keybinds = config.has_global_keybinds;
    app.keybind_triggers = config.keybind_triggers.clone();
    app.keybind_sequences = config.keybind_sequences.clone();
    app.keybind_tables = config.keybind_tables.clone();
    for mut surface in app.surfaces.clone() {
        let surface = unsafe { surface.as_mut() };
        if surface.app == app as *mut App as RoasttyApp {
            surface.apply_config(config);
            surface.renderer = None;
            surface.dirty = true;
        }
    }
}

#[no_mangle]
pub extern "C" fn roastty_app_needs_confirm_quit(app: RoasttyApp) -> bool {
    let Some(app_ref) = app_from_handle(app) else {
        return false;
    };
    app_ref.surfaces.iter().any(|surface| {
        let surface = unsafe { surface.as_ref() };
        surface.app == app && surface.needs_confirm_quit()
    })
}

#[no_mangle]
pub extern "C" fn roastty_app_has_global_keybinds(app: RoasttyApp) -> bool {
    app_from_handle(app)
        .map(|app| app.has_global_keybinds)
        .unwrap_or(false)
}

#[no_mangle]
pub extern "C" fn roastty_app_set_color_scheme(app: RoasttyApp, color_scheme: c_int) {
    let Some(app_ref) = app_from_handle(app) else {
        return;
    };
    let Some(theme) = color_scheme_conditional_theme(color_scheme) else {
        return;
    };
    if app_ref.config_conditional_state.theme == theme {
        return;
    }
    app_ref.color_scheme = color_scheme;
    app_ref.config_conditional_state.theme = theme;
    let _ = app_ref.perform_app_runtime_action_result(
        app,
        ROASTTY_ACTION_RELOAD_CONFIG,
        soft_reload_config_storage(),
    );
}

#[no_mangle]
pub extern "C" fn roastty_terminal_new(
    columns: u16,
    rows: u16,
    max_scrollback_rows: usize,
    out: *mut RoasttyTerminal,
) -> c_int {
    if out.is_null() {
        return ROASTTY_INVALID_VALUE;
    }
    unsafe {
        out.write(ptr::null_mut());
    }
    if columns == 0 || rows == 0 {
        return ROASTTY_INVALID_VALUE;
    }

    let max_scrollback_rows = if max_scrollback_rows == usize::MAX {
        None
    } else {
        Some(max_scrollback_rows)
    };
    let terminal = match InnerTerminal::init(columns, rows, max_scrollback_rows) {
        Ok(terminal) => terminal,
        Err(_) => return ROASTTY_OUT_OF_MEMORY,
    };

    let mut terminal = Box::new(Terminal {
        terminal,
        tracked_grid_refs: Vec::new(),
    });
    let handle = (&mut *terminal) as *mut Terminal as RoasttyTerminal;
    terminal.terminal.set_effect_handle(handle);
    unsafe {
        out.write(Box::into_raw(terminal).cast());
    }
    ROASTTY_SUCCESS
}

#[no_mangle]
pub extern "C" fn roastty_terminal_free(terminal: RoasttyTerminal) {
    if !terminal.is_null() {
        unsafe {
            let mut terminal = Box::from_raw(terminal.cast::<Terminal>());
            terminal.detach_tracked_grid_refs();
            drop(terminal);
        }
    }
}

#[no_mangle]
pub extern "C" fn roastty_terminal_reset(terminal: RoasttyTerminal) {
    if let Some(terminal) = terminal_from_handle(terminal) {
        terminal.terminal.reset();
    }
}

#[no_mangle]
pub extern "C" fn roastty_terminal_vt_write(
    terminal: RoasttyTerminal,
    bytes: *const u8,
    len: usize,
) -> c_int {
    let Some(terminal) = terminal_from_handle(terminal) else {
        return ROASTTY_INVALID_VALUE;
    };
    if bytes.is_null() && len > 0 {
        return ROASTTY_INVALID_VALUE;
    }
    let input = if len == 0 {
        &[]
    } else {
        unsafe { slice::from_raw_parts(bytes, len) }
    };
    match terminal.terminal.next_slice(input) {
        Ok(()) => ROASTTY_SUCCESS,
        Err(error) => terminal_stream_error_result(error),
    }
}

#[no_mangle]
pub extern "C" fn roastty_terminal_set(
    terminal: RoasttyTerminal,
    option: c_int,
    value: *const c_void,
) -> c_int {
    let Some(terminal) = terminal_from_handle(terminal) else {
        return ROASTTY_INVALID_VALUE;
    };

    match option {
        ROASTTY_TERMINAL_OPTION_USERDATA => {
            terminal.terminal.set_effect_userdata(value.cast_mut());
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_WRITE_PTY => {
            terminal
                .terminal
                .set_write_pty_callback((!value.is_null()).then(|| unsafe {
                    std::mem::transmute::<*const c_void, TerminalWritePtyCallback>(value)
                }));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_BELL => {
            terminal
                .terminal
                .set_bell_callback((!value.is_null()).then(|| unsafe {
                    std::mem::transmute::<*const c_void, TerminalBellCallback>(value)
                }));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_ENQUIRY => {
            terminal
                .terminal
                .set_enquiry_callback((!value.is_null()).then(|| unsafe {
                    std::mem::transmute::<*const c_void, TerminalEnquiryCallback>(value)
                }));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_XTVERSION => {
            terminal
                .terminal
                .set_xtversion_callback((!value.is_null()).then(|| unsafe {
                    std::mem::transmute::<*const c_void, TerminalXtversionCallback>(value)
                }));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_TITLE_CHANGED => {
            terminal
                .terminal
                .set_title_changed_callback((!value.is_null()).then(|| unsafe {
                    std::mem::transmute::<*const c_void, TerminalTitleChangedCallback>(value)
                }));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_SIZE_CB => {
            terminal
                .terminal
                .set_size_callback((!value.is_null()).then(|| unsafe {
                    std::mem::transmute::<*const c_void, TerminalSizeCallback>(value)
                }));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_COLOR_SCHEME => {
            terminal
                .terminal
                .set_color_scheme_callback((!value.is_null()).then(|| unsafe {
                    std::mem::transmute::<*const c_void, TerminalColorSchemeCallback>(value)
                }));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_DEVICE_ATTRIBUTES => {
            terminal
                .terminal
                .set_device_attributes_callback((!value.is_null()).then(|| unsafe {
                    std::mem::transmute::<*const c_void, TerminalDeviceAttributesCallback>(value)
                }));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_TITLE => match staged_terminal_string(value) {
            Ok(value) => {
                terminal.terminal.set_title(value);
                ROASTTY_SUCCESS
            }
            Err(error) => error,
        },
        ROASTTY_TERMINAL_OPTION_PWD => match staged_terminal_pwd(value) {
            Ok(value) => {
                terminal.terminal.set_pwd(value);
                ROASTTY_SUCCESS
            }
            Err(error) => error,
        },
        ROASTTY_TERMINAL_OPTION_COLOR_FOREGROUND => {
            terminal
                .terminal
                .set_color_default(TerminalColorKind::Foreground, read_rgb(value));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_COLOR_BACKGROUND => {
            terminal
                .terminal
                .set_color_default(TerminalColorKind::Background, read_rgb(value));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_COLOR_CURSOR => {
            terminal
                .terminal
                .set_color_default(TerminalColorKind::Cursor, read_rgb(value));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_COLOR_PALETTE => {
            terminal.terminal.set_palette_default(read_palette(value));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_KITTY_IMAGE_STORAGE_LIMIT => {
            let limit = match read_optional_u64(value) {
                Some(value) => match usize::try_from(value) {
                    Ok(value) => value,
                    Err(_) => return ROASTTY_INVALID_VALUE,
                },
                None => 0,
            };
            terminal.terminal.set_kitty_image_storage_limit(limit);
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_KITTY_IMAGE_MEDIUM_FILE => {
            if let Some(enabled) = read_optional_bool(value) {
                terminal
                    .terminal
                    .set_kitty_image_medium(KittyImageMedium::File, enabled);
            }
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_KITTY_IMAGE_MEDIUM_TEMP_FILE => {
            if let Some(enabled) = read_optional_bool(value) {
                terminal
                    .terminal
                    .set_kitty_image_medium(KittyImageMedium::TemporaryFile, enabled);
            }
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_KITTY_IMAGE_MEDIUM_SHARED_MEM => {
            if let Some(enabled) = read_optional_bool(value) {
                terminal
                    .terminal
                    .set_kitty_image_medium(KittyImageMedium::SharedMemory, enabled);
            }
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_APC_MAX_BYTES => {
            terminal
                .terminal
                .set_apc_max_bytes(read_optional_usize(value));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_APC_MAX_BYTES_KITTY => {
            terminal
                .terminal
                .set_kitty_apc_max_bytes(read_optional_usize(value));
            ROASTTY_SUCCESS
        }
        ROASTTY_TERMINAL_OPTION_SELECTION => {
            let selection = if value.is_null() {
                None
            } else {
                match read_selection(value.cast::<RoasttyGridSelection>()) {
                    Ok(selection) => Some(selection),
                    Err(error) => return error,
                }
            };
            match terminal.terminal.set_selection(selection) {
                Ok(()) => ROASTTY_SUCCESS,
                Err(error) => grid_ref_error_result(error),
            }
        }
        _ => ROASTTY_INVALID_VALUE,
    }
}

#[no_mangle]
pub extern "C" fn roastty_terminal_mode_get(
    terminal: RoasttyTerminal,
    tag: u16,
    out: *mut bool,
) -> c_int {
    let Some(terminal) = terminal_from_handle(terminal) else {
        return ROASTTY_INVALID_VALUE;
    };
    if out.is_null() {
        return ROASTTY_INVALID_VALUE;
    }

    let (value, ansi) = mode_tag_parts(tag);
    let Some(enabled) = terminal.terminal.mode_get(value, ansi) else {
        return ROASTTY_INVALID_VALUE;
    };
    unsafe {
        out.write(enabled);
    }
    ROASTTY_SUCCESS
}

#[no_mangle]
pub extern "C" fn roastty_terminal_mode_set(
    terminal: RoasttyTerminal,
    tag: u16,
    enabled: bool,
) -> c_int {
    let Some(terminal) = terminal_from_handle(terminal) else {
        return ROASTTY_INVALID_VALUE;
    };

    let (value, ansi) = mode_tag_parts(tag);
    if !terminal.terminal.mode_set(value, ansi, enabled) {
        return ROASTTY_INVALID_VALUE;
    }
    ROASTTY_SUCCESS
}

