#[no_mangle]
pub extern "C" fn roastty_surface_new(
    app: RoasttyApp,
    config: *const RoasttySurfaceConfig,
) -> RoasttySurface {
    if app.is_null() {
        return ptr::null_mut();
    }

    let config = if config.is_null() {
        roastty_surface_config_new()
    } else {
        unsafe { *config }
    };
    let (
        confirm_close_surface,
        clipboard_read,
        clipboard_write,
        clipboard_paste_protection,
        clipboard_paste_bracketed_safe,
        copy_on_select,
        selection_clear_on_typing,
        selection_word_chars,
        vt_kam_allowed,
        key_remaps,
        macos_option_as_alt,
        cursor_click_to_move,
        right_click_action,
        middle_click_action,
        mouse_reporting,
        mouse_scroll_multiplier,
        click_repeat_interval_ns,
        window_vsync,
        config_conditional_state,
    ) = app_from_handle(app)
        .map(|app| {
            let parsed = finalized_parsed_config_with_conditional_state(
                &app.source_config,
                app.config_conditional_state,
            );
            (
                app.confirm_close_surface,
                app.clipboard_read,
                app.clipboard_write,
                parsed.clipboard_paste_protection,
                parsed.clipboard_paste_bracketed_safe,
                parsed.copy_on_select,
                parsed.selection_clear_on_typing,
                parsed.selection_word_chars.codepoints.clone(),
                parsed.vt_kam_allowed,
                parsed.key_remap.clone(),
                parsed.macos_option_as_alt,
                parsed.cursor_click_to_move,
                parsed.right_click_action,
                parsed.middle_click_action,
                parsed.mouse_reporting,
                parsed.mouse_scroll_multiplier,
                click_repeat_interval_ns(&parsed),
                parsed.window_vsync,
                app.config_conditional_state,
            )
        })
        .unwrap_or((
            config::ConfirmCloseSurface::True,
            config::ClipboardAccess::Ask,
            config::ClipboardAccess::Allow,
            true,
            true,
            config::CopyOnSelect::True,
            true,
            config::SelectionWordChars::default().codepoints,
            false,
            key_mods::RemapSet::default(),
            None,
            true,
            config::RightClickAction::ContextMenu,
            config::MiddleClickAction::PrimaryPaste,
            true,
            config::MouseScrollMultiplier::default(),
            500_000_000,
            true,
            config::conditional::State::default(),
        ));

    let initial_surface = app_from_handle(app)
        .map(|app| {
            let initial_surface = app.initial_surface_pending;
            app.initial_surface_pending = false;
            initial_surface
        })
        .unwrap_or(false);
    let font_size_points = sanitized_font_size_points(config.font_size);
    let surface = Box::new(Surface {
        app,
        userdata: config.userdata,
        working_directory: copied_config_string(config.working_directory),
        command: copied_config_string(config.command),
        initial_surface,
        env_vars: copied_env_vars(config.env_vars, config.env_var_count),
        initial_input: copied_config_string(config.initial_input).map(String::into_bytes),
        context: valid_surface_context(config.context).unwrap_or(0),
        font_size_points,
        original_font_size_points: font_size_points,
        font_size_adjusted: false,
        scale_factor_x: config.scale_factor,
        scale_factor_y: config.scale_factor,
        inherited_working_directory: None,
        display_id: 0,
        focused: false,
        visible: true,
        size: RoasttySurfaceSize {
            columns: 0,
            rows: 0,
            width_px: 0,
            height_px: 0,
            cell_width_px: 0,
            cell_height_px: 0,
        },
        color_scheme: 0,
        config_conditional_state,
        confirm_close_surface,
        clipboard_read,
        clipboard_write,
        clipboard_paste_protection,
        clipboard_paste_bracketed_safe,
        copy_on_select,
        selection_clear_on_typing,
        selection_word_chars,
        vt_kam_allowed,
        key_remaps,
        macos_option_as_alt,
        cursor_click_to_move,
        right_click_action,
        middle_click_action,
        mouse_scroll_multiplier,
        click_repeat_interval_ns,
        preedit: None,
        inspector: None,
        last_key_event: None,
        last_consumed_default_binding: None,
        active_key_sequence: None,
        queued_key_sequence: Vec::new(),
        active_key_tables: Vec::new(),
        mouse: SurfaceMouseState::default(),
        mouse_reporting,
        selection_gesture: SelectionGesture::default(),
        selection_click_epoch: std::time::Instant::now(),
        readonly: false,
        termio_worker: None,
        retained_write_file_dirs: Vec::new(),
        active_clipboard_requests: Vec::new(),
        kitty_clipboard_write: None,
        process_exited: false,
        dirty: false,
        cursor_blink_visible: false,
        cursor_blink_next: std::time::Instant::now() + CURSOR_BLINK_INTERVAL,
        last_cursor_reset: None,
        last_termio_error: None,
        // Capture the app's NSView (macOS) for the live-render target (Exp 15). Null off-macOS.
        nsview: if config.platform_tag == 1 {
            // 1 == ROASTTY_PLATFORM_MACOS
            unsafe { config.platform.macos.nsview }
        } else {
            ptr::null_mut()
        },
        renderer: None,
        present_driver: None,
        #[cfg(test)]
        test_termio_events: VecDeque::new(),
    });
    let surface = NonNull::from(Box::leak(surface));
    register_surface(app, surface);
    // Auto-start the surface IO for real macOS app surfaces (Issue 802 / Exp 16), matching
    // upstream's `surface_new` (which starts the IO itself — upstream has no `surface_start`,
    // and the renamed app never calls `roastty_surface_start`). Gated on the runtime
    // `platform_tag == MACOS` (1): the `abi_harness` + unit tests use `platform_tag == 0` and
    // inject `termio_worker` manually, so they are excluded (a `cfg(test)` gate would NOT
    // exclude the harness, which links the cdylib).
    if config.platform_tag == 1 {
        // 1 == ROASTTY_PLATFORM_MACOS
        let surface_ptr = surface.as_ptr();
        if let Some(s) = unsafe { surface_ptr.as_mut() } {
            let _ = s.start_termio();
            // Start the continuous present driver (Exp 19/175) so the terminal updates live.
            s.present_driver = Some(PresentDriver::start(surface_ptr, window_vsync));
        }
    }
    surface.as_ptr().cast()
}

#[no_mangle]
pub extern "C" fn roastty_surface_start(surface: RoasttySurface) -> c_int {
    let Some(surface) = surface_from_handle(surface) else {
        return ROASTTY_INVALID_VALUE;
    };
    surface.start_termio()
}

#[no_mangle]
pub extern "C" fn roastty_surface_free(surface: RoasttySurface) {
    if !surface.is_null() {
        // Stop the present driver (Exp 19/175) before freeing — its thread/display link +
        // main-queue ticks check the flag before touching the surface. (`Drop` repeats this as a
        // safety net.)
        if let Some(s) = surface_from_handle(surface) {
            if let Some(driver) = &mut s.present_driver {
                driver.stop();
            }
        }
        unsafe {
            let surface_ptr = NonNull::new_unchecked(surface.cast::<Surface>());
            let mut surface_box = Box::from_raw(surface.cast::<Surface>());
            surface_box.free_inspector();
            if !surface_box.app.is_null() {
                unregister_surface(surface_box.app, surface_ptr);
            }
            drop(surface_box);
        }
    }
}

