pub extern "C" fn roastty_surface_key_translation_mods(
    surface: RoasttySurface,
    mods: c_int,
) -> c_int {
    let Some(surface) = surface_from_handle(surface) else {
        return key_mods_to_raw(key_mods_from_raw(mods));
    };
    if surface.app.is_null() {
        return key_mods_to_raw(key_mods_from_raw(mods));
    }
    let option_as_alt = surface.macos_option_as_alt.unwrap_or_else(|| {
        app_from_handle(surface.app)
            .map(|app| app.keyboard_layout.detect_option_as_alt())
            .unwrap_or(key_mods::OptionAsAlt::False)
    });
    key_mods_to_raw(key_mods_from_raw(mods).translation(option_as_alt))
}

/// Embedded by-value key event (Issue 802 / Exp 8) — byte-faithful to
/// `ghostty_input_key_s` / `roastty_input_key_s`.
#[repr(C)]
pub struct RoasttyInputKey {
    pub action: c_int,
    pub mods: c_int,
    pub consumed_mods: c_int,
    pub keycode: u32,
    pub text: *const c_char,
    pub unshifted_codepoint: u32,
    pub composing: bool,
}

/// Build the internal `KeyEvent` from a by-value `roastty_input_key_s`.
/// `text` is a NUL-terminated C string (null → empty), UTF-8-validated to match
/// the opaque path's `set_utf8` semantics.
fn input_key_to_event(k: &RoasttyInputKey) -> KeyEvent {
    let mut ev = key::KeyEvent::default();
    if let Some(action) = key_action_from_int(k.action) {
        ev.action = action;
    }
    // `keycode` is the NATIVE platform keycode (e.g. macOS keyCode), not a Key enum
    // index — resolve the physical key via the native→Key table, matching ghostty
    // `apprt/embedded.zig` `KeyEvent.core()`.
    ev.key = key::key_from_native(k.keycode);
    ev.mods = key_mods::Mods::from_int(k.mods as u16);
    ev.consumed_mods = key_mods::Mods::from_int(k.consumed_mods as u16);
    ev.composing = k.composing;
    // Clamp to u21 (`std.math.cast(u21, …) orelse 0` upstream), zeroing out-of-range.
    ev.unshifted_codepoint = if k.unshifted_codepoint <= 0x1f_ffff {
        k.unshifted_codepoint
    } else {
        0
    };
    if !k.text.is_null() {
        let bytes = unsafe { CStr::from_ptr(k.text) }.to_bytes();
        if let Ok(s) = core::str::from_utf8(bytes) {
            ev.utf8 = s.as_bytes().to_vec();
        }
    }
    KeyEvent { event: ev }
}

fn trace_hex(bytes: &[u8]) -> String {
    bytes
        .iter()
        .map(|byte| format!("{byte:02x}"))
        .collect::<Vec<_>>()
        .join("")
}

fn trace_input_text_hex(event: &RoasttyInputKey) -> String {
    if event.text.is_null() {
        return String::new();
    }

    trace_hex(unsafe { CStr::from_ptr(event.text) }.to_bytes())
}

pub(crate) fn append_ui_key_trace(line: impl AsRef<str>) {
    let Some(path) = std::env::var_os("ROASTTY_UI_KEY_TRACE_PATH") else {
        return;
    };

    let Ok(mut file) = std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(path)
    else {
        return;
    };

    let _ = writeln!(file, "{}", line.as_ref());
}

/// Embedded by-value `surface_key` (the app's path) — supersedes the opaque
/// `*_handle` variant (kept for the existing tests).
#[no_mangle]
pub extern "C" fn roastty_surface_key(surface: RoasttySurface, event: RoasttyInputKey) -> bool {
    let Some(surface) = surface_from_handle(surface) else {
        append_ui_key_trace(format!(
            "rust roastty_surface_key result=false reason=no-surface action={} keycode={} mods={} consumed_mods={} composing={} text_hex={}",
            event.action,
            event.keycode,
            event.mods,
            event.consumed_mods,
            event.composing,
            trace_input_text_hex(&event)
        ));
        return false;
    };
    let ev = input_key_to_event(&event);
    let result = surface.key(&ev);
    append_ui_key_trace(format!(
        "rust roastty_surface_key result={} action={} keycode={} mods={} consumed_mods={} composing={} text_hex={} utf8_hex={}",
        result,
        event.action,
        event.keycode,
        event.mods,
        event.consumed_mods,
        event.composing,
        trace_input_text_hex(&event),
        trace_hex(&ev.event.utf8)
    ));
    result
}

/// Embedded by-value `app_key`. Handles configured global keybinds, direct
/// chained leaves, and focused app-scoped keybinds; native keymaps, key tables,
/// and sequences remain later feature-completion items.
