    #[derive(Clone, Debug, Default, PartialEq, Eq)]
    struct ActionRecord {
        app: RoasttyApp,
        target_tag: c_int,
        surface: RoasttySurface,
        action_tag: c_int,
        storage: [usize; 8],
        title: Option<String>,
        needle: Option<String>,
        open_url: Option<(c_int, Vec<u8>)>,
        key_table: Option<(c_int, Vec<u8>)>,
        key_sequence: Option<(bool, c_int, usize, c_int)>,
    }

