    unsafe extern "C" fn split_action_cb(
        app: RoasttyApp,
        target: RoasttyTarget,
        action: RoasttyAction,
    ) -> bool {
        ACTION_RECORDS.with(|records| {
            // Reconstruct the storage carrier from the typed union (round-trips the
            // real storage→union conversion) so these assertions stay storage-based.
            let storage = action_u_to_storage(action.tag, &action.action);
            let title = if matches!(
                action.tag,
                ROASTTY_ACTION_SET_TITLE | ROASTTY_ACTION_SET_TAB_TITLE
            ) {
                let ptr = storage[0] as *const c_char;
                (!ptr.is_null()).then(|| {
                    unsafe { CStr::from_ptr(ptr) }
                        .to_string_lossy()
                        .into_owned()
                })
            } else {
                None
            };
            let needle = if action.tag == ROASTTY_ACTION_START_SEARCH {
                let ptr = storage[0] as *const c_char;
                (!ptr.is_null()).then(|| {
                    unsafe { CStr::from_ptr(ptr) }
                        .to_string_lossy()
                        .into_owned()
                })
            } else {
                None
            };
            let open_url = if action.tag == ROASTTY_ACTION_OPEN_URL {
                let ptr = storage[1] as *const u8;
                let len = storage[2];
                (!ptr.is_null()).then(|| {
                    let bytes = unsafe { slice::from_raw_parts(ptr, len) };
                    (storage[0] as c_int, bytes.to_vec())
                })
            } else {
                None
            };
            let key_table = if action.tag == ROASTTY_ACTION_KEY_TABLE {
                let tag = storage[0] as c_int;
                let ptr = storage[1] as *const u8;
                let len = storage[2];
                let name = if tag == ROASTTY_KEY_TABLE_ACTIVATE && !ptr.is_null() {
                    unsafe { slice::from_raw_parts(ptr, len) }.to_vec()
                } else {
                    Vec::new()
                };
                Some((tag, name))
            } else {
                None
            };
            let key_sequence = if action.tag == ROASTTY_ACTION_KEY_SEQUENCE {
                Some((
                    storage[0] != 0,
                    storage[1] as c_int,
                    storage[2],
                    storage[3] as c_int,
                ))
            } else {
                None
            };
            records.borrow_mut().push(ActionRecord {
                app,
                target_tag: target.tag,
                surface: unsafe { target.target.surface },
                action_tag: action.tag,
                storage,
                title,
                needle,
                open_url,
                key_table,
                key_sequence,
            });
        });
        if target.tag == ROASTTY_TARGET_APP && action.tag == ROASTTY_ACTION_QUIT {
            DETACH_ON_APP_ACTION.with(|surface| {
                if let Some(surface) = surface.borrow_mut().take() {
                    if let Some(surface) = surface_from_handle(surface) {
                        surface.app = ptr::null_mut();
                    }
                }
            });
        }
        ACTION_RESULT.with(|result| *result.borrow())
    }

    fn reset_action_records(result: bool) {
        ACTION_RECORDS.with(|records| records.borrow_mut().clear());
        ACTION_RESULT.with(|stored| *stored.borrow_mut() = result);
        DETACH_ON_APP_ACTION.with(|surface| *surface.borrow_mut() = None);
    }

    fn action_records() -> Vec<ActionRecord> {
        ACTION_RECORDS.with(|records| records.borrow().clone())
    }

