    #[test]
    fn surface_set_color_scheme_updates_conditional_state_reloads_and_reports() {
        let _guard = pty_command_lock();
        let app = new_test_app_with_action(true);
        let surface = new_test_surface(app);
        surface_from_handle(surface).unwrap().termio_worker = Some(test_worker("sleep 1"));

        roastty_surface_set_color_scheme(surface, 99);
        roastty_surface_set_color_scheme(surface, ROASTTY_COLOR_SCHEME_LIGHT);
        assert!(action_records().is_empty());
        assert_eq!(
            surface_from_handle(surface)
                .unwrap()
                .config_conditional_state
                .theme,
            config::conditional::Theme::Light
        );

        roastty_surface_set_color_scheme(surface, ROASTTY_COLOR_SCHEME_DARK);
        let records = action_records();
        assert_eq!(records.len(), 1);
        assert_eq!(records[0].target_tag, ROASTTY_TARGET_SURFACE);
        assert_eq!(records[0].surface, surface);
        assert_eq!(records[0].action_tag, ROASTTY_ACTION_RELOAD_CONFIG);
        assert_eq!(records[0].storage[0], 1);
        assert_eq!(
            surface_from_handle(surface)
                .unwrap()
                .config_conditional_state
                .theme,
            config::conditional::Theme::Dark
        );

        reset_action_records(true);
        roastty_surface_set_color_scheme(surface, ROASTTY_COLOR_SCHEME_DARK);
        assert!(action_records().is_empty());

        roastty_surface_free(surface);
        roastty_app_free(app);
    }

    fn app_surface_count(app: RoasttyApp) -> usize {
        app_from_handle(app)
            .map(|app| app.surfaces.len())
            .unwrap_or_default()
    }

    fn read_surface_screen_text(surface: RoasttySurface) -> String {
        let mut text = RoasttyText {
            tl_px_x: 0.0,
            tl_px_y: 0.0,
            offset_start: 0,
            offset_len: 0,
            text: ptr::null(),
            text_len: 0,
        };
        let selection = RoasttySelection {
            top_left: RoasttyPoint {
                tag: ROASTTY_POINT_SCREEN,
                coord: 0,
                x: 0,
                y: 0,
            },
            bottom_right: RoasttyPoint {
                tag: ROASTTY_POINT_SCREEN,
                coord: 0,
                x: 200,
                y: 200,
            },
            rectangle: false,
        };
        assert!(roastty_surface_read_text(surface, selection, &mut text));
        let result = unsafe { CStr::from_ptr(text.text).to_string_lossy().into_owned() };
        roastty_surface_free_text(surface, &mut text);
        result
    }

    fn test_worker(script: &str) -> termio::TermioWorker {
        test_worker_with_size(script, test_pty_size())
    }

    fn test_worker_with_size(script: &str, size: PtySize) -> termio::TermioWorker {
        let termio = termio::Termio::spawn("/bin/sh", ["-c", script], size).expect("spawn termio");
        termio::TermioWorker::spawn(termio, 10, 4096).expect("spawn termio worker")
    }

    fn wait_until(mut done: impl FnMut() -> bool) {
        for _ in 0..100 {
            if done() {
                return;
            }
            thread::sleep(Duration::from_millis(10));
        }
        panic!("condition not met");
    }

    struct DefaultShellDesktopOverrideGuard {
        previous: Option<bool>,
    }

    impl DefaultShellDesktopOverrideGuard {
        fn new(value: bool) -> Self {
            let previous = DEFAULT_SHELL_DESKTOP_OVERRIDE.with(|state| {
                let previous = state.get();
                state.set(Some(value));
                previous
            });
            Self { previous }
        }
    }

    impl Drop for DefaultShellDesktopOverrideGuard {
        fn drop(&mut self) {
            DEFAULT_SHELL_DESKTOP_OVERRIDE.with(|state| state.set(self.previous));
        }
    }

    struct EnvGuard {
        key: &'static str,
        previous: Option<OsString>,
    }

    impl EnvGuard {
        fn set(key: &'static str, value: impl AsRef<std::ffi::OsStr>) -> Self {
            let previous = std::env::var_os(key);
            std::env::set_var(key, value);
            Self { key, previous }
        }
    }

    impl Drop for EnvGuard {
        fn drop(&mut self) {
            if let Some(previous) = &self.previous {
                std::env::set_var(self.key, previous);
            } else {
                std::env::remove_var(self.key);
            }
        }
    }

    struct CurrentDirGuard {
        previous: PathBuf,
    }

    impl CurrentDirGuard {
        fn set(path: &std::path::Path) -> Self {
            let previous = std::env::current_dir().unwrap();
            std::env::set_current_dir(path).unwrap();
            Self { previous }
        }
    }

    impl Drop for CurrentDirGuard {
        fn drop(&mut self) {
            std::env::set_current_dir(&self.previous).unwrap();
        }
    }

    struct TempScript {
        path: PathBuf,
    }

    impl TempScript {
        fn new(body: &[u8]) -> Self {
            let id = SCRIPT_COUNTER.fetch_add(1, Ordering::Relaxed);
            let path = std::env::temp_dir().join(format!(
                "roastty-default-shell-{}-{id}.sh",
                std::process::id()
            ));
            std::fs::write(&path, body).expect("write script");
            let mut permissions = std::fs::metadata(&path)
                .expect("script metadata")
                .permissions();
            permissions.set_mode(0o755);
            std::fs::set_permissions(&path, permissions).expect("chmod script");
            Self { path }
        }
    }

    impl Drop for TempScript {
        fn drop(&mut self) {
            let _ = std::fs::remove_file(&self.path);
        }
    }

    fn test_pump(
        bytes_read: usize,
        bytes_written: usize,
        pending_write_bytes: usize,
        eof: bool,
        child_exited: bool,
    ) -> termio::TermioPump {
        termio::TermioPump {
            readiness: PtyReadiness::default(),
            bytes_read,
            eof,
            bytes_written,
            pending_write_bytes,
            child_exited,
        }
    }

    fn render_state_text(state: RoasttyRenderStateHandle) -> String {
        let iterator = new_render_state_row_iterator();
        bind_render_state_rows(state, iterator);
        let cells = new_render_state_row_cells();
        let mut text = String::new();

        while roastty_render_state_row_iterator_next(iterator) {
            bind_render_state_row_cells(iterator, cells);
            while roastty_render_state_row_cells_next(cells) {
                let mut bytes = [0u8; 8];
                let mut buffer = RoasttyBuffer {
                    ptr: bytes.as_mut_ptr(),
                    cap: bytes.len(),
                    len: 0,
                };
                assert_eq!(
                    roastty_render_state_row_cells_get(
                        cells,
                        ROASTTY_RENDER_STATE_ROW_CELLS_DATA_GRAPHEMES_UTF8,
                        &mut buffer as *mut _ as *mut c_void,
                    ),
                    ROASTTY_SUCCESS
                );
                if buffer.len > 0 {
                    text.push_str(std::str::from_utf8(&bytes[..buffer.len]).unwrap());
                }
            }
            text.push('\n');
        }

        roastty_render_state_row_cells_free(cells);
        roastty_render_state_row_iterator_free(iterator);
        text
    }

    fn surface_worker_selection(
        surface: RoasttySurface,
        start: (u16, u32),
        end: (u16, u32),
    ) -> RoasttyGridSelection {
        let surface = surface_from_handle(surface).unwrap();
        surface
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio(|termio| {
                let start = termio
                    .terminal()
                    .grid_ref(
                        TerminalPointTag::Screen,
                        point::Coordinate::new(start.0, start.1),
                    )
                    .unwrap();
                let end = termio
                    .terminal()
                    .grid_ref(
                        TerminalPointTag::Screen,
                        point::Coordinate::new(end.0, end.1),
                    )
                    .unwrap();
                let selection = TerminalSelection {
                    start,
                    end,
                    rectangle: false,
                };
                let mut out = RoasttyGridSelection::default();
                write_selection(&mut out, selection);
                out
            })
    }

    /// Build an embedded `roastty_selection_s` from SCREEN/EXACT `(x, y)` endpoints — the
    /// embedded equivalent of [`surface_worker_selection`] for the by-value `read_text`.
    fn embedded_screen_selection(start: (u16, u32), end: (u16, u32)) -> RoasttySelection {
        let point = |c: (u16, u32)| RoasttyPoint {
            tag: ROASTTY_POINT_SCREEN,
            coord: 0, // ROASTTY_POINT_COORD_EXACT
            x: c.0 as u32,
            y: c.1,
        };
        RoasttySelection {
            top_left: point(start),
            bottom_right: point(end),
            rectangle: false,
        }
    }

    fn set_surface_worker_active_selection(
        surface: RoasttySurface,
        selection: Option<RoasttyGridSelection>,
    ) {
        let selection = selection.map(|selection| read_selection(&selection).unwrap());
        let surface = surface_from_handle(surface).unwrap();
        surface
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio_mut(|termio| termio.terminal_mut().set_selection(selection).unwrap());
    }

    fn surface_selection_plain_text(surface: RoasttySurface) -> Option<String> {
        let surface = surface_from_handle(surface).unwrap();
        surface
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio(|termio| {
                let terminal = termio.terminal();
                let selection = terminal.active_selection()?;
                terminal
                    .selection_format(TerminalSelectionFormat::Plain, true, true, Some(selection))
                    .ok()
            })
    }

