    fn c_str_ptr_to_str(ptr: *const c_char) -> Option<String> {
        if ptr.is_null() {
            None
        } else {
            Some(unsafe { CStr::from_ptr(ptr) }.to_str().unwrap().to_string())
        }
    }

    fn key_press(key: key::Key, utf8: &[u8], unshifted_codepoint: u32, mods: c_int) -> KeyEvent {
        let mut event = key::KeyEvent::default();
        event.action = key::KeyAction::Press;
        event.key = key;
        event.utf8 = utf8.to_vec();
        event.unshifted_codepoint = unshifted_codepoint;
        event.mods = key_mods_from_raw(mods);
        KeyEvent { event }
    }

    fn key_release(key: key::Key, utf8: &[u8], unshifted_codepoint: u32, mods: c_int) -> KeyEvent {
        let mut event = key_press(key, utf8, unshifted_codepoint, mods);
        event.event.action = key::KeyAction::Release;
        event
    }

    fn input_key_press_x(mods: c_int) -> RoasttyInputKey {
        RoasttyInputKey {
            action: key_action_to_int(key::KeyAction::Press),
            mods,
            consumed_mods: ROASTTY_MODS_NONE,
            keycode: 0x0007,
            text: b"x\0".as_ptr().cast::<c_char>(),
            unshifted_codepoint: b'x' as u32,
            composing: false,
        }
    }

    fn send_key(surface: RoasttySurface, event: KeyEvent) -> bool {
        surface_from_handle(surface).unwrap().key(&event)
    }

    fn send_line(surface: RoasttySurface, key: key::Key, text: u8) {
        assert!(send_key(
            surface,
            key_press(key, &[text], u32::from(text), ROASTTY_MODS_NONE)
        ));
        assert!(send_key(
            surface,
            key_press(key::Key::Enter, &[], 0, ROASTTY_MODS_NONE)
        ));
    }

    fn wait_for_surface_plain_screen(app: RoasttyApp, surface: RoasttySurface, needle: &str) {
        wait_until(|| {
            roastty_app_tick(app);
            surface_from_handle(surface)
                .unwrap()
                .termio_worker
                .as_ref()
                .unwrap()
                .with_termio(|termio| termio.terminal().plain_screen(false).contains(needle))
        });
    }

    fn set_surface_worker_semantic_prompt(surface: RoasttySurface, options: &str, input: &str) {
        let prompt = if options.is_empty() {
            "\x1b]133;A\x07".to_string()
        } else {
            format!("\x1b]133;A;{options}\x07")
        };
        let bytes = format!("{prompt}> \x1b]133;B\x07{input}");
        surface_from_handle(surface)
            .unwrap()
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio_mut(|termio| {
                termio
                    .terminal_mut()
                    .next_slice(bytes.as_bytes())
                    .expect("write semantic prompt");
            });
    }

