    fn config_command_palette_entries(
        config: RoasttyConfig,
    ) -> Vec<(String, String, String, String)> {
        let mut list = RoasttyConfigCommandList {
            commands: ptr::null(),
            len: usize::MAX,
        };
        assert!(roastty_config_get(
            config,
            (&mut list as *mut RoasttyConfigCommandList).cast(),
            c"command-palette-entry".as_ptr(),
            "command-palette-entry".len()
        ));
        if list.len == 0 {
            return Vec::new();
        }
        assert!(!list.commands.is_null());
        unsafe { slice::from_raw_parts(list.commands, list.len) }
            .iter()
            .map(|command| {
                assert!(!command.action_key.is_null());
                assert!(!command.action.is_null());
                assert!(!command.title.is_null());
                assert!(!command.description.is_null());
                unsafe {
                    (
                        CStr::from_ptr(command.action_key)
                            .to_str()
                            .unwrap()
                            .to_string(),
                        CStr::from_ptr(command.action).to_str().unwrap().to_string(),
                        CStr::from_ptr(command.title).to_str().unwrap().to_string(),
                        CStr::from_ptr(command.description)
                            .to_str()
                            .unwrap()
                            .to_string(),
                    )
                }
            })
            .collect()
    }

    fn config_get_bool_value(config: RoasttyConfig, key: &'static CStr) -> bool {
        let mut value = false;
        assert!(roastty_config_get(
            config,
            (&mut value as *mut bool).cast(),
            key.as_ptr(),
            key.to_bytes().len()
        ));
        value
    }

    fn config_get_palette_value(config: RoasttyConfig) -> RoasttyPalette {
        let mut value = [RoasttyRgb::default(); 256];
        assert!(roastty_config_get(
            config,
            (&mut value as *mut RoasttyPalette).cast(),
            c"palette".as_ptr(),
            "palette".len()
        ));
        value
    }

    fn config_get_string_value(config: RoasttyConfig, key: &'static CStr) -> Option<String> {
        let mut value: *const c_char = ptr::null();
        if !roastty_config_get(
            config,
            (&mut value as *mut *const c_char).cast(),
            key.as_ptr(),
            key.to_bytes().len(),
        ) {
            return None;
        }
        if value.is_null() {
            return None;
        }
        Some(
            unsafe { CStr::from_ptr(value) }
                .to_str()
                .unwrap()
                .to_string(),
        )
    }

    fn config_get_path_value(config: RoasttyConfig, key: &'static CStr) -> Option<(String, bool)> {
        let mut value = RoasttyConfigPath {
            path: ptr::null(),
            optional: false,
        };
        if !roastty_config_get(
            config,
            (&mut value as *mut RoasttyConfigPath).cast(),
            key.as_ptr(),
            key.to_bytes().len(),
        ) {
            return None;
        }
        assert!(!value.path.is_null());
        Some((
            unsafe { CStr::from_ptr(value.path) }
                .to_str()
                .unwrap()
                .to_string(),
            value.optional,
        ))
    }

    #[test]
    fn config_get_macos_unit_test_scalar_keys() {
        let config = roastty_config_new();
        roastty_config_finalize(config);

        assert_eq!(
            config_get_string_value(config, c"auto-update-channel").as_deref(),
            Some("tip")
        );
        assert_eq!(
            config_get_string_value(config, c"window-title-font-family"),
            None
        );
        assert_eq!(
            config_get_string_value(config, c"macos-titlebar-style").as_deref(),
            Some("transparent")
        );
        assert_eq!(
            config_get_string_value(config, c"resize-overlay").as_deref(),
            Some("after-first")
        );
        assert_eq!(
            config_get_string_value(config, c"scrollbar").as_deref(),
            Some("system")
        );
        assert!(!config_get_bool_value(config, c"focus-follows-mouse"));
        assert!(!config_get_bool_value(config, c"maximize"));
        assert!(config_get_bool_value(config, c"macos-window-shadow"));

        {
            let config_ref = config_from_handle(config).unwrap();
            config_ref
                .parsed
                .set("focus-follows-mouse", Some("true"))
                .unwrap();
            config_ref.parsed.set("maximize", Some("true")).unwrap();
            config_ref
                .parsed
                .set("window-title-font-family", Some("Menlo"))
                .unwrap();
            config_ref
                .parsed
                .set("macos-titlebar-style", Some("tabs"))
                .unwrap();
            config_ref
                .parsed
                .set("macos-window-shadow", Some("false"))
                .unwrap();
            config_ref
                .parsed
                .set("resize-overlay", Some("never"))
                .unwrap();
            config_ref.parsed.set("scrollbar", Some("never")).unwrap();
            config_ref.sync_from_parsed_config();
        }

        assert!(config_get_bool_value(config, c"focus-follows-mouse"));
        assert!(config_get_bool_value(config, c"maximize"));
        assert_eq!(
            config_get_string_value(config, c"window-title-font-family").as_deref(),
            Some("Menlo")
        );
        assert_eq!(
            config_get_string_value(config, c"macos-titlebar-style").as_deref(),
            Some("tabs")
        );
        assert!(!config_get_bool_value(config, c"macos-window-shadow"));
        assert_eq!(
            config_get_string_value(config, c"resize-overlay").as_deref(),
            Some("never")
        );
        assert_eq!(
            config_get_string_value(config, c"scrollbar").as_deref(),
            Some("never")
        );

        roastty_config_free(config);
    }

    #[test]
    fn config_get_palette_default_set_generate_and_clone() {
        let config = roastty_config_new();
        let default_palette = config_get_palette_value(config);
        assert_eq!(
            default_palette[0],
            RoasttyRgb {
                r: 0x1d,
                g: 0x1f,
                b: 0x21
            }
        );
        assert!(!config_get_bool_value(config, c"palette-generate"));
        assert!(!config_get_bool_value(config, c"palette-harmonious"));

        {
            let config_ref = config_from_handle(config).unwrap();
            config_ref.parsed.set("palette", Some("0=#aabbcc")).unwrap();
            config_ref.parsed.set("palette", Some("1=#010203")).unwrap();
            config_ref
                .parsed
                .set("palette-generate", Some("true"))
                .unwrap();
            config_ref
                .parsed
                .set("palette-harmonious", Some("true"))
                .unwrap();
            config_ref.sync_from_parsed_config();
        }

        let raw_palette = config_get_palette_value(config);
        assert_eq!(
            raw_palette[0],
            RoasttyRgb {
                r: 0xaa,
                g: 0xbb,
                b: 0xcc
            }
        );
        assert_eq!(raw_palette[1], RoasttyRgb { r: 1, g: 2, b: 3 });
        assert_eq!(raw_palette[100], default_palette[100]);
        assert!(config_get_bool_value(config, c"palette-generate"));
        assert!(config_get_bool_value(config, c"palette-harmonious"));

        let clone = roastty_config_clone(config);
        roastty_config_free(config);
        assert_eq!(config_get_palette_value(clone), raw_palette);
        assert!(config_get_bool_value(clone, c"palette-generate"));
        assert!(config_get_bool_value(clone, c"palette-harmonious"));

        {
            let config_ref = config_from_handle(clone).unwrap();
            config_ref.parsed.set("palette", Some("")).unwrap();
            config_ref.parsed.set("palette-generate", Some("")).unwrap();
            config_ref
                .parsed
                .set("palette-harmonious", Some(""))
                .unwrap();
            config_ref.sync_from_parsed_config();
        }
        assert_eq!(config_get_palette_value(clone), default_palette);
        assert!(!config_get_bool_value(clone, c"palette-generate"));
        assert!(!config_get_bool_value(clone, c"palette-harmonious"));
        roastty_config_free(clone);
    }

    #[test]
    fn config_get_background_image_path_default_set_reset_and_clone() {
        let config = roastty_config_new();
        assert_eq!(config_get_path_value(config, c"background-image"), None);

        {
            let config_ref = config_from_handle(config).unwrap();
            config_ref
                .parsed
                .set("background-image", Some("backdrop.png"))
                .unwrap();
            config_ref.sync_from_parsed_config();
        }
        assert_eq!(
            config_get_path_value(config, c"background-image"),
            Some(("backdrop.png".to_string(), false))
        );

        {
            let config_ref = config_from_handle(config).unwrap();
            config_ref
                .parsed
                .set("background-image", Some("?optional.png"))
                .unwrap();
            config_ref.sync_from_parsed_config();
        }
        assert_eq!(
            config_get_path_value(config, c"background-image"),
            Some(("optional.png".to_string(), true))
        );

        let clone = roastty_config_clone(config);
        roastty_config_free(config);
        assert_eq!(
            config_get_path_value(clone, c"background-image"),
            Some(("optional.png".to_string(), true))
        );

        {
            let config_ref = config_from_handle(clone).unwrap();
            config_ref.parsed.set("background-image", Some("")).unwrap();
            config_ref.sync_from_parsed_config();
        }
        assert_eq!(config_get_path_value(clone, c"background-image"), None);
        roastty_config_free(clone);
    }

