    fn surface_binding_action(surface: RoasttySurface, action: &[u8]) -> bool {
        roastty_surface_binding_action(surface, action.as_ptr().cast::<c_char>(), action.len())
    }

    fn caught_panic_message(f: impl FnOnce()) -> String {
        let _guard = PANIC_HOOK_LOCK
            .lock()
            .unwrap_or_else(|poisoned| poisoned.into_inner());
        let previous_hook = std::panic::take_hook();
        std::panic::set_hook(Box::new(|_| {}));
        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(f));
        std::panic::set_hook(previous_hook);
        let payload = result.expect_err("expected panic");
        if let Some(message) = payload.downcast_ref::<&'static str>() {
            (*message).to_string()
        } else if let Some(message) = payload.downcast_ref::<String>() {
            message.clone()
        } else {
            "<non-string panic>".to_string()
        }
    }

    fn assert_unique_action_tags(tags: &[&str]) {
        for (index, tag) in tags.iter().enumerate() {
            assert!(
                !tags[..index].contains(tag),
                "duplicate action tag in coverage table: {tag}"
            );
        }
    }

