    #[test]
    fn config_trigger_reports_ordered_macos_default_bindings() {
        assert_default_unicode_trigger(b"open_config", b',' as u32, ROASTTY_MODS_SUPER);
        assert_default_unicode_trigger(
            b"reload_config",
            b',' as u32,
            ROASTTY_MODS_SHIFT | ROASTTY_MODS_SUPER,
        );
        assert_default_physical_trigger(
            b"copy_to_clipboard:mixed",
            key::Key::Copy,
            ROASTTY_MODS_NONE,
        );
        assert_default_physical_trigger(
            b"paste_from_clipboard",
            key::Key::Paste,
            ROASTTY_MODS_NONE,
        );
        for digit in b'1'..=b'8' {
            let action = format!("goto_tab:{}", digit - b'0');
            assert_default_unicode_trigger(action.as_bytes(), digit as u32, ROASTTY_MODS_SUPER);
        }
        assert_default_unicode_trigger(b"last_tab", b'9' as u32, ROASTTY_MODS_SUPER);
        assert_default_unicode_trigger(
            b"close_tab:this",
            b'w' as u32,
            ROASTTY_MODS_ALT | ROASTTY_MODS_SUPER,
        );
        assert_default_unicode_trigger(b"new_split:right", b'd' as u32, ROASTTY_MODS_SUPER);
        assert_default_unicode_trigger(
            b"new_split:down",
            b'd' as u32,
            ROASTTY_MODS_SHIFT | ROASTTY_MODS_SUPER,
        );
        assert_default_unicode_trigger(
            b"toggle_fullscreen",
            b'f' as u32,
            ROASTTY_MODS_CTRL | ROASTTY_MODS_SUPER,
        );
        assert_default_unicode_trigger(
            b"toggle_command_palette",
            b'p' as u32,
            ROASTTY_MODS_SHIFT | ROASTTY_MODS_SUPER,
        );
        assert_empty_trigger(default_config_trigger(b"start_search"));
        assert_empty_trigger(default_config_trigger(b"end_search"));
    }

    #[test]
    fn parse_config_binding_action_key_table_actions() {
        assert_eq!(
            canonical_config_binding_action(b"activate_key_table:copy").unwrap(),
            "activate_key_table:copy"
        );
        assert_eq!(
            canonical_config_binding_action(b"activate_key_table_once:copy").unwrap(),
            "activate_key_table_once:copy"
        );
        assert_eq!(
            canonical_config_binding_action(b"deactivate_key_table").unwrap(),
            "deactivate_key_table"
        );
        assert_eq!(
            canonical_config_binding_action(b"deactivate_all_key_tables").unwrap(),
            "deactivate_all_key_tables"
        );

        for action in [
            b"activate_key_table".as_slice(),
            b"activate_key_table:".as_slice(),
            b"activate_key_table:a/b".as_slice(),
            b"activate_key_table:a=b".as_slice(),
            b"activate_key_table:a+b".as_slice(),
            b"activate_key_table:a>b".as_slice(),
            b"deactivate_key_table:x".as_slice(),
            b"deactivate_all_key_tables:x".as_slice(),
        ] {
            assert!(canonical_config_binding_action(action).is_none());
        }
    }

