    #[test]
    fn configured_catch_all_binding_order_matches_upstream() {
        let bindings = vec![
            parse_config_keybind(b"catch_all=quit").unwrap(),
            parse_config_keybind(b"ctrl+catch_all=toggle_fullscreen").unwrap(),
            parse_config_keybind(b"ctrl+a=new_window").unwrap(),
        ];

        let ctrl_a = key_press(key::Key::KeyA, b"a", b'a' as u32, ROASTTY_MODS_CTRL);
        assert_eq!(
            configured_key_event_binding(&bindings, &ctrl_a.event)
                .unwrap()
                .first_action(),
            Some(b"new_window".as_slice())
        );

        let ctrl_b = key_press(key::Key::KeyB, b"b", b'b' as u32, ROASTTY_MODS_CTRL);
        assert_eq!(
            configured_key_event_binding(&bindings, &ctrl_b.event)
                .unwrap()
                .first_action(),
            Some(b"toggle_fullscreen".as_slice())
        );

        let alt_b = key_press(key::Key::KeyB, b"b", b'b' as u32, ROASTTY_MODS_ALT);
        assert_eq!(
            configured_key_event_binding(&bindings, &alt_b.event)
                .unwrap()
                .first_action(),
            Some(b"quit".as_slice())
        );

        let plain_b = key_press(key::Key::KeyB, b"b", b'b' as u32, ROASTTY_MODS_NONE);
        assert_eq!(
            configured_key_event_binding(&bindings, &plain_b.event)
                .unwrap()
                .first_action(),
            Some(b"quit".as_slice())
        );

        let mut release = plain_b.event.clone();
        release.action = key::KeyAction::Release;
        assert!(configured_key_event_binding(&bindings, &release).is_none());
    }

    fn expected_translation_mods(mods: c_int, option_as_alt: key_mods::OptionAsAlt) -> c_int {
        key_mods_to_raw(key_mods_from_raw(mods).translation(option_as_alt))
    }

    #[test]
    fn key_translation_mods_explicit_macos_option_as_alt_values() {
        for (configured, input, expected_policy) in [
            (
                key_mods::OptionAsAlt::False,
                ROASTTY_MODS_SHIFT | ROASTTY_MODS_ALT,
                key_mods::OptionAsAlt::False,
            ),
            (
                key_mods::OptionAsAlt::True,
                ROASTTY_MODS_SHIFT | ROASTTY_MODS_ALT,
                key_mods::OptionAsAlt::True,
            ),
            (
                key_mods::OptionAsAlt::Left,
                ROASTTY_MODS_ALT,
                key_mods::OptionAsAlt::Left,
            ),
            (
                key_mods::OptionAsAlt::Left,
                ROASTTY_MODS_ALT | ROASTTY_MODS_ALT_RIGHT,
                key_mods::OptionAsAlt::Left,
            ),
            (
                key_mods::OptionAsAlt::Right,
                ROASTTY_MODS_ALT,
                key_mods::OptionAsAlt::Right,
            ),
            (
                key_mods::OptionAsAlt::Right,
                ROASTTY_MODS_ALT | ROASTTY_MODS_ALT_RIGHT,
                key_mods::OptionAsAlt::Right,
            ),
        ] {
            let config = new_test_config_with_macos_option_as_alt(Some(configured));
            let app = roastty_app_new(ptr::null(), config);
            set_app_keyboard_layout_for_test(app, input_keyboard::Layout::UsStandard);
            let surface = new_test_surface(app);

            assert_eq!(
                roastty_surface_key_translation_mods(surface, input),
                expected_translation_mods(input, expected_policy)
            );

            roastty_surface_free(surface);
            roastty_app_free(app);
            roastty_config_free(config);
        }
    }

