    /// Issue 802 / Exp 28: a drag held past the top edge autoscrolls the viewport into history;
    /// it stops after the button releases.
    #[test]
    fn drag_autoscroll_scrolls_into_history() {
        let _guard = pty_command_lock();
        let app = new_test_app();
        let surface = new_test_surface(app);
        set_test_size_80x24(surface);
        surface_from_handle(surface).unwrap().termio_worker = Some(test_worker("sleep 5"));
        let mut content = String::new();
        for i in 0..40 {
            content.push_str(&format!("LINE{i:03}\r\n"));
        }
        surface_from_handle(surface)
            .unwrap()
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio_mut(|termio| {
                termio
                    .terminal_mut()
                    .next_slice(content.as_bytes())
                    .unwrap();
            });

        fn first_row_num(surface: RoasttySurface) -> i32 {
            let text: String = surface_from_handle(surface)
                .unwrap()
                .termio_worker
                .as_ref()
                .unwrap()
                .with_termio(|termio| {
                    termio
                        .terminal()
                        .shape_run_options()
                        .first()
                        .map(|row| {
                            row.cells
                                .iter()
                                .filter_map(|c| char::from_u32(c.codepoint))
                                .filter(|&ch| ch != '\0')
                                .collect()
                        })
                        .unwrap_or_default()
                });
            text.trim_start_matches("LINE").parse::<i32>().unwrap_or(-1)
        }

        let before = first_row_num(surface);
        assert!(
            before >= 0,
            "first row should be a numbered line, got {before}"
        );

        // Press inside the viewport, then drag up past the top edge → autoscroll Up.
        let s = surface_from_handle(surface).unwrap();
        s.mouse_pos(55.0, 110.0, 0); // cell (5,5)
        s.mouse_button(1, 1, 0); // press Left
        s.mouse_pos(55.0, -10.0, 0); // drag ABOVE the top edge → clamps + autoscroll Up

        // Tick (simulating the present loop) — scrolls up into history.
        for _ in 0..5 {
            surface_from_handle(surface)
                .unwrap()
                .selection_autoscroll_tick();
        }
        let after = first_row_num(surface);
        assert!(
            after >= 0 && after < before,
            "autoscroll should scroll the viewport UP into history; before={before} after={after}"
        );

        // Release → autoscroll stops; further ticks are no-ops.
        surface_from_handle(surface).unwrap().mouse_button(0, 1, 0); // release Left
        let at_release = first_row_num(surface);
        for _ in 0..3 {
            surface_from_handle(surface)
                .unwrap()
                .selection_autoscroll_tick();
        }
        assert_eq!(
            first_row_num(surface),
            at_release,
            "autoscroll must stop after the button releases"
        );

        roastty_surface_free(surface);
        roastty_app_free(app);
    }

    /// Issue 802 / Exp 30: shift-click extends the existing selection from its anchor. "0123456789…"
    /// — initial drag 2..5 = "2345"; a shift-click at col 9 (>500ms later) extends to 2..9.
    #[test]
    fn shift_click_extends_selection() {
        let _guard = pty_command_lock();
        let app = new_test_app();
        let surface = new_test_surface(app);
        set_test_size_80x24(surface);
        surface_from_handle(surface).unwrap().termio_worker = Some(test_worker("sleep 5"));
        surface_from_handle(surface)
            .unwrap()
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio_mut(|termio| {
                termio
                    .terminal_mut()
                    .next_slice(b"0123456789ABCDEF")
                    .unwrap();
            });

        // Initial selection 2..5 = "2345" (clock 0).
        SELECTION_TEST_CLOCK_NS.with(|c| c.set(Some(0)));
        let s = surface_from_handle(surface).unwrap();
        s.mouse_pos(25.0, 10.0, 0); // col 2
        s.mouse_button(1, 1, 0); // press (no shift)
        s.mouse_pos(59.0, 10.0, 0); // drag to col 5
        s.mouse_button(0, 1, 0); // release
        assert_eq!(
            selected_text(surface).as_deref(),
            Some("2345"),
            "initial selection"
        );

        // Shift-click at col 9, > 500ms later → extend from anchor (col 2) to col 9.
        SELECTION_TEST_CLOCK_NS.with(|c| c.set(Some(1_000_000_000)));
        let s = surface_from_handle(surface).unwrap();
        s.mouse_pos(99.0, 10.0, 0); // col 9
        s.mouse_button(1, 1, 1); // press WITH shift (mods bit 1<<0)
        assert_eq!(
            selected_text(surface).as_deref(),
            Some("23456789"),
            "shift-click should extend the selection to col 9"
        );

        SELECTION_TEST_CLOCK_NS.with(|c| c.set(None));
        roastty_surface_free(surface);
        roastty_app_free(app);
    }

    /// Issue 802 / Exp 30: a shift-click WITHIN the 500ms interval does NOT extend (it's treated as a
    /// potential multi-click increment, falling to the fresh `selection_press` path which clears).
    #[test]
    fn shift_click_within_interval_does_not_extend() {
        let _guard = pty_command_lock();
        let app = new_test_app();
        let surface = new_test_surface(app);
        set_test_size_80x24(surface);
        surface_from_handle(surface).unwrap().termio_worker = Some(test_worker("sleep 5"));
        surface_from_handle(surface)
            .unwrap()
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio_mut(|termio| {
                termio
                    .terminal_mut()
                    .next_slice(b"0123456789ABCDEF")
                    .unwrap();
            });

        SELECTION_TEST_CLOCK_NS.with(|c| c.set(Some(0)));
        let s = surface_from_handle(surface).unwrap();
        s.mouse_pos(25.0, 10.0, 0);
        s.mouse_button(1, 1, 0);
        s.mouse_pos(59.0, 10.0, 0);
        s.mouse_button(0, 1, 0);
        assert_eq!(
            selected_text(surface).as_deref(),
            Some("2345"),
            "initial selection"
        );

        // Shift-click WITHIN 500ms (0.1s) of the press → NOT an extend → fresh single Cell press clears.
        SELECTION_TEST_CLOCK_NS.with(|c| c.set(Some(100_000_000)));
        let s = surface_from_handle(surface).unwrap();
        s.mouse_pos(99.0, 10.0, 0);
        s.mouse_button(1, 1, 1); // shift, but within interval
                                 // Not an extend: falls to the fresh `selection_press` path, which (a single Cell press at a
                                 // distance from the anchor) resets + clears the selection.
        assert_ne!(
            selected_text(surface).as_deref(),
            Some("23456789"),
            "a within-interval shift-click must not extend"
        );
        assert_eq!(
            selected_text(surface).as_deref(),
            None,
            "a within-interval shift-click clears (fresh press), not extends"
        );

        SELECTION_TEST_CLOCK_NS.with(|c| c.set(None));
        roastty_surface_free(surface);
        roastty_app_free(app);
    }

    /// Issue 802 / Exp 32: while mouse-reporting, ANY button + press/release clears the selection
    /// (not just Left+Press), matching upstream — so a stale selection can't linger.
    #[test]
    fn reporting_clear_widens_to_any_button() {
        let _guard = pty_command_lock();
        let app = new_test_app();
        let surface = new_test_surface(app);
        set_test_size_80x24(surface);
        surface_from_handle(surface).unwrap().termio_worker = Some(test_worker("sleep 5"));
        // Enter mouse-reporting mode (so `mouse_report_context()` is `Some`) + some text.
        surface_from_handle(surface)
            .unwrap()
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio_mut(|termio| {
                termio
                    .terminal_mut()
                    .next_slice(b"\x1b[?1000h0123456789")
                    .unwrap();
            });

        let has_selection = |surface: RoasttySurface| -> bool {
            surface_from_handle(surface)
                .unwrap()
                .termio_worker
                .as_ref()
                .unwrap()
                .with_termio(|termio| termio.terminal().active_selection().is_some())
        };
        let set_sel = |surface: RoasttySurface| {
            let sel = surface_worker_selection(surface, (0, 0), (3, 0));
            set_surface_worker_active_selection(surface, Some(sel));
        };

        // (a) a NON-Left (Right = 2) press while reporting clears.
        set_sel(surface);
        assert!(has_selection(surface), "selection was set");
        surface_from_handle(surface).unwrap().mouse_button(1, 2, 0); // Press, Right
        assert!(
            !has_selection(surface),
            "non-Left press while reporting must clear"
        );

        // (b) a Left RELEASE while reporting clears (pre-fix it did not).
        set_sel(surface);
        surface_from_handle(surface).unwrap().mouse_button(0, 1, 0); // Release, Left
        assert!(
            !has_selection(surface),
            "Left release while reporting must clear"
        );

        // (c) control: Left press while reporting still clears (unchanged).
        set_sel(surface);
        surface_from_handle(surface).unwrap().mouse_button(1, 1, 0); // Press, Left
        assert!(
            !has_selection(surface),
            "Left press while reporting still clears"
        );

        roastty_surface_free(surface);
        roastty_app_free(app);
    }

    /// Issue 802 / Exp 35: a content-scale (DPI) change drops the live renderer (so `present_live`
    /// rebuilds it at the new scale) and requests a present; an idempotent same-scale call is a no-op.
    #[test]
    fn content_scale_change_drops_renderer_for_rebuild() {
        let _guard = pty_command_lock();
        let app = new_test_app();
        let surface = new_test_surface(app);
        surface_from_handle(surface).unwrap().dirty = false;

        // A real change from the default 1.0 → renderer dropped + a present (rebuild) requested.
        roastty_surface_set_content_scale(surface, 2.0, 2.0);
        {
            let s = surface_from_handle(surface).unwrap();
            assert_eq!(s.scale_factor_x, 2.0);
            assert_eq!(s.scale_factor_y, 2.0);
            assert!(s.dirty, "a DPI change requests a present (rebuild)");
            assert!(
                s.renderer.is_none(),
                "the renderer is dropped (None headless anyway)"
            );
            s.dirty = false;
        }

        // Same scale again → no spurious rebuild/present.
        roastty_surface_set_content_scale(surface, 2.0, 2.0);
        assert!(
            !surface_from_handle(surface).unwrap().dirty,
            "an idempotent set_content_scale must not churn the renderer"
        );

        roastty_surface_free(surface);
        roastty_app_free(app);
    }

    /// Issue 802 / Exp 34: `mouse_shift_capture()` honors the `mouse-shift-capture` config
    /// (Never/Always decide outright; False/True fall through to the XTSHIFTESCAPE flag, else the
    /// config default).
    #[test]
    fn mouse_shift_capture_honors_config() {
        let _guard = pty_command_lock();
        let app = new_test_app();
        let surface = new_test_surface(app);
        roastty_surface_set_size(surface, 800, 480);
        surface_from_handle(surface).unwrap().termio_worker = Some(test_worker("sleep 5"));

        let set_config = |v: config::MouseShiftCapture| {
            app_from_handle(app).unwrap().mouse_shift_capture = v;
        };
        let capture =
            |surface: RoasttySurface| surface_from_handle(surface).unwrap().mouse_shift_capture();

        // No XTSHIFTESCAPE flag yet → config decides.
        set_config(config::MouseShiftCapture::Never);
        assert!(!capture(surface), "Never → not captured (shift overrides)");
        set_config(config::MouseShiftCapture::Always);
        assert!(
            capture(surface),
            "Always → captured (shift does not override)"
        );
        set_config(config::MouseShiftCapture::False);
        assert!(!capture(surface), "False default + no flag → not captured");
        set_config(config::MouseShiftCapture::True);
        assert!(capture(surface), "True default + no flag → captured");

        // Feed XTSHIFTESCAPE `CSI > 1 s` → flag Some(true): wins for False/True, ignored by Never/Always.
        surface_from_handle(surface)
            .unwrap()
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio_mut(|t| {
                t.terminal_mut().next_slice(b"\x1b[>1s").unwrap();
            });
        set_config(config::MouseShiftCapture::False);
        assert!(
            capture(surface),
            "False + flag Some(true) → captured (flag wins)"
        );
        set_config(config::MouseShiftCapture::Never);
        assert!(!capture(surface), "Never ignores the flag");
        set_config(config::MouseShiftCapture::Always);
        assert!(capture(surface), "Always ignores the flag");

        roastty_surface_free(surface);
        roastty_app_free(app);
    }

    /// Issue 802 / Exp 33: shift overrides mouse-reporting for selection (shift-drag selects in a
    /// mouse-mode TUI + suppresses the report); bare shift-motion still reports; XTSHIFTESCAPE
    /// disables the override.
    #[test]
    fn shift_overrides_mouse_reporting_for_selection() {
        let _guard = pty_command_lock();
        let app = new_test_app();
        let surface = new_test_surface(app);
        roastty_surface_set_size(surface, 800, 480);
        surface_from_handle(surface).unwrap().termio_worker = Some(test_worker("sleep 5"));
        surface_from_handle(surface)
            .unwrap()
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio_mut(|t| {
                t.terminal_mut().next_slice(b"0123456789ABCDEF").unwrap();
            });
        set_surface_worker_mouse_mode(surface, 1000, true); // mouse-reporting on

        let has_sel = |surface: RoasttySurface| -> bool {
            surface_from_handle(surface)
                .unwrap()
                .termio_worker
                .as_ref()
                .unwrap()
                .with_termio(|t| t.terminal().active_selection().is_some())
        };
        let reported = |surface: RoasttySurface| -> bool {
            surface_from_handle(surface)
                .unwrap()
                .mouse
                .last_reported_cell
                .is_some()
        };
        let reset = |surface: RoasttySurface| {
            let s = surface_from_handle(surface).unwrap();
            s.mouse.last_reported_cell = None;
            s.mouse.buttons.fill(None); // clear stale button state between cases
            s.termio_worker.as_ref().unwrap().with_termio_mut(|t| {
                let _ = t.terminal_mut().set_selection(None);
            });
        };

        // (1) shift-drag while reporting → selection; press/drag/release suppress the report.
        roastty_surface_mouse_pos(surface, 25.0, 10.0, ROASTTY_MODS_SHIFT); // pos cell 2 (bare motion reports)
        reset(surface); // clear that bare-motion report before the press
        roastty_surface_mouse_button(
            surface,
            ROASTTY_MOUSE_BUTTON_PRESS,
            ROASTTY_MOUSE_BUTTON_LEFT,
            ROASTTY_MODS_SHIFT,
        );
        roastty_surface_mouse_pos(surface, 59.0, 10.0, ROASTTY_MODS_SHIFT); // drag to cell 5
        roastty_surface_mouse_button(
            surface,
            ROASTTY_MOUSE_BUTTON_RELEASE,
            ROASTTY_MOUSE_BUTTON_LEFT,
            ROASTTY_MODS_SHIFT,
        );
        assert!(has_sel(surface), "shift-drag while reporting must select");
        assert!(
            !reported(surface),
            "shift-override press/drag/release suppress the report"
        );

        // (a) no-shift press while reporting → no selection (the clear path runs).
        reset(surface);
        roastty_surface_mouse_pos(surface, 25.0, 10.0, ROASTTY_MODS_NONE);
        roastty_surface_mouse_button(
            surface,
            ROASTTY_MOUSE_BUTTON_PRESS,
            ROASTTY_MOUSE_BUTTON_LEFT,
            ROASTTY_MODS_NONE,
        );
        assert!(
            !has_sel(surface),
            "no-shift press while reporting must not select"
        );

        // (c) mode 1003, shift, NO button → bare motion still reports (the button-gated suppression).
        set_surface_worker_mouse_mode(surface, 1003, true);
        reset(surface);
        roastty_surface_mouse_pos(surface, 35.0, 30.0, ROASTTY_MODS_SHIFT);
        assert!(
            reported(surface),
            "bare shift-motion in mode 1003 must still report"
        );

        // (b) XTSHIFTESCAPE (CSI > 1 s) → shift does NOT override (program captures shift).
        reset(surface);
        surface_from_handle(surface)
            .unwrap()
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio_mut(|t| {
                t.terminal_mut().next_slice(b"\x1b[>1s").unwrap();
            });
        roastty_surface_mouse_pos(surface, 25.0, 10.0, ROASTTY_MODS_SHIFT);
        roastty_surface_mouse_button(
            surface,
            ROASTTY_MOUSE_BUTTON_PRESS,
            ROASTTY_MOUSE_BUTTON_LEFT,
            ROASTTY_MODS_SHIFT,
        );
        roastty_surface_mouse_pos(surface, 59.0, 10.0, ROASTTY_MODS_SHIFT);
        roastty_surface_mouse_button(
            surface,
            ROASTTY_MOUSE_BUTTON_RELEASE,
            ROASTTY_MOUSE_BUTTON_LEFT,
            ROASTTY_MODS_SHIFT,
        );
        assert!(
            !has_sel(surface),
            "shift must not override when XTSHIFTESCAPE captures it"
        );

        roastty_surface_free(surface);
        roastty_app_free(app);
    }

    /// Issue 802 / Exp 23: the mouse wheel must navigate scrollback in a plain (non-mouse-
    /// reporting) shell. Two bugs were fixed:  never touched the viewport (only
    /// emitted mouse reports), and the render read-path read the active bottom, not the viewport.
    /// Asserts through  (what  feeds): scroll-up reveals history.
    #[test]
    fn mouse_scroll_navigates_scrollback() {
        let _guard = pty_command_lock();
        let app = new_test_app();
        let surface = new_test_surface(app);
        surface_from_handle(surface).unwrap().termio_worker = Some(test_worker("sleep 5"));

        let mut content = String::from(
            "TOPMARKER
",
        );
        for _ in 0..200 {
            content.push_str(
                "filler
",
            );
        }
        content.push_str(
            "BOTMARKER
",
        );
        surface_from_handle(surface)
            .unwrap()
            .termio_worker
            .as_ref()
            .unwrap()
            .with_termio_mut(|termio| {
                termio
                    .terminal_mut()
                    .next_slice(content.as_bytes())
                    .unwrap();
            });

        let rendered = |surface: RoasttySurface| -> String {
            surface_from_handle(surface)
                .unwrap()
                .termio_worker
                .as_ref()
                .unwrap()
                .with_termio(|termio| {
                    termio
                        .terminal()
                        .shape_run_options()
                        .iter()
                        .flat_map(|row| row.cells.iter())
                        .filter_map(|cell| char::from_u32(cell.codepoint))
                        .filter(|&ch| ch != '␀')
                        .collect()
                })
        };

        // Active viewport shows the tail; TOPMARKER is in scrollback.
        let bottom = rendered(surface);
        assert!(
            bottom.contains("BOTMARKER"),
            "tail should show BOTMARKER; got {bottom:?}"
        );
        assert!(
            !bottom.contains("TOPMARKER"),
            "TOPMARKER should be off-screen in scrollback; got {bottom:?}"
        );

        // Wheel scroll up (positive y → toward history) reveals the top of scrollback.
        surface_from_handle(surface)
            .unwrap()
            .mouse_scroll(0.0, 1000.0, 0);
        let scrolled = rendered(surface);
        assert!(
            scrolled.contains("TOPMARKER"),
            "scroll-up must reveal scrollback history (Exp 23); got {scrolled:?}"
        );

        // Wheel scroll down returns toward the tail (BOTMARKER on-screen again).
        surface_from_handle(surface)
            .unwrap()
            .mouse_scroll(0.0, -1000.0, 0);
        let back = rendered(surface);
        assert!(
            back.contains("BOTMARKER"),
            "scroll-down should return to the tail; got {back:?}"
        );

        roastty_surface_free(surface);
        roastty_app_free(app);
    }

