    #[test]
    fn target_abi_layout_and_action_tags_match_upstream() {
        use core::mem::{align_of, offset_of, size_of};
        // roastty_target_s {tag, target_u target} — byte-identical to the old flat {tag, surface}.
        assert_eq!(size_of::<RoasttyTarget>(), 16);
        assert_eq!(align_of::<RoasttyTarget>(), 8);
        assert_eq!(offset_of!(RoasttyTarget, tag), 0);
        assert_eq!(offset_of!(RoasttyTarget, target), 8);
        assert_eq!(size_of::<RoasttyTargetU>(), 8);
        // All 24 filled-in action tags equal their upstream positions.
        assert_eq!(ROASTTY_ACTION_PRESENT_TERMINAL, 21);
        assert_eq!(ROASTTY_ACTION_SIZE_LIMIT, 22);
        assert_eq!(ROASTTY_ACTION_INITIAL_SIZE, 24);
        assert_eq!(ROASTTY_ACTION_CELL_SIZE, 25);
        assert_eq!(ROASTTY_ACTION_SCROLLBAR, 26);
        assert_eq!(ROASTTY_ACTION_RENDER, 27);
        assert_eq!(ROASTTY_ACTION_RENDER_INSPECTOR, 30);
        assert_eq!(ROASTTY_ACTION_DESKTOP_NOTIFICATION, 31);
        assert_eq!(ROASTTY_ACTION_PWD, 35);
        assert_eq!(ROASTTY_ACTION_MOUSE_SHAPE, 36);
        assert_eq!(ROASTTY_ACTION_MOUSE_VISIBILITY, 37);
        assert_eq!(ROASTTY_ACTION_MOUSE_OVER_LINK, 38);
        assert_eq!(ROASTTY_ACTION_RENDERER_HEALTH, 39);
        assert_eq!(ROASTTY_ACTION_QUIT_TIMER, 41);
        assert_eq!(ROASTTY_ACTION_KEY_SEQUENCE, 44);
        assert_eq!(ROASTTY_ACTION_KEY_TABLE, 45);
        assert_eq!(ROASTTY_ACTION_COLOR_CHANGE, 46);
        assert_eq!(ROASTTY_ACTION_CONFIG_CHANGE, 48);
        assert_eq!(ROASTTY_ACTION_RING_BELL, 50);
        assert_eq!(ROASTTY_ACTION_SHOW_CHILD_EXITED, 55);
        assert_eq!(ROASTTY_ACTION_PROGRESS_REPORT, 56);
        assert_eq!(ROASTTY_ACTION_COMMAND_FINISHED, 58);
        assert_eq!(ROASTTY_ACTION_SEARCH_TOTAL, 61);
        assert_eq!(ROASTTY_ACTION_SEARCH_SELECTED, 62);
    }

    #[test]
    fn action_abi_layout_and_roundtrip() {
        use core::mem::{align_of, offset_of, size_of};
        // roastty_action_s / _u byte-faithful to upstream (s=32/align 8, u=24).
        assert_eq!(size_of::<RoasttyAction>(), 32);
        assert_eq!(align_of::<RoasttyAction>(), 8);
        assert_eq!(offset_of!(RoasttyAction, tag), 0);
        assert_eq!(offset_of!(RoasttyAction, action), 8);
        assert_eq!(size_of::<RoasttyActionU>(), 24);
        assert_eq!(align_of::<RoasttyActionU>(), 8);
        // open_url_s { c_int kind; const char* url; uintptr_t len } = 24, padded.
        assert_eq!(size_of::<RoasttyActionOpenUrl>(), 24);
        assert_eq!(offset_of!(RoasttyActionOpenUrl, kind), 0);
        assert_eq!(offset_of!(RoasttyActionOpenUrl, url), 8);
        assert_eq!(offset_of!(RoasttyActionOpenUrl, len), 16);
        // resize_split_s { uint16_t amount; e direction } = 8 (2 + 2 pad + 4).
        assert_eq!(size_of::<RoasttyActionResizeSplit>(), 8);
        assert_eq!(offset_of!(RoasttyActionResizeSplit, direction), 4);
        // storage -> union -> storage round-trips per tag (exercises the conversion).
        let rt = |tag, slots: &[usize]| {
            let mut s = [0usize; 8];
            s[..slots.len()].copy_from_slice(slots);
            action_u_to_storage(tag, &action_u_from_storage(tag, s))
        };
        assert_eq!(rt(ROASTTY_ACTION_READONLY, &[1])[0], 1);
        assert_eq!(
            &rt(ROASTTY_ACTION_OPEN_URL, &[2, 0xABCD, 7])[..3],
            &[2, 0xABCD, 7]
        );
        assert_eq!(
            rt(ROASTTY_ACTION_MOVE_TAB, &[(-3isize) as usize])[0],
            (-3isize) as usize
        );
        assert_eq!(&rt(ROASTTY_ACTION_RESIZE_SPLIT, &[5, 1])[..2], &[5, 1]);
        assert_eq!(rt(ROASTTY_ACTION_SET_TITLE, &[0x9999])[0], 0x9999);
    }

    #[test]
    fn input_key_abi_layout_matches_upstream() {
        // roastty_input_key_s must be byte-faithful to ghostty_input_key_s.
        use core::mem::{align_of, offset_of, size_of};
        assert_eq!(size_of::<RoasttyInputKey>(), 32);
        assert_eq!(align_of::<RoasttyInputKey>(), 8);
        assert_eq!(offset_of!(RoasttyInputKey, action), 0);
        assert_eq!(offset_of!(RoasttyInputKey, mods), 4);
        assert_eq!(offset_of!(RoasttyInputKey, consumed_mods), 8);
        assert_eq!(offset_of!(RoasttyInputKey, keycode), 12);
        assert_eq!(offset_of!(RoasttyInputKey, text), 16);
        assert_eq!(offset_of!(RoasttyInputKey, unshifted_codepoint), 24);
        assert_eq!(offset_of!(RoasttyInputKey, composing), 28);
        // enum values match upstream (RELEASE=0, PRESS=1, REPEAT=2).
        assert_eq!(key_action_to_int(key::KeyAction::Release), 0);
        assert_eq!(key_action_to_int(key::KeyAction::Press), 1);
        assert_eq!(key_action_to_int(key::KeyAction::Repeat), 2);
        // by-value construction round-trips through the internal event.
        let ik = RoasttyInputKey {
            action: 1,
            mods: 0,
            consumed_mods: 0,
            keycode: 0,
            text: core::ptr::null(),
            unshifted_codepoint: 0,
            composing: false,
        };
        let ev = input_key_to_event(&ik);
        assert_eq!(ev.event.action, key::KeyAction::Press);
        assert!(ev.event.utf8.is_empty());
        // keycode is the NATIVE macOS keyCode: 0x00 = A, 0x35 = Escape (not a Key index).
        assert_eq!(ev.event.key, key::Key::KeyA);
        assert_eq!(
            input_key_to_event(&RoasttyInputKey {
                keycode: 0x35,
                ..ik
            })
            .event
            .key,
            key::Key::Escape
        );
    }

