    #[test]
    fn surface_key_default_performable_action_consumes_when_performed() {
        let app = new_test_app_with_action(true);
        let surface = new_test_surface(app);
        let event = new_key_event();

        set_key_event(
            event,
            key::KeyAction::Press,
            key::Key::Escape,
            ROASTTY_MODS_NONE,
            &[],
            0,
        );
        assert!(roastty_surface_key_handle(surface, event));
        let records = action_records();
        assert_eq!(records.len(), 1);
        assert_eq!(records[0].action_tag, ROASTTY_ACTION_END_SEARCH);

        set_key_event(
            event,
            key::KeyAction::Press,
            key::Key::KeyG,
            ROASTTY_MODS_SUPER,
            b"g",
            0,
        );
        assert!(roastty_surface_key_handle(surface, event));

        set_key_event(
            event,
            key::KeyAction::Release,
            key::Key::KeyG,
            ROASTTY_MODS_SUPER,
            &[],
            0,
        );
        assert!(roastty_surface_key_handle(surface, event));

        set_key_event(
            event,
            key::KeyAction::Press,
            key::Key::KeyG,
            ROASTTY_MODS_SHIFT | ROASTTY_MODS_SUPER,
            b"g",
            0,
        );
        assert!(roastty_surface_key_handle(surface, event));

        let records = action_records();
        assert_eq!(records.len(), 3);
        assert_eq!(records[1].action_tag, ROASTTY_ACTION_NAVIGATE_SEARCH);
        assert_eq!(records[1].storage[0], ROASTTY_NAVIGATE_SEARCH_NEXT as usize);
        assert!(records[1].storage[1..].iter().all(|value| *value == 0));
        assert_eq!(records[2].action_tag, ROASTTY_ACTION_NAVIGATE_SEARCH);
        assert_eq!(
            records[2].storage[0],
            ROASTTY_NAVIGATE_SEARCH_PREVIOUS as usize
        );
        assert!(records[2].storage[1..].iter().all(|value| *value == 0));

        roastty_key_event_free(event);
        roastty_surface_free(surface);
        roastty_app_free(app);
    }

    #[test]
    fn surface_key_default_performable_action_falls_through_when_unperformed() {
        let _guard = pty_command_lock();
        let app = new_test_app_with_action(true);
        // `cat -v` renders each received byte (here ESC[1;2D -> "^[[1;2D") as the
        // child's own deterministic output, so the assert no longer depends on the
        // racy pre-`stty -echo` terminal echo that the old `dd count=8 | od` child
        // forced (count=8 blocked on the 6-byte sequence; Issue 801, Exp 836).
        let command = CString::new("stty -echo -icanon min 1 time 0; cat -v").unwrap();
        let mut config = roastty_surface_config_new();
        config.command = command.as_ptr();
        let surface = new_test_surface_with_config(app, &config);
        let event = new_key_event();

        set_key_event(
            event,
            key::KeyAction::Press,
            key::Key::KeyD,
            ROASTTY_MODS_SUPER,
            b"d",
            0,
        );
        assert!(roastty_surface_key_handle(surface, event));

        set_key_event(
            event,
            key::KeyAction::Press,
            key::Key::ArrowLeft,
            ROASTTY_MODS_SHIFT,
            &[],
            0,
        );
        assert_eq!(roastty_surface_start(surface), ROASTTY_SUCCESS);
        assert!(roastty_surface_key_handle(surface, event));
        let text = surface_snapshot_text_until(app, surface, "^[[1;2D");
        assert!(
            text.contains("^[[1;2D") || text.contains("^[[D"),
            "{text:?}"
        );

        set_key_event(
            event,
            key::KeyAction::Release,
            key::Key::KeyD,
            ROASTTY_MODS_SUPER,
            &[],
            0,
        );
        assert!(!roastty_surface_key_handle(surface, event));

        roastty_key_event_free(event);
        roastty_surface_free(surface);
        roastty_app_free(app);
    }

