    #[test]
    fn surface_key_is_binding_zeroes_flags_tolerates_null_flags_and_returns_false() {
        let app = new_test_app();
        let surface = new_test_surface(app);
        let event = new_key_event();
        let mut flags = 0xffu8;

        assert!(!roastty_surface_key_is_binding_handle(
            surface,
            ptr::null_mut(),
            &mut flags
        ));
        assert_eq!(flags, 0);
        assert!(!roastty_surface_key_is_binding_handle(
            surface,
            event,
            ptr::null_mut()
        ));
        flags = 0xff;
        assert!(!roastty_surface_key_is_binding_handle(
            surface, event, &mut flags
        ));
        assert_eq!(flags, 0);

        set_key_event(
            event,
            key::KeyAction::Press,
            key::Key::Unidentified,
            ROASTTY_MODS_SUPER,
            b"c",
            0,
        );
        assert!(roastty_surface_key_is_binding_handle(
            surface,
            event,
            ptr::null_mut()
        ));

        set_key_event(
            event,
            key::KeyAction::Release,
            key::Key::Copy,
            ROASTTY_MODS_NONE,
            &[],
            0,
        );
        flags = 0xff;
        assert!(!roastty_surface_key_is_binding_handle(
            surface, event, &mut flags
        ));
        assert_eq!(flags, 0);

        set_key_event(
            event,
            key::KeyAction::Press,
            key::Key::Unidentified,
            ROASTTY_MODS_CTRL,
            b"c",
            0,
        );
        flags = 0xff;
        assert!(!roastty_surface_key_is_binding_handle(
            surface, event, &mut flags
        ));
        assert_eq!(flags, 0);

        roastty_key_event_free(event);
        roastty_surface_free(surface);
        roastty_app_free(app);
    }

