    #[test]
    fn keybind_trigger_abi_layout_and_empty_values_are_stable() {
        assert_eq!(
            std::mem::size_of::<RoasttyInputTrigger>(),
            std::mem::size_of::<c_int>() * 3
        );
        assert_eq!(std::mem::offset_of!(RoasttyInputTrigger, tag), 0);
        assert_eq!(
            std::mem::offset_of!(RoasttyInputTrigger, key),
            std::mem::size_of::<c_int>()
        );
        assert_eq!(
            std::mem::offset_of!(RoasttyInputTrigger, mods),
            std::mem::size_of::<c_int>() * 2
        );

        let trigger = empty_trigger();
        assert_eq!(trigger.tag, ROASTTY_TRIGGER_PHYSICAL);
        assert_eq!(
            unsafe { trigger.key.physical },
            key::Key::Unidentified as c_int
        );
        assert_eq!(trigger.mods, ROASTTY_MODS_NONE);
    }

    fn assert_empty_config_trigger(trigger: RoasttyInputTrigger) {
        assert_eq!(trigger.tag, ROASTTY_TRIGGER_PHYSICAL);
        assert_eq!(
            unsafe { trigger.key.physical },
            key::Key::Unidentified as c_int
        );
        assert_eq!(trigger.mods, ROASTTY_MODS_NONE);
    }

    fn assert_physical_config_trigger(trigger: RoasttyInputTrigger, key: key::Key, mods: c_int) {
        assert_eq!(trigger.tag, ROASTTY_TRIGGER_PHYSICAL);
        assert_eq!(unsafe { trigger.key.physical }, key as c_int);
        assert_eq!(trigger.mods, mods);
    }

    fn assert_unicode_config_trigger(trigger: RoasttyInputTrigger, codepoint: u32, mods: c_int) {
        assert_eq!(trigger.tag, ROASTTY_TRIGGER_UNICODE);
        assert_eq!(unsafe { trigger.key.unicode }, codepoint);
        assert_eq!(trigger.mods, mods);
    }

    fn assert_default_binding_action(
        event: KeyEvent,
        action: &[u8],
        flags: u8,
    ) -> DefaultBindingMatch {
        let binding = default_key_event_binding(&event.event).expect("default binding");
        assert_eq!(binding.action, Some(action));
        assert_eq!(binding.flags, flags);
        binding
    }

    fn config_diagnostic_message(config: RoasttyConfig, index: u32) -> String {
        let diagnostic = roastty_config_get_diagnostic(config, index);
        assert!(!diagnostic.message.is_null());
        unsafe { CStr::from_ptr(diagnostic.message) }
            .to_string_lossy()
            .into_owned()
    }

    fn config_get_string(config: RoasttyConfig, key: &str) -> Option<String> {
        let mut value: *const c_char = ptr::null();
        let ok = roastty_config_get(
            config,
            (&mut value as *mut *const c_char).cast::<c_void>(),
            key.as_ptr().cast(),
            key.len(),
        );
        if !ok {
            return None;
        }
        if value.is_null() {
            return Some(String::new());
        }
        Some(
            unsafe { CStr::from_ptr(value) }
                .to_string_lossy()
                .into_owned(),
        )
    }

    fn config_get_optional_string_ptr(config: RoasttyConfig, key: &str) -> Option<*const c_char> {
        let mut value: *const c_char = ptr::null();
        let ok = roastty_config_get(
            config,
            (&mut value as *mut *const c_char).cast::<c_void>(),
            key.as_ptr().cast(),
            key.len(),
        );
        ok.then_some(value)
    }

    fn config_get_optional_string(config: RoasttyConfig, key: &str) -> Option<Option<String>> {
        let value = config_get_optional_string_ptr(config, key)?;
        if value.is_null() {
            return Some(None);
        }
        Some(Some(
            unsafe { CStr::from_ptr(value) }
                .to_string_lossy()
                .into_owned(),
        ))
    }

    fn config_get_bool(config: RoasttyConfig, key: &str) -> Option<bool> {
        let mut value = false;
        let ok = roastty_config_get(
            config,
            (&mut value as *mut bool).cast::<c_void>(),
            key.as_ptr().cast(),
            key.len(),
        );
        ok.then_some(value)
    }

    fn config_get_f64(config: RoasttyConfig, key: &str) -> Option<f64> {
        let mut value = 0.0;
        let ok = roastty_config_get(
            config,
            (&mut value as *mut f64).cast::<c_void>(),
            key.as_ptr().cast(),
            key.len(),
        );
        ok.then_some(value)
    }

    fn config_get_usize(config: RoasttyConfig, key: &str) -> Option<usize> {
        let mut value = 0usize;
        let ok = roastty_config_get(
            config,
            (&mut value as *mut usize).cast::<c_void>(),
            key.as_ptr().cast(),
            key.len(),
        );
        ok.then_some(value)
    }

    fn config_get_c_short(config: RoasttyConfig, key: &str, initial: c_short) -> (bool, c_short) {
        let mut value = initial;
        let ok = roastty_config_get(
            config,
            (&mut value as *mut c_short).cast::<c_void>(),
            key.as_ptr().cast(),
            key.len(),
        );
        (ok, value)
    }

    fn config_get_path(
        config: RoasttyConfig,
        key: &str,
        initial: RoasttyConfigPath,
    ) -> (bool, RoasttyConfigPath) {
        let mut value = initial;
        let ok = roastty_config_get(
            config,
            (&mut value as *mut RoasttyConfigPath).cast::<c_void>(),
            key.as_ptr().cast(),
            key.len(),
        );
        (ok, value)
    }

    fn unique_config_abi_test_dir(tag: &str) -> PathBuf {
        let nanos = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_nanos();
        std::env::temp_dir().join(format!(
            "roastty-config-abi-{tag}-{}-{nanos}",
            std::process::id()
        ))
    }

    fn write_config_file(path: &std::path::Path, text: &str) {
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent).unwrap();
        }
        std::fs::write(path, text).unwrap();
    }

    fn c_path(path: &std::path::Path) -> CString {
        CString::new(path.as_os_str().as_bytes()).unwrap()
    }

    fn with_init_args(args: &[&str], f: impl FnOnce()) {
        let _guard = CLI_ARGS_LOCK.lock().unwrap();
        let strings = args
            .iter()
            .map(|arg| CString::new(*arg).unwrap())
            .collect::<Vec<_>>();
        let mut ptrs = strings
            .iter()
            .map(|arg| arg.as_ptr().cast_mut())
            .collect::<Vec<_>>();
        assert_eq!(roastty_init(ptrs.len(), ptrs.as_mut_ptr()), ROASTTY_SUCCESS);
        f();
        assert_eq!(roastty_init(0, ptr::null_mut()), ROASTTY_SUCCESS);
    }

    fn with_init_arg_bytes(args: &[&[u8]], f: impl FnOnce()) {
        let _guard = CLI_ARGS_LOCK.lock().unwrap();
        let strings = args
            .iter()
            .map(|arg| CString::new(*arg).unwrap())
            .collect::<Vec<_>>();
        let mut ptrs = strings
            .iter()
            .map(|arg| arg.as_ptr().cast_mut())
            .collect::<Vec<_>>();
        assert_eq!(roastty_init(ptrs.len(), ptrs.as_mut_ptr()), ROASTTY_SUCCESS);
        f();
        assert_eq!(roastty_init(0, ptr::null_mut()), ROASTTY_SUCCESS);
    }

