    #[test]
    fn config_c_abi_recursive_records_missing_relative_and_cycle_diagnostics() {
        let dir = unique_config_abi_test_dir("recursive-diagnostics");
        let parent = dir.join("parent.roastty");
        let cycle = dir.join("cycle.roastty");
        let missing = dir.join("missing.roastty");
        write_config_file(
            &parent,
            &format!(
                "config-file = {}\nconfig-file = {}\nconfig-file = relative.roastty\n",
                missing.display(),
                cycle.display()
            ),
        );
        write_config_file(&cycle, &format!("config-file = {}\n", cycle.display()));
        let parent = c_path(&parent);

        let config = roastty_config_new();
        roastty_config_load_file(config, parent.as_ptr());
        {
            let parsed = config_from_handle(config).unwrap();
            parsed.parsed.config_file.list.insert(
                0,
                config::ConfigFilePath::Required("manual-relative.roastty".to_string()),
            );
        }
        roastty_config_load_recursive_files(config);

        assert_eq!(roastty_config_diagnostics_count(config), 4);
        let messages = (0..4)
            .map(|index| config_diagnostic_message(config, index))
            .collect::<Vec<_>>();
        assert!(
            messages
                .iter()
                .any(|message| message.contains("missing.roastty")),
            "{messages:?}"
        );
        assert!(
            messages
                .iter()
                .any(|message| message.contains("not absolute")),
            "{messages:?}"
        );
        assert!(
            messages
                .iter()
                .any(|message| message.contains("cycle detected")),
            "{messages:?}"
        );

        roastty_config_free(config);
        std::fs::remove_dir_all(&dir).ok();
    }

    #[test]
    fn config_cli_keybind_validates_supported_and_unsupported_actions() {
        for value in [
            b"ctrl+a=text:hello".as_slice(),
            b"ctrl+b=new_split",
            b"ctrl+c=new_split:right",
            b"ctrl+d=goto_tab:1",
            b"ctrl+e=resize_split:right,10",
            b"ctrl+f=copy_to_clipboard:plain",
            b"ctrl+g=set_font_size:14",
            b"ctrl+h=navigate_search:next",
        ] {
            assert!(parse_config_keybind(value).is_ok(), "{value:?}");
        }

        for value in [
            b"ctrl+a=unknown_action".as_slice(),
            b"ctrl+b=goto_tab:not-a-number",
            b"ctrl+c=resize_split:right",
            b"ctrl+d=copy_to_clipboard:bad",
            b"ctrl+e=new_window:bad",
        ] {
            let Err(error) = parse_config_keybind(value) else {
                panic!("expected invalid action for {value:?}");
            };
            assert_eq!(error, ConfigKeybindParseError::InvalidAction, "{value:?}");
        }

        let Err(error) = parse_config_keybind(b"ctrl+i=") else {
            panic!("expected missing action");
        };
        assert_eq!(error, ConfigKeybindParseError::MissingAction);
    }

    #[test]
    fn config_cli_keybind_init_replaces_previous_argv_and_handles_nulls() {
        let _guard = CLI_ARGS_LOCK.lock().unwrap();
        let first = CString::new("roastty").unwrap();
        let keybind = CString::new("--keybind=ctrl+a=copy_to_clipboard").unwrap();
        let mut first_ptrs = vec![first.as_ptr().cast_mut(), keybind.as_ptr().cast_mut()];
        assert_eq!(
            roastty_init(first_ptrs.len(), first_ptrs.as_mut_ptr()),
            ROASTTY_SUCCESS
        );
        let config = roastty_config_new();
        roastty_config_load_cli_args(config);
        let copy = CString::new("copy_to_clipboard").unwrap();
        assert_unicode_config_trigger(
            roastty_config_trigger(config, copy.as_ptr(), copy.as_bytes().len()),
            b'a' as u32,
            ROASTTY_MODS_CTRL,
        );
        roastty_config_free(config);

        let later = CString::new("--keybind=cmd+n=new_window").unwrap();
        let mut second_ptrs = vec![
            first.as_ptr().cast_mut(),
            ptr::null_mut(),
            later.as_ptr().cast_mut(),
        ];
        assert_eq!(
            roastty_init(second_ptrs.len(), second_ptrs.as_mut_ptr()),
            ROASTTY_SUCCESS
        );
        let config = roastty_config_new();
        roastty_config_load_cli_args(config);
        assert_unicode_config_trigger(
            roastty_config_trigger(config, copy.as_ptr(), copy.as_bytes().len()),
            b'c' as u32,
            ROASTTY_MODS_SUPER,
        );
        roastty_config_free(config);

        assert_eq!(roastty_init(0, ptr::null_mut()), ROASTTY_SUCCESS);
    }

    #[test]
    fn config_key_is_binding_validates_inputs_and_returns_false() {
        let config = roastty_config_new();
        let event = new_key_event();

        assert!(!roastty_config_key_is_binding_handle(
            ptr::null_mut(),
            event
        ));
        assert!(!roastty_config_key_is_binding_handle(
            config,
            ptr::null_mut()
        ));
        assert!(!roastty_config_key_is_binding_handle(config, event));

        roastty_key_event_free(event);
        roastty_config_free(config);
    }

    fn set_key_event(
        event: RoasttyKeyEvent,
        action: key::KeyAction,
        key: key::Key,
        mods: c_int,
        utf8: &[u8],
        unshifted: u32,
    ) {
        assert_eq!(
            roastty_key_event_set_action(event, action as c_int),
            ROASTTY_SUCCESS
        );
        assert_eq!(
            roastty_key_event_set_key(event, key as c_int),
            ROASTTY_SUCCESS
        );
        assert_eq!(
            roastty_key_event_set_mods(event, key_mods_to_abi(key_mods_from_raw(mods))),
            ROASTTY_SUCCESS
        );
        assert_eq!(
            roastty_key_event_set_utf8(event, utf8.as_ptr(), utf8.len()),
            ROASTTY_SUCCESS
        );
        assert_eq!(
            roastty_key_event_set_unshifted_codepoint(event, unshifted),
            ROASTTY_SUCCESS
        );
    }

    #[test]
    fn config_key_is_binding_matches_default_physical_keys() {
        let config = roastty_config_new();
        let event = new_key_event();

        for (key, mods) in [
            (key::Key::Copy, ROASTTY_MODS_NONE),
            (key::Key::Paste, ROASTTY_MODS_NONE),
            (key::Key::ArrowRight, ROASTTY_MODS_ALT | ROASTTY_MODS_SUPER),
            (key::Key::Home, ROASTTY_MODS_SUPER),
            (key::Key::Enter, ROASTTY_MODS_SHIFT | ROASTTY_MODS_SUPER),
            (key::Key::ArrowLeft, ROASTTY_MODS_SHIFT),
            (key::Key::Escape, ROASTTY_MODS_NONE),
            (key::Key::Backspace, ROASTTY_MODS_SUPER),
            (key::Key::Insert, ROASTTY_MODS_SHIFT),
        ] {
            set_key_event(event, key::KeyAction::Press, key, mods, &[], 0);
            assert!(
                roastty_config_key_is_binding_handle(config, event),
                "{key:?}"
            );
        }

        roastty_key_event_free(event);
        roastty_config_free(config);
    }

    #[test]
    fn config_key_is_binding_by_value_uses_default_fallback() {
        // The by-value `config_key_is_binding` (the app-linked path) must mirror the handle
        // body's `config || default` — Escape (native macOS keycode 0x35) with no mods is a
        // built-in default binding, so this fails if the default fallback is dropped.
        let config = roastty_config_new();
        let escape = RoasttyInputKey {
            action: 1, // ROASTTY_ACTION_PRESS
            mods: 0,
            consumed_mods: 0,
            keycode: 0x35, // -> Key::Escape
            text: core::ptr::null(),
            unshifted_codepoint: 0,
            composing: false,
        };
        assert!(roastty_config_key_is_binding(config, escape));
        // Native 'A' (keycode 0x00) with no mods is just typing — not a binding.
        let typing = RoasttyInputKey {
            action: 1, // ROASTTY_ACTION_PRESS
            mods: 0,
            consumed_mods: 0,
            keycode: 0x00, // -> Key::KeyA
            text: core::ptr::null(),
            unshifted_codepoint: 0,
            composing: false,
        };
        assert!(!roastty_config_key_is_binding(config, typing));
        roastty_config_free(config);
    }

