    fn push_osc52_write(surface: RoasttySurface, kind: u8, data: &[u8]) {
        surface_from_handle(surface)
            .unwrap()
            .test_termio_events
            .push_back(termio::TermioWorkerEvent::Clipboard(
                TerminalClipboardEvent::Osc52 {
                    kind,
                    data: data.to_vec(),
                },
            ));
    }

