    fn take_roastty_string(value: RoasttyString) -> Vec<u8> {
        if value.ptr.is_null() || value.len == 0 {
            return Vec::new();
        }
        let bytes = unsafe { slice::from_raw_parts(value.ptr.cast::<u8>(), value.len) }.to_vec();
        roastty_string_free(value);
        bytes
    }

