    #[test]
    fn terminal_get_abi_multi_reports_success_and_partial_counts() {
        let terminal = new_terminal(8, 4);
        write_terminal(terminal, b"abc");

        let mut cols = 0u16;
        let mut rows = 0u16;
        let mut cursor_x = 0u16;
        let keys = [
            ROASTTY_TERMINAL_DATA_COLS,
            ROASTTY_TERMINAL_DATA_ROWS,
            ROASTTY_TERMINAL_DATA_CURSOR_X,
        ];
        let mut values = [
            &mut cols as *mut _ as *mut c_void,
            &mut rows as *mut _ as *mut c_void,
            &mut cursor_x as *mut _ as *mut c_void,
        ];
        let mut written = 999usize;
        assert_eq!(
            roastty_terminal_get_multi(
                terminal,
                keys.len(),
                keys.as_ptr(),
                values.as_mut_ptr(),
                &mut written,
            ),
            ROASTTY_SUCCESS
        );
        assert_eq!(written, 3);
        assert_eq!((cols, rows, cursor_x), (8, 4, 3));

        assert_eq!(
            roastty_terminal_get_multi(
                terminal,
                0,
                keys.as_ptr(),
                values.as_mut_ptr(),
                &mut written,
            ),
            ROASTTY_SUCCESS
        );
        assert_eq!(written, 0);

        let deferred_keys = [
            ROASTTY_TERMINAL_DATA_COLS,
            ROASTTY_TERMINAL_DATA_TITLE,
            ROASTTY_TERMINAL_DATA_ROWS,
        ];
        written = 999;
        assert_eq!(
            roastty_terminal_get_multi(
                terminal,
                deferred_keys.len(),
                deferred_keys.as_ptr(),
                values.as_mut_ptr(),
                &mut written,
            ),
            ROASTTY_NO_VALUE
        );
        assert_eq!(written, 1);

        let invalid_keys = [ROASTTY_TERMINAL_DATA_COLS, 33];
        written = 999;
        assert_eq!(
            roastty_terminal_get_multi(
                terminal,
                invalid_keys.len(),
                invalid_keys.as_ptr(),
                values.as_mut_ptr(),
                &mut written,
            ),
            ROASTTY_INVALID_VALUE
        );
        assert_eq!(written, 1);

        values[1] = ptr::null_mut();
        written = 999;
        assert_eq!(
            roastty_terminal_get_multi(
                terminal,
                keys.len(),
                keys.as_ptr(),
                values.as_mut_ptr(),
                &mut written,
            ),
            ROASTTY_INVALID_VALUE
        );
        assert_eq!(written, 1);

        assert_eq!(
            roastty_terminal_get_multi(
                ptr::null_mut(),
                keys.len(),
                keys.as_ptr(),
                values.as_mut_ptr(),
                &mut written,
            ),
            ROASTTY_INVALID_VALUE
        );
        assert_eq!(
            roastty_terminal_get_multi(
                terminal,
                keys.len(),
                ptr::null(),
                values.as_mut_ptr(),
                &mut written,
            ),
            ROASTTY_INVALID_VALUE
        );
        assert_eq!(
            roastty_terminal_get_multi(
                terminal,
                keys.len(),
                keys.as_ptr(),
                ptr::null_mut(),
                &mut written,
            ),
            ROASTTY_INVALID_VALUE
        );

        roastty_terminal_free(terminal);
    }

